-- Rellenar instructions (text[]) en tipo_ejercicio solo donde esté vacío
-- Fuente: sql/ejercicios.csv columna instrucciones (JSON array)
-- Condición: instructions NULL o array vacío
begin;
-- csv: Abdominales en V con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Tumbado en el suelo (o colchoneta de ejercicios) sobre la espalda con los brazos estirados hacia atrás detrás de la cabeza y con las piernas extendidas.', 'Al exhalar, flexiona la cintura al mismo tiempo que elevas las piernas y los brazos para que se junten.', 'Las piernas deben estar estiradas y levantadas a un ángulo aproximado de 35-45 grados del suelo, y los brazos deben estar totalmente extendidos y paralelos a las piernas.', 'La parte superior del torso debe estar levantada.', 'Mientras inhalas, baja los brazos y las piernas de nuevo a la posición inicial.', 'Sostén una mancuerna entre las manos para mayor dificultad.']::text[] where nombre = 'Abdominales en V con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aductor Externo Aislado en Máquina
update public.tipo_ejercicio set instructions = ARRAY['De pie en la máquina con la espalda recta, ponte el rodillo en el lateral exterior de una pierna y crúzala por delante de la de apoyo.', 'Abre la pierna hacia fuera lateralmente empujando el peso.', 'Después regresa lentamente a la posición inicial, sin dejar caer el peso bruscamente.']::text[] where nombre = 'Aductor Externo Aislado en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aductor Externo en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina con la espalda recta, las piernas abiertas y el exterior de los muslos en los soportes.', 'Realiza la apertura de las piernas todo lo que puedas.', 'Después regresa lentamente a la posición inicial, sin dejar caer el peso bruscamente.']::text[] where nombre = 'Aductor Externo en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aductor Externo en Polea
update public.tipo_ejercicio set instructions = ARRAY['Ponte de pie al lado de una máquina de polea.', 'Sujeta la polea al tobillo de la pierna más alejada a la polea.', 'Apóyate con las manos para conservar el equilibrio y desde allí comienza el movimiento.', 'Sin movilizar el torso, despega la pierna que sujeta el peso del suelo y llévala desde la máquina hacia el lado opuesto, por delante de la otra pierna que está apoyada en el suelo.', 'Después regresa lentamente a la posición inicial, sin dejar caer el peso bruscamente.']::text[] where nombre = 'Aductor Externo en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aductor Interno Aislado en Máquina
update public.tipo_ejercicio set instructions = ARRAY['De pie en la máquina con la espalda recta, ponte el rodillo en el lateral interior de una pierna con ella abierta hacia fuera.', 'Cierra la pierna hacia dentro lateralmente empujando el peso y crúzala por delante de la de apoyo.', 'Después regresa lentamente a la posición inicial, sin dejar caer el peso bruscamente.']::text[] where nombre = 'Aductor Interno Aislado en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aductor Interno en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina con la espalda recta, las piernas abiertas y el interior de los muslos en los soportes.', 'Realiza el cierre de las piernas llegando a juntar los soportes.', 'Después regresa lentamente a la posición inicial, sin dejar caer el peso bruscamente.']::text[] where nombre = 'Aductor Interno en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aductor Interno en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['Ponte de pie al lado de una máquina de polea.', 'Sujeta la polea al tobillo de la pierna cercana a la polea.', 'Apóyate con las manos para conservar el equilibrio y desde allí comienza el movimiento.', 'Sin movilizar el torso, despega la pierna que sujeta el peso del suelo y llévala desde la máquina hacia el lado opuesto, por delante de la otra pierna que está apoyada en el suelo.', 'Después regresa lentamente a la posición inicial, sin dejar caer el peso bruscamente.']::text[] where nombre = 'Aductor Interno en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv (alias): Air Bike (Assault Bike)
update public.tipo_ejercicio set instructions = ARRAY['Una bicicleta de resistencia de aire es una bicicleta estacionaria con manillas donde también se aplica fuerza.', 'La resistencia es aplicada por una turbina de viento; esto causa que a mayor velocidad, mayor resistencia de la máquina.', 'Por esta razón se suele decir que un Airbike ofrece resistencia infinita.', 'Ajusta toda la bicicleta para sentarte sobre ella con una postura cómoda manteniendo la espalda recta en todo momento.']::text[] where nombre = 'Air Bike (Assault Bike)' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Apertura Aislada Declinada con Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado sobre un banco declinado cercano a una polea baja, el brazo estirado horizontalmente, agarramos la empuñadura de forma natural (palma de la mano hacia arriba).', 'El movimiento consiste en realizar el cierre con el brazo estirado hacia el centro del pecho.', 'La inspiración se hace durante el descenso, la expiración durante el ascenso.', 'La otra mano la podemos colocar bajo el banco o agarrando un lateral del mismo.']::text[] where nombre = 'Apertura Aislada Declinada con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Apertura Aislada en Punta
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el suelo, el brazo estirado horizontalmente, agarramos el extremo de la barra en punta de forma natural (palma de la mano hacia arriba).', 'El movimiento consiste en realizar el cierre con el brazo hacia el centro del pecho, ligeramente flexionado (casi estirado).', 'La inspiración se hace durante el descenso, la expiración durante el ascenso.', 'La otra mano la podemos colocar al otro lado del cuerpo o como nos resulte más cómodo.']::text[] where nombre = 'Apertura Aislada en Punta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aperturas con Bandas
update public.tipo_ejercicio set instructions = ARRAY['Asegura la banda elástica a una altura elevada detrás de ti y sujeta una agarradera con tu mano cerca de tu hombro, con la palma apuntando hacia abajo.', 'Empuja la agarradera en forma recta hacia adelante y hacia abajo, hasta que tu brazo esté extendido, y regresa lentamente luego de una breve pausa.']::text[] where nombre = 'Aperturas con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv (alias): Aperturas con Mancuernas (Flyes)
update public.tipo_ejercicio set instructions = ARRAY['Túmbate boca arriba sobre el banco.', 'Coge las mancuernas con las dos manos, teniendo en cuenta que las palmas deben mirar hacia el centro del cuerpo y manteniendo los brazos un poco flexionados en vertical al cuerpo.', 'Desciende los brazos a los lados hasta bajar con las manos a la altura de los hombros.', 'Los codos tienen que estar alineados entre sí, perpendiculares al cuerpo y paralelos al suelo.', 'En el momento que espiras, regresa al centro del cuerpo sin extender los brazos ni flexionar los codos.']::text[] where nombre = 'Aperturas con Mancuernas (Flyes)' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aperturas Declinadas con giro con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate boca arriba sobre el banco declinado.', 'Coge las mancuernas con las dos manos, teniendo en cuenta que las palmas deben mirar hacia la cabeza (supinación) y manteniendo los brazos un poco flexionados en vertical al cuerpo.', 'Desciende los brazos a los lados hasta bajar con las manos a la altura de los hombros, girando las mismas de forma que queden con las palmas hacia el cuerpo.', 'Los codos tienen que estar alineados entre sí, perpendiculares al cuerpo y paralelos al suelo.', 'En el momento que espiras, regresa al centro del cuerpo sin extender los brazos ni flexionar los codos, girando de nuevo a supinación.']::text[] where nombre = 'Aperturas Declinadas con giro con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aperturas Declinadas con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate boca arriba sobre el banco declinado.', 'Coge las mancuernas con las dos manos, teniendo en cuenta que las palmas deben mirar hacia el centro del cuerpo y manteniendo los brazos un poco flexionados en vertical al cuerpo.', 'Desciende los brazos a los lados hasta bajar con las manos a la altura de los hombros.', 'Los codos tienen que estar alineados entre sí, perpendiculares al cuerpo y paralelos al suelo.', 'En el momento que espiras, regresa al centro del cuerpo sin extender los brazos ni flexionar los codos.']::text[] where nombre = 'Aperturas Declinadas con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aperturas en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentados con la espalda bien apoyada y recta, abrimos los brazos a los lados, flexionados 90° hacia arriba y agarramos las barras de la máquina con las palmas hacia delante.', 'A continuación realizamos el cierre efectuando la fuerza desde los codos, hasta llegar al centro del pecho.', 'Después retrocedemos de forma controlada sin llegar a perder la tensión (no llegar al final para descansar).']::text[] where nombre = 'Aperturas en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aperturas Extendidas en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentados con la espalda bien apoyada y recta, extendemos bien los brazos a los lados y agarramos las barras de la máquina con agarre neutro (palmas mirándose entre sí).', 'A continuación realizamos el cierre manteniendo los brazos extendidos hasta llegar a tocarse ambas manos.', 'Después retrocedemos de forma controlada sin llegar a perder la tensión (no llegar al final para descansar).']::text[] where nombre = 'Aperturas Extendidas en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aperturas Inclinadas con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate boca arriba sobre el banco inclinado (no demasiado inclinado, si no tiraremos más de hombro).', 'Coge las mancuernas con las dos manos, teniendo en cuenta que las palmas deben mirar hacia el centro del cuerpo y manteniendo los brazos un poco flexionados en vertical al cuerpo.', 'Desciende los brazos a los lados hasta bajar con las manos a la altura de los hombros.', 'Los codos tienen que estar alineados entre sí, perpendiculares al cuerpo y paralelos al suelo.', 'En el momento que espiras, regresa al centro del cuerpo sin extender los brazos ni flexionar los codos.']::text[] where nombre = 'Aperturas Inclinadas con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aperturas Traseras en Pronación en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Con la espalda recta coge un agarre con cada mano en pronación y sin balanceo ni impulso, lleva los soportes hacia los lados con los brazos rectos.', 'Aprieta los hombros y aguanta durante uno o dos segundos.', 'Retrocede de forma controlada a la posición inicial.']::text[] where nombre = 'Aperturas Traseras en Pronación en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Aperturas Traseras Neutras en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Con la espalda recta coge un agarre con cada mano neutro (palmas hacia el interior) y sin balanceo ni impulso, lleva los soportes hacia los lados con los brazos rectos.', 'Aprieta los hombros y aguanta durante uno o dos segundos.', 'Retrocede de forma controlada a la posición inicial.']::text[] where nombre = 'Aperturas Traseras Neutras en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Bicicleta Estática Deportiva
update public.tipo_ejercicio set instructions = ARRAY['La espalda inclinada en posición deportiva permite liberar un máximo de potencia para el pedaleo.']::text[] where nombre = 'Bicicleta Estática Deportiva' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Bicicleta Estática Normal
update public.tipo_ejercicio set instructions = ARRAY['-Espalda recta para un confort máximo (especialmente aconsejado en caso de dolores lumbares) -Espalda ligeramente inclinada, para una buena relación confort / potencia de pedaleo.']::text[] where nombre = 'Bicicleta Estática Normal' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Bicicleta Estática Reclinada
update public.tipo_ejercicio set instructions = ARRAY['En una bicicleta reclinada u horizontal el cuerpo se encuentra más cerca del suelo.', 'Esta clase de bicicletas cuentan con un asiento que envuelve la zona lumbar del usuario y unos pedales situados enfrente del mismo, lo que conlleva que la acción de pedalear se realice en círculos más abiertos y hacia afuera.', 'Las bicicletas reclinadas son perfectas para personas de edad avanzada o con problemas de espalda, ya que el asiento permite descansar la espalda y no ejercer presión sobre esta zona.', 'Por otra parte, no son recomendables para personas con lesiones en la rodilla al estar la fuerza más concentrada en las piernas.']::text[] where nombre = 'Bicicleta Estática Reclinada' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Brazada en Fitball
update public.tipo_ejercicio set instructions = ARRAY['Trabajarás las lumbares y los músculos de la espalda simplemente realizando el gesto de la brazada con el abdomen situado en el fitball y los pies en el suelo.']::text[] where nombre = 'Brazada en Fitball' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Buenos días con Barra
update public.tipo_ejercicio set instructions = ARRAY['Colócate de pie con las piernas separadas a la anchura algo menor a la de los hombros.', 'Así, coge una barra tras la cabeza, exactamente bajo la zona de los trapecios.', 'Baja el tronco hacia adelante, siempre manteniendo la espalda en una posición erecta.', 'Al llegar al punto máximo, tu torso debe encontrarse casi paralelo al piso, todo ello sin que la espalda pierda su posición inicial y, eso sí, doblando ligeramente las rodillas y sacando los glúteos.', 'Puedes mantener la posición final por uno o dos segundos, en donde sentirás cómo se tensa tu abdomen.', 'Una vez hecho esto, regresa a la posición de inicio.']::text[] where nombre = 'Buenos días con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Burpee
update public.tipo_ejercicio set instructions = ARRAY['Para realizar el ejercicio de se parte de una posición inicial en cuclillas (o sentadillas), se colocan las manos en el suelo y se mantiene la cabeza erguida.', 'Después se desplazan las piernas hacia atrás con los pies juntos.', 'A continuación se recogen las piernas para volver y se da un salto vertical con los brazos en alto (se puede dar una palmada por encima de la cabeza).', 'Después vuelve a la posición de cuclillas para repetir el ejercicio.']::text[] where nombre = 'Burpee' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Burpee con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Sostén una mancuerna en cada mano, ponte de pie con los pies separados a la anchura de los hombros.', 'Agáchate y coloca las mancuernas sobre el piso antes de patear con fuerza hacia atrás y ponerte en la posición de flexión o lagartija.', 'Rápidamente empuja las piernas con fuerza para regresar a la posición más baja de sentadilla y con impulso salta levantando las mancuernas tan alto como pueda antes de regresar a la posición inicial.']::text[] where nombre = 'Burpee con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Burpee Jack
update public.tipo_ejercicio set instructions = ARRAY['Para empezar, nos colocaremos de pie, con las piernas a la anchura de los hombros.', 'Sin mover los pies, colocaremos las manos en el suelo delante de nuestra cabeza.', 'De un salto, deberemos extender las piernas para quedar en una posición de plancha.', 'En esta posición, tendremos que dar otro salto para separar las piernas, y de nuevo otro salto con el fin de volver a juntarlas.', 'Posteriormente, volviendo a saltar, tendremos que flexionar las piernas hasta la posición inicial.', 'Nos levantaremos por completo y deberemos aprovechar el impulso para dar un salto que nos haga despegar del suelo.']::text[] where nombre = 'Burpee Jack' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Butt Kicks
update public.tipo_ejercicio set instructions = ARRAY['Se trata de correr sin moverte del sitio donde te encuentres, flexionando las rodillas hacia atrás lo máximo posible tratando de tocar el glúteo con el talón.']::text[] where nombre = 'Butt Kicks' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Caminar
update public.tipo_ejercicio set instructions = ARRAY['Andar con normalidad.', 'Puede ser un paseo por el exterior o caminar tranquilamente sobre una cinta.']::text[] where nombre = 'Caminar' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Caminar a paso ligero
update public.tipo_ejercicio set instructions = ARRAY['El paso ligero es aquel que cubre aproximadamente 4,3 kilómetros por hora.', 'Dicho de otra manera, unas 100 zancadas por minuto (es decir, casi dos por segundo).']::text[] where nombre = 'Caminar a paso ligero' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Caminar con peso
update public.tipo_ejercicio set instructions = ARRAY['Andar con normalidad mientras sostenemos una mancuerna a cada mano (puede ser otro tipo de material que pese).', 'Puede ser un paseo libre o caminar sobre una cinta.']::text[] where nombre = 'Caminar con peso' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Caminar con rodilla arriba
update public.tipo_ejercicio set instructions = ARRAY['De pie, con una rodilla arriba flexionada a 90º y el brazo opuesto del mismo modo, da un paso hacia delante manteniendo el ángulo de la rodilla flexionada descendiendo con la otra pierna a modo de zancada.', 'Impúlsate con la pierna adelantada y sigue caminando alternando la pierna.']::text[] where nombre = 'Caminar con rodilla arriba' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Caminar en cuclillas
update public.tipo_ejercicio set instructions = ARRAY['Ponerse en cuclillas puede aliviar el dolor persistente, prevenir lesiones y ayudar a lograr metas de tu estado físico.', 'Separa tus pies a la altura de la cadera con los dedos de los pies hacia adelante.', 'Ahora, en cuclillas, baja lo más que puedas y comienza a andar sin levantarte.']::text[] where nombre = 'Caminar en cuclillas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Carrera con salto
update public.tipo_ejercicio set instructions = ARRAY['Consiste en correr realizando saltos longitudinales alargando la zancada lo máximo posible.']::text[] where nombre = 'Carrera con salto' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Carrera continua
update public.tipo_ejercicio set instructions = ARRAY['Se trata de correr al libremente de forma natural, a un ritmo adecuado, con intervalos de alta y baja intensidad o a un ritmo constante si se prefiere.']::text[] where nombre = 'Carrera continua' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Carrera de pasos cortos
update public.tipo_ejercicio set instructions = ARRAY['Carrera continua con pasos cortos y flexión mínima de rodillas.', 'Adelanta ligeramente el brazo inverso a cada rodilla.']::text[] where nombre = 'Carrera de pasos cortos' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Carrera de skater
update public.tipo_ejercicio set instructions = ARRAY['Con una pierna hacia delante y otra hacia atrás, flexionadas a modo de zancada, inclina el cuerpo hacia delante con ambos codos flexionados y con el torso girado hacia el lado de la pierna adelantada.', 'Comienza a caminar adelantando la otra pierna e invirtiendo la posición.']::text[] where nombre = 'Carrera de skater' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Carrera en Cinta
update public.tipo_ejercicio set instructions = ARRAY['Una cinta de correr, cinta ergométrica, caminadora de banda o máquina de caminar es una máquina para entrenamiento físico que puede funcionar mediante propulsión eléctrica o manual, y que sirve para correr o andar sin moverse de un mismo sitio.', 'Colócate sobre la cinta y realiza algún programa de la misma o regula la intensidad ajustándola a tus necesidades.']::text[] where nombre = 'Carrera en Cinta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Carrera en Cinta Inclinada
update public.tipo_ejercicio set instructions = ARRAY['Una cinta de correr, cinta ergométrica, caminadora de banda o máquina de caminar es una máquina para entrenamiento físico que puede funcionar mediante propulsión eléctrica o manual, y que sirve para correr o andar sin moverse de un mismo sitio.', 'Ajusta la inclinación de la cinta, colócate sobre ella y realiza algún programa de la misma o regula la intensidad ajustándola a tus necesidades.']::text[] where nombre = 'Carrera en Cinta Inclinada' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Carrera en zigzag
update public.tipo_ejercicio set instructions = ARRAY['Seguir un patrón de zigzag imaginario (se pueden colocar conos u otros objetos) y ejecutar una zancada larga hacia afuera con el pie derecho, luego seguir inmediatamente con una zancada larga al lado contrario con el pie izquierdo.']::text[] where nombre = 'Carrera en zigzag' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Carrera hacia atrás
update public.tipo_ejercicio set instructions = ARRAY['Correr hacia atrás ofrece al atleta un entrenamiento cardiovascular intenso, reduce el riesgo de lesiones en la espalda y en las piernas, ayuda a conseguir un tren inferior más fuerte y equilibrado, y se trata de una alternativa perfecta para perder peso de forma más rápida.']::text[] where nombre = 'Carrera hacia atrás' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Carrera rápida en el sitio
update public.tipo_ejercicio set instructions = ARRAY['De pie, con los codos flexionados en un ángulo de 90 grados y los pies separados a la anchura de las caderas.', 'Mueve el codo derecho hacia delante al mismo tiempo que subes la rodilla izquierda.', 'Repite en el lado opuesto y mantén los lados alternados.']::text[] where nombre = 'Carrera rápida en el sitio' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Cocoons
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con los brazos extendidos a lo largo del cuerpo y las palmas hacia abajo.', 'Levanta las piernas y el torso del suelo al mismo tiempo, manteniendo los brazos rectos y extendidos hacia adelante.', 'A continuación, lleva las rodillas hacia el pecho mientras te enrollas hacia adelante, tocando tus rodillas con la barbilla y adoptando una postura como si te sujetases las piernas por las tibias.', 'Mantén la contracción en los músculos abdominales y luego extiende lentamente las piernas y el torso de nuevo hacia la posición inicial.', 'Este ejercicio trabaja los músculos abdominales superiores e inferiores, así como los flexores de la cadera, ayudando a fortalecer y tonificar el área del núcleo.']::text[] where nombre = 'Cocoons' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Cruce completo de Poleas
update public.tipo_ejercicio set instructions = ARRAY['De pie con una polea a cada lado del cuerpo, por encima de la cabeza, cogemos las empuñaduras con la palma hacia el frente, con las piernas separadas.', 'Realiza el cierre de ambos brazos, de arriba a abajo sin flexionarlos, de forma que queden delante del cuerpo por debajo de la cadera, sin necesidad de tocar ambas manos, y regresa lentamente luego de una breve pausa.']::text[] where nombre = 'Cruce completo de Poleas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv (alias): Cruce de Poleas (Alto a Bajo)
update public.tipo_ejercicio set instructions = ARRAY['De pie con una polea a cada lado del cuerpo, a la altura del pecho, cogemos las empuñaduras con la palma hacia el frente, con un pie delante del otro para tener estabilidad.', 'Realiza el cierre de ambos brazos sin flexionarlos de forma que queden delante del pecho, llegando a tocarse las manos, y regresa lentamente luego de una breve pausa.']::text[] where nombre = 'Cruce de Poleas (Alto a Bajo)' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv (alias): Cruce de Poleas (Bajo a Alto)
update public.tipo_ejercicio set instructions = ARRAY['De pie con una polea a cada lado del cuerpo, a la altura del pecho, cogemos las empuñaduras con la palma hacia el frente, con un pie delante del otro para tener estabilidad.', 'Realiza el cierre de ambos brazos sin flexionarlos de forma que queden delante del pecho, llegando a tocarse las manos, y regresa lentamente luego de una breve pausa.']::text[] where nombre = 'Cruce de Poleas (Bajo a Alto)' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Cruce inferior de Poleas
update public.tipo_ejercicio set instructions = ARRAY['De pie con una polea a cada lado del cuerpo, a la altura del pecho, cogemos las empuñaduras con la palma hacia el frente, con un pie delante del otro para tener estabilidad.', 'Realiza el cierre de ambos brazos sin flexionarlos de forma que queden delante del pecho a la altura de la cadera, llegando a tocarse las manos, y regresa lentamente luego de una breve pausa.']::text[] where nombre = 'Cruce inferior de Poleas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Cruce superior de Poleas
update public.tipo_ejercicio set instructions = ARRAY['De pie con una polea a cada lado del cuerpo, a la altura del pecho, cogemos las empuñaduras con la palma hacia el frente, con un pie delante del otro para tener estabilidad.', 'Realiza el cierre de ambos brazos sin flexionarlos de forma que queden delante del pecho sobre la cabeza, llegando a tocarse las manos, y regresa lentamente luego de una breve pausa.']::text[] where nombre = 'Cruce superior de Poleas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Cruces en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentados en la máquina con la espalda recta, ponemos las manos en pronación (palmas hacia el suelo) y los codos bien arriba, a la altura de los hombros.', 'Empujamos hacia abajo para cerrar los brazos (sin bajar los codos por debajo de las manos) hasta prácticamente juntar las manos y volvemos a la posición inicial con un movimiento controlado.']::text[] where nombre = 'Cruces en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Cruzado
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con las rodillas dobladas y los pies apoyados en el suelo.', 'Coloca las manos detrás de la cabeza, sin entrelazar los dedos.', 'Levanta los hombros del suelo mientras contraes los abdominales.', 'A medida que subes, gira el torso y lleva el codo derecho hacia la rodilla izquierda, levantando también esa pierna del suelo para acortar el recorrido.', 'Intenta tocar la rodilla con el codo mientras mantienes la parte baja de la espalda en contacto con el suelo.', 'Regresa a la posición inicial y repite del otro lado, llevando el codo izquierdo hacia la rodilla derecha.', 'Alterna los lados en cada repetición.', 'Este ejercicio trabaja los músculos oblicuos y abdominales']::text[] where nombre = 'Crunch Cruzado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Cruzado con Bandas
update public.tipo_ejercicio set instructions = ARRAY['Agarra una banda a cada pie y a su vez a algún soporte a la misma altura.', 'Túmbate en el suelo boca arriba.', 'Coloca las manos tras la nuca, levanta una pierna del suelo y estírala, después levanta la otra pierna y dobla la rodilla hacia el pecho.', 'Toca con el codo la rodilla contraria y asegúrate de que giras el torso con los abdominales.', 'Cambia de lado y cuenta una repetición cuando la rodilla y el codo se toquen.']::text[] where nombre = 'Crunch Cruzado con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Cruzado con piernas elevadas
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con las rodillas dobladas y los cuádriceps a 90 grados del torso, manteniendo los pies en el aire y las manos detrás de la cabeza.', 'Levanta los hombros del suelo mientras contraes los abdominales.', 'A medida que subes, gira el torso y lleva el codo derecho hacia la rodilla izquierda, acercando esa rodilla pero manteniendo la otra pierna también elevada.', 'Intenta tocar la rodilla con el codo mientras mantienes la parte baja de la espalda en contacto con el suelo.', 'Regresa a la posición inicial y repite del otro lado, llevando el codo izquierdo hacia la rodilla derecha.', 'Alterna los lados en cada repetición.', 'Este ejercicio trabaja intensamente los músculos oblicuos y abdominales al desafiar la estabilidad y fuerza del núcleo.']::text[] where nombre = 'Crunch Cruzado con piernas elevadas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Cruzado estirado
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con las piernas rectas y los pies apoyados en el suelo.', 'Coloca las manos detrás de la cabeza.', 'Levanta los hombros del suelo mientras contraes los abdominales.', 'Al mismo tiempo, levanta ligeramente una pierna mientras mantienes la parte baja de la espalda en contacto con el suelo.', 'Regresa a la posición inicial y repite, alternando la pierna en cada repetición.', 'Este ejercicio trabaja los músculos oblicuos y abdominales']::text[] where nombre = 'Crunch Cruzado estirado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Diagonal de pie con Bandas
update public.tipo_ejercicio set instructions = ARRAY['Agarra las bandas de un soporte alto.', 'Ponte de pie de espaldas a ellas.', 'Agarra un extremo con cada mano a los lados de la cabeza, con los brazos por delante flexionados hacia arriba.', 'Inclina el torso ligeramente hacia delante con la espalda recta.', 'Realiza el encogimiento hacia un lado, apretando el abdomen sin mover las piernas.']::text[] where nombre = 'Crunch Diagonal de pie con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Diagonal de rodillas con Bandas
update public.tipo_ejercicio set instructions = ARRAY['Agarra las bandas de un soporte alto.', 'Ponte de rodillas de espaldas a ellas.', 'Agarra un extremo con cada mano a los lados de la cabeza, con los brazos por delante flexionados hacia arriba.', 'Inclina el torso ligeramente hacia delante con la espalda recta.', 'Realiza el encogimiento hacia un lado, apretando el abdomen.']::text[] where nombre = 'Crunch Diagonal de rodillas con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Diagonal en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas a la anchura aproximada de la cadera, ponte delante de la polea alta.', 'Coge la cuerda con las dos manos a un lado de la cabeza, con los brazos flexionados hacia arriba.', 'Flexiona el tronco lateralmente hacia abajo del lado contrario al de las manos, girando el torso y sin mover los brazos, apretando el abdomen.']::text[] where nombre = 'Crunch Diagonal en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Doble Vertical en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina con las manos en el soporte superior y los pies tras el soporte inferior, encoge la parte alta del torso a la vez que la parte baja, mediante la contracción de los abdominales, sin tirar del cuello, brazos ni piernas.']::text[] where nombre = 'Crunch Doble Vertical en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch en Decúbito Lateral con curl de bíceps
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate de lado en el suelo con las piernas flexionadas y el cuerpo alineado en línea recta.', 'Coloca ambos brazos por fuera de las rodillas.', 'Contrae los músculos abdominales y de los oblicuos mientras levantas las piernas del suelo con ayuda del bíceps del brazo apoyado, al mismo tiempo que realizas una flexión lateral del torso hacia las piernas.', 'Mantén la posición superior durante un momento y luego baja el torso y las piernas de forma controlada hasta volver a la posición inicial.', 'Este ejercicio trabaja los músculos del bíceps y los oblicuos, proporcionando un entrenamiento efectivo para los brazos y el core.']::text[] where nombre = 'Crunch en Decúbito Lateral con curl de bíceps' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch en Plancha Lateral
update public.tipo_ejercicio set instructions = ARRAY['Túmbate de lado en el suelo.', 'Apoya un antebrazo con el codo bajo el hombro y la otra mano tras la cabeza, pon los pies juntos y luego eleva la cadera apoyando sólo el pie de abajo y el antebrazo, con las piernas rectas en línea con el torso.', 'Manteniendo esa posición, eleva la rodilla mientras desciendes el codo de la mano tras la cabeza, intentando tocarse entre ambos.', 'Vuelve a la posición inicial y repite.']::text[] where nombre = 'Crunch en Plancha Lateral' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Frog
update public.tipo_ejercicio set instructions = ARRAY['Sentado en el suelo con las rodillas dobladas y los pies apoyados en el suelo, mantén los talones juntos y cerca de los glúteos.', 'Mantén los brazos extendidos hacia delante, con las manos justo por delante de las rodillas.', 'Inclínate ligeramente hacia atrás para activar los abdominales y levanta los pies del suelo, manteniendo las rodillas dobladas.', 'A continuación, estira las piernas hacia adelante, separándolas y llevando los brazos hacia los lados del cuerpo.', 'Vuelve a la posición inicial, llevando las rodillas hacia el pecho y los brazos hacia adelante, justo por delante de las rodillas.', 'Repite el movimiento de forma fluida y controlada, manteniendo la tensión en los abdominales en todo momento.', 'Este ejercicio trabaja los músculos abdominales y puede ayudar a mejorar la fuerza y resistencia del core.']::text[] where nombre = 'Crunch Frog' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Horizontal en Silla Romana
update public.tipo_ejercicio set instructions = ARRAY['Colócate en la silla romana con los pies asegurados y las piernas estiradas.', 'Cruza los brazos sobre el pecho o colócalos detrás de la cabeza para mayor resistencia.', 'Desciende lentamente hacia atrás hasta que tu torso esté casi paralelo al suelo, y luego utiliza los músculos abdominales para levantar el torso hacia adelante hasta una posición vertical.', 'Mantén el control del movimiento y evita balancearte hacia adelante y hacia atrás.', 'Repite el movimiento durante el número deseado de repeticiones.', 'Este ejercicio fortalece los músculos abdominales superiores y puede aumentar la fuerza y resistencia del core.']::text[] where nombre = 'Crunch Horizontal en Silla Romana' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior con flexión y extensión
update public.tipo_ejercicio set instructions = ARRAY['Siéntate con las palmas apoyadas en el suelo a ambos lados del cuerpo.', 'Mantén las piernas estiradas y los pies juntos, echando el cuerpo ligeramente hacia atrás.', 'Contrae los músculos abdominales y glúteos mientras flexionas las rodillas hasta que tus muslos estén cerca de tu abdomen.', 'A continuación estira las piernas hacia arriba, formando una V con tu cuerpo.', 'Baja las piernas de nuevo a la posición inicial y repite el movimiento.', 'Este ejercicio es excelente para fortalecer los músculos abdominales inferiores y mejorar la estabilidad del núcleo.']::text[] where nombre = 'Crunch Inferior con flexión y extensión' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior con Rodillas Flexionadas
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con los brazos extendidos a los lados del cuerpo y las palmas hacia abajo.', 'Mantén las piernas estiradas y los pies juntos.', 'Contrae los músculos abdominales y glúteos mientras levantas lentamente las piernas hacia arriba, flexionando las rodillas hasta que tus muslos estén a 90 grados del torso.', 'Asegúrate de mantener la parte baja de la espalda en contacto con el suelo en todo momento para evitar arquearla.', 'Este ejercicio es excelente para fortalecer los músculos abdominales inferiores y mejorar la estabilidad del núcleo.']::text[] where nombre = 'Crunch Inferior con Rodillas Flexionadas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior Cruzado
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate en el suelo con las piernas extendidas y las manos bajo los glúteos para mayor estabilidad.', 'Contrae los músculos abdominales y flexiona lentamente las piernas mientras las elevas del suelo.', 'Según vayas subiendo, gira el abdomen hacia un lado mientras levantas la cadera.', 'Mantén la posición durante un momento y luego baja las piernas y las caderas de manera controlada hacia el suelo.', 'Repite el movimiento durante el número deseado de repeticiones cambiando de lado en cada subida.', 'Este ejercicio fortalece los músculos abductores de la cadera y puede ayudar a mejorar la estabilidad y el equilibrio del core.']::text[] where nombre = 'Crunch Inferior Cruzado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior Cruzado Alterno
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con las piernas estiradas, manteniendo las manos detrás de la cabeza.', 'Levanta una pierna flexionándola hasta llevar la rodilla casi a la altura del pecho, intentando tocar el codo opuesto mientras levantas los hombros girando el torso.', 'Mantén la parte baja de la espalda en contacto con el suelo en todo momento.', 'Regresa a la posición inicial y repite del otro lado, llevando la otra rodilla flexionada hacia el codo opuesto.', 'Alterna los lados en cada repetición.', 'Este ejercicio se centra en los músculos abdominales inferiores y oblicuos, mejorando la fuerza y la estabilidad del núcleo.']::text[] where nombre = 'Crunch Inferior Cruzado Alterno' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior en círculos
update public.tipo_ejercicio set instructions = ARRAY['Desde una posición sentada en un banco con el cuerpo perpendicular al asiento y las piernas extendidas frente a ti, apoya las manos en el banco a los lados de tus caderas.', 'Levanta las piernas rectas mientras las abres al ponerlas paralelas al suelo.', 'Contrae los abdominales y eleva las piernas todo lo que puedas mientras las cierras de nuevo.', 'Mantén la posición y desciende invirtiendo el movimiento, con el descenso controlado.', 'Este ejercicio fortalece los músculos abdominales inferiores y contribuye a mejorar la estabilidad del core.']::text[] where nombre = 'Crunch Inferior en círculos' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior en Máquina Smith
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia arriba en el suelo bajo una máquina Smith.', 'Estira las piernas hacia arriba y pon el centro de los pies en la barra, ligeramente separados.', 'Eleva la cadera mediante la contracción abdominal inferior, levantando la barra.', 'Baja lentamente y sube de nuevo sin flexionar las piernas.']::text[] where nombre = 'Crunch Inferior en Máquina Smith' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior en Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el suelo, con la espalda recta y brazos apoyados, agarra las correas de la polea baja en los pies.', 'A continuación levanta las piernas totalmente rectas hacia arriba y flexiona las rodillas 90º.', 'Esa es la posición inicial.', 'Desde ahí y con las rodillas flexionadas, realiza el encogimiento del abdomen inferior, apretando y levantando los glúteos del suelo.', 'Desciende lentamente y vuelve a subir.']::text[] where nombre = 'Crunch Inferior en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior Horizontal en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el banco de la máquina con el soporte sobre los cuádriceps y con las piernas ligeramente flexionadas, encoge la parte baja del torso levantando las piernas mediante la contracción de los abdominales inferiores.']::text[] where nombre = 'Crunch Inferior Horizontal en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior Inclinado con piernas estiradas
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en un banco inclinado con la parte superior de la espalda apoyada en el banco y las manos sujetas en los bordes para estabilizarte.', 'Extiende las piernas hacia adelante y colócalas juntas, manteniendo los pies apoyados en el suelo o colgando del banco.', 'Desde esta posición, contrae los músculos de los abdominales inferiores, glúteos y los isquiotibiales para levantar las caderas hacia arriba, manteniendo las piernas rectas.', 'Alcanza la posición más alta posible y luego baja las caderas de manera controlada hasta que vuelvan a tocar ligeramente el banco/suelo.', 'Este ejercicio se enfoca en los músculos abdominales, ayudando a fortalecer el core inferior y mejorar la estabilidad de la cadera.']::text[] where nombre = 'Crunch Inferior Inclinado con piernas estiradas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior sentado
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en el suelo con las piernas extendidas frente a ti y las manos a ambos lados de las caderas.', 'Inclina el torso hacia atrás y contrae los abdominales.', 'Encoge las piernas mientras inclinas un poco el tronco hacia delante.', 'Mantén la posición por un momento y luego baja las piernas de manera controlada.', 'Repite el movimiento durante el número deseado de repeticiones.', 'Este ejercicio trabaja los músculos abdominales inferiores y ayuda a fortalecer el core.']::text[] where nombre = 'Crunch Inferior sentado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Inferior sentado en banco
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en el borde de un banco, con las piernas extendidas frente a ti y las manos agarrando el banco, a ambos lados de las caderas.', 'Inclina el torso hacia atrás y contrae los abdominales.', 'Levanta lentamente las piernas, con una ligera flexión, lo más alto que puedas sin arquear la espalda mientras inclinas un poco el tronco hacia delante.', 'Mantén la posición por un momento y luego baja las piernas de manera controlada.', 'Repite el movimiento durante el número deseado de repeticiones.', 'Este ejercicio trabaja los músculos abdominales inferiores y ayuda a fortalecer el core.']::text[] where nombre = 'Crunch Inferior sentado en banco' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Lateral con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas a la anchura aproximada de la cadera, sujeta una barra sobre el trapecio.', 'Flexiona el tronco lateralmente, sin inclinarte hacia delante ni hacia atrás.']::text[] where nombre = 'Crunch Lateral con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Lateral con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas a la anchura aproximada de la cadera, sujeta la mancuerna con una mano.', 'Flexiona el tronco lateralmente, sin inclinarte hacia delante ni hacia atrás.', 'Baja la mancuerna, sin hacer fuerza con el brazo, deja el peso "muerto".', 'Vuelve a la posición inicial sin movimientos bruscos.']::text[] where nombre = 'Crunch Lateral con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Lateral de pie con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie situado al lado de una banda en algún soporte a la altura de los pies, coge el agarre con una mano con el brazo extendido al lado del cuerpo.', 'Encoge el torso lateralmente hacia el lado de la banda.', 'A continuación inclínate hacia el lado opuesto mediante la contracción de los abdominales oblicuos, sin tirar del brazo.', 'Al terminar la serie cambia de lado.']::text[] where nombre = 'Crunch Lateral de pie con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Lateral de pie en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie situado al lado de la polea alta, coge el agarre con una mano y ponla a la altura de la cabeza, con el brazo flexionado hacia arriba al lado del cuerpo.', 'Encoge el torso lateralmente hacia el lado de la polea mediante la contracción de los abdominales oblicuos, sin tirar del brazo.', 'Al terminar la serie cambia de lado.']::text[] where nombre = 'Crunch Lateral de pie en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Lateral de pie en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie situado al lado de la polea baja, coge el agarre con una mano con el brazo extendido al lado del cuerpo.', 'Encoge el torso lateralmente hacia el lado de la polea.', 'A continuación inclínate hacia el lado opuesto mediante la contracción de los abdominales oblicuos, sin tirar del brazo.', 'Al terminar la serie cambia de lado.']::text[] where nombre = 'Crunch Lateral de pie en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Lateral en soporte
update public.tipo_ejercicio set instructions = ARRAY['Apoya la espalda y los antebrazos en el soporte, con las manos agarradas.', 'Flexiona las rodillas 90º con las piernas hacia delante.', 'Encoge la cadera lateralmente hacia un lado mediante la contracción de los abdominales oblicuos.', 'A continuación procede hacia el otro lado, y así hasta completar la serie.']::text[] where nombre = 'Crunch Lateral en soporte' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Lateral Horizontal Alterno
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con las rodillas dobladas y los pies apoyados en el suelo.', 'Mantén los brazos extendidos a los lados del cuerpo con las palmas hacia abajo.', 'Levanta ligeramente la cabeza, los hombros y la parte superior de la espalda del suelo.', 'Desde esta posición, lleva una mano hacia el talón del mismo lado, tocándolo ligeramente, mientras contraes los músculos abdominales.', 'Alterna los lados, llevando la mano izquierda hacia el talón derecho y luego la mano derecha hacia el talón derecho.', 'Mantén el movimiento controlado y continúa alternando los toques de talón durante el número deseado de repeticiones.', 'Este ejercicio trabaja los músculos oblicuos y abdominales, ayudando a fortalecer el núcleo.']::text[] where nombre = 'Crunch Lateral Horizontal Alterno' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Lateral Horizontal Concentrado
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate de lado en el suelo con las piernas juntas y ligeramente flexionadas.', 'Coloca la mano del brazo superior detrás de la cabeza o en el suelo frente a ti.', 'Contrae los abdominales y levanta el torso hacia el lado, llevando el codo hacia la cadera en un movimiento de crunch lateral.', 'Baja el torso de forma controlada hacia el suelo.', 'Completa el número deseado de repeticiones en un lado y luego cambia de lado para trabajar el otro lado de los oblicuos.', 'Este ejercicio se enfoca en los músculos oblicuos y ayuda a tonificar y fortalecer los músculos de la cintura.']::text[] where nombre = 'Crunch Lateral Horizontal Concentrado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Lateral Inclinado
update public.tipo_ejercicio set instructions = ARRAY['En un banco de lumbares, colócate de lado apoyando la cadera en el respaldo y con los pies bloqueados en los topes.', 'Pon las manos detrás de la cabeza.', 'Encoge el torso lateralmente de lado a lado, mediante la contracción de los abdominales oblicuos.', 'Al terminar la serie cambia de lado.']::text[] where nombre = 'Crunch Lateral Inclinado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en el suelo con las piernas ligeramente flexionadas, las manos entrelazadas en el pecho.', 'Deslízate hacia atrás manteniendo el control, luego utiliza los músculos abdominales para levantar el torso de nuevo.', 'Concéntrate en activar los abdominales, evita el impulso y repite el movimiento.', 'Este ejercicio fortalece el core y las caderas.']::text[] where nombre = 'Crunch Superior' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior Concentrado Elevado
update public.tipo_ejercicio set instructions = ARRAY['Túmbate en el suelo con las piernas flexionadas 90º y los pies apoyados sobre un banco, silla o algo elevado.', 'Coloca las manos detrás de la cabeza.', 'Realiza una flexión de tronco, manteniendo la parte baja de la espalda en contacto con el suelo.', 'Mantén la posición unos instantes y regresa a la posición inicial.', 'Repite el movimiento las veces necesarias sin descansar abajo.', 'Este ejercicio fortalece los músculos abdominales y oblicuos, mejorando la fuerza y estabilidad del core.']::text[] where nombre = 'Crunch Superior Concentrado Elevado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior Cruzado
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con las rodillas dobladas y los pies apoyados en el suelo.', 'Coloca las manos delante del pecho sin apoyar, con los dedos entrelazados.', 'Levanta los hombros del suelo mientras contraes los abdominales.', 'A medida que subes, gira el torso y lleva el codo derecho hacia la rodilla izquierda.', 'Regresa a la posición inicial y repite del otro lado, llevando el codo izquierdo a la rodilla derecha.', 'Alterna los lados en cada repetición.', 'Este ejercicio trabaja los músculos oblicuos y abdominales']::text[] where nombre = 'Crunch Superior Cruzado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior Cruzado Concentrado
update public.tipo_ejercicio set instructions = ARRAY['Túmbate en el suelo con las piernas flexionadas.', 'Pon un pie sobre el muslo contrario, de forma que la rodilla salga lateralmente.', 'Coloca la mano de ese lado ligeramente sobre el abdomen y la otra detrás de la cabeza.', 'Realiza una flexión de tronco, llevando el codo libre hacia la rodilla opuesta mientras giras el torso hacia ese lado.', 'Regresa a la posición inicial y repite el movimiento al mismo lado.', 'Al terminar la serie hazlo con el otro lado.', 'Este ejercicio fortalece los músculos abdominales y oblicuos, mejorando la fuerza y estabilidad del core.']::text[] where nombre = 'Crunch Superior Cruzado Concentrado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior Cruzado Concentrado Elevado
update public.tipo_ejercicio set instructions = ARRAY['Túmbate en el suelo con las piernas flexionadas 90º y los pies apoyados sobre un banco, silla o algo elevado.', 'Coloca un brazo extendido con la mano apoyada en el suelo al lado de la cadera.', 'La otra mano detrás de la cabeza.', 'Realiza una flexión de tronco, llevando el codo libre hacia la rodilla opuesta mientras giras el torso hacia ese lado.', 'Regresa a la posición inicial y repite el movimiento al mismo lado.', 'Al terminar la serie hazlo con el otro lado.', 'Este ejercicio fortalece los músculos abdominales y oblicuos, mejorando la fuerza y estabilidad del core.']::text[] where nombre = 'Crunch Superior Cruzado Concentrado Elevado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior Cruzado Declinado
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en un banco declinado con los pies asegurados y las manos detrás de la cabeza.', 'Realiza una flexión de tronco, llevando los codos hacia las rodillas mientras giras el torso hacia un lado, tratando de tocar con él la rodilla opuesta.', 'Regresa a la posición inicial y repite el movimiento hacia el otro lado.', 'Este ejercicio fortalece los músculos abdominales y oblicuos, mejorando la fuerza y estabilidad del core.']::text[] where nombre = 'Crunch Superior Cruzado Declinado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior de pie con Bandas
update public.tipo_ejercicio set instructions = ARRAY['Agarra las bandas de un soporte alto.', 'Ponte de rodillas de espaldas a ellas.', 'Agarra un extremo con cada mano a los lados de la cabeza, con los brazos por delante flexionados hacia arriba, con la espalda recta.', 'Realiza el encogimiento hacia delante, apretando el abdomen superior.']::text[] where nombre = 'Crunch Superior de pie con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior de pie con Polea delante
update public.tipo_ejercicio set instructions = ARRAY['De pie de cara a la polea alta, coge la barra con las manos en supinación (palmas hacia arriba) y ponla frente tu cabeza, con los brazos flexionados 90º.', 'Encoge el torso mediante la contracción de los abdominales superiores, sin tirar del cuello ni los brazos.']::text[] where nombre = 'Crunch Superior de pie con Polea delante' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior de rodillas con Polea
update public.tipo_ejercicio set instructions = ARRAY['De rodillas de cara a la polea alta, coge la cuerda con las dos manos y ponla sobre tu cabeza, con los brazos ligeramente flexionados.', 'Encoge y baja el torso mediante la contracción de los abdominales superiores, sin tirar del cuello ni los brazos.']::text[] where nombre = 'Crunch Superior de rodillas con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior Declinado
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en un banco declinado con los pies asegurados.', 'Cruza los brazos sobre el pecho o colócalos detrás de la cabeza.', 'Desciende lentamente hacia atrás hasta que tu espalda esté casi paralela al suelo, y luego utiliza los músculos abdominales para levantar el torso hacia adelante hasta una posición vertical.', 'Mantén el control del movimiento y evita balancearte hacia adelante y hacia atrás.', 'Repite el movimiento durante el número deseado de repeticiones.', 'Este ejercicio trabaja los músculos abdominales superiores y puede aumentar la fuerza y resistencia del core.']::text[] where nombre = 'Crunch Superior Declinado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior en Fitball
update public.tipo_ejercicio set instructions = ARRAY['Apoya la espalda sobre el fitball, con los pies apoyados en el suelo, las rodillas flexionadas a 90° y las manos delante del pecho.', 'Desde atrás, con la espalda casi en su totalidad apoyada sobre el fitball excepto la cabeza y columna dorsal que deben estar levemente despegadas del objeto, inspira y mientras exhalas el aire inicia el encogimiento abdominal para elevar el torso mediante la contracción de los músculos abdominales superiores...', 'Regresa lentamente a la posición inicial y repite tantas veces como necesites para completar la serie de ejercicios.']::text[] where nombre = 'Crunch Superior en Fitball' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior Horizontal en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba con las manos en el soporte, encoge la parte alta del torso hacia delante mediante la contracción de los abdominales superiores, sin tirar del cuello ni los brazos.']::text[] where nombre = 'Crunch Superior Horizontal en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior sentado con Polea
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, de espaldas a la polea alta, coge la cuerda y ponla tras tu cabeza, con una mano agarrando cada extremo.', 'Encoge el torso mediante la contracción de los abdominales superiores, sin tirar del cuello ni los brazos.']::text[] where nombre = 'Crunch Superior sentado con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Crunch Superior Vertical Amplio en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina con las manos en el soporte, encoge el torso hacia delante todo lo que puedas, mediante la contracción de los abdominales, sin tirar del cuello ni los brazos.']::text[] where nombre = 'Crunch Superior Vertical Amplio en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Cuarto de Sentadilla con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas a la anchura de los hombros y una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Desciende flexionando las rodillas ligeramente, aproximadamente a 45º.', 'Sube de nuevo estirando bien arriba.']::text[] where nombre = 'Cuarto de Sentadilla con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Cuarto de Sentadilla con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y con las piernas separadas a la anchura de los hombros, coge una mancuerna con cada mano.', 'Desciende flexionando las rodillas ligeramente, aproximadamente a 45º.', 'Sube de nuevo estirando bien arriba.']::text[] where nombre = 'Cuarto de Sentadilla con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl a una mano en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De rodillas o de pie, con la palma de la mano mirando hacia abajo y el codo flexionado a 90 grados, sujetar firmemente la barra de la polea y realizar el movimiento de subida y bajada de la muñeca, manteniendo inmóvil el brazo.']::text[] where nombre = 'Curl a una mano en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Aislado con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge la barra por el centro con una mano, con la palma hacia arriba (supinación).', 'Sube la barra flexionando el codo y desciende de forma controlada, manteniendo el equilibrio con la barra recta.']::text[] where nombre = 'Curl Aislado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Aislado en Pronación con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge una mancuerna con una mano y con la palma hacia atrás (pronación).', 'Flexiona el codo llevando la mancuerna a la altura del pecho y desciende nuevamente de forma controlada.']::text[] where nombre = 'Curl Aislado en Pronación con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Aislado en Pronación en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, coge la polea baja con una mano y la palma hacia atrás (pronación).', 'Ponte de cara a la polea con las piernas ligeramente separadas.', 'Flexiona el codo subiendo la mano hasta el pecho, sin mover el brazo.', 'Desciende de forma controlada.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Curl Aislado en Pronación en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Aislado en Supinación con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge una mancuerna con una mano y con la palma hacia delante (supinación).', 'Flexiona el codo llevando la mancuerna a la altura del pecho y desciende nuevamente de forma controlada.']::text[] where nombre = 'Curl Aislado en Supinación con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Aislado en Supinación en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, coge la polea baja con una mano y la palma hacia delante (supinación).', 'Ponte de cara a la polea con las piernas ligeramente separadas.', 'Flexiona el codo subiendo la mano hasta el pecho, sin mover el brazo.', 'Desciende de forma controlada.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Curl Aislado en Supinación en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Aislado hacia abajo con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas, inclínate hacia delante con la espalda paralela al suelo.', 'Coge una mancuerna con una mano y con la palma hacia el interior.', 'Flexiona el codo llevando la mancuerna frente al pectoral opuesto y desciende nuevamente de forma controlada.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Curl Aislado hacia abajo con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Aislado Largo en Supinación en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, coge la polea baja con una mano y la palma hacia delante (supinación).', 'Da un paso hacia delante para que el brazo quede ligeramente por detrás.', 'Flexiona el codo subiendo la mano hasta el pecho, sin mover el brazo.', 'Desciende de forma controlada.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Curl Aislado Largo en Supinación en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Aislado Neutro con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge una mancuerna con una mano y con la palma hacia el cuerpo (agarre neutro).', 'Flexiona el codo llevando la mancuerna a la altura del pecho y desciende nuevamente de forma controlada.']::text[] where nombre = 'Curl Aislado Neutro con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Alterno en Supinación en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina, coge los agarres con las palmas de las manos hacia arriba (supinación).', 'Sube una mano flexionando el codo hasta llegar a la altura del pecho, y desciende de forma controlada mientras subes el otro brazo.']::text[] where nombre = 'Curl Alterno en Supinación en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl con giro Alterno con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge una mancuerna con cada mano y con la palma hacia el cuerpo (agarre neutro).', 'Flexiona un codo subiendo la mancuerna a la altura del pecho mientras giras la muñeca con la palma hacia dentro.', 'Mientras desciendes, sube el otro brazo.']::text[] where nombre = 'Curl con giro Alterno con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl con peso libre
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia arriba en el suelo y agarra una barra con las manos a la anchura de los hombros.', 'Una vez colgado de ella, realiza el ascenso flexionando los codos.', 'Desciende lentamente y procede de nuevo.', 'Se puede hacer con agarre en supinación y en pronación.']::text[] where nombre = 'Curl con peso libre' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado Cerrado con Barra
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco, coge la barra con las manos en supinación (palmas hacia arriba) a una anchura inferior a la de los hombros.', 'Inclina el cuerpo hacia delante y abre las piernas, apoyando los codos en el borde del banco.', 'Flexiona los codos y sube la barra hasta llegar casi a la cabeza.', 'Desciende lentamente sin despegar los codos.']::text[] where nombre = 'Curl Concentrado Cerrado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado Cerrado con Barra Z
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, coge la barra con las manos en supinación (palmas hacia arriba) a una anchura inferior a la de los hombros.', 'Inclina el cuerpo hacia delante y abre las piernas, apoyando los codos en el borde del banco o en los muslos.', 'Flexiona los codos y sube la barra hasta llegar casi a la cabeza.', 'Desciende lentamente sin despegar los codos.']::text[] where nombre = 'Curl Concentrado Cerrado con Barra Z' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado Cerrado en Polea Baja
