-- csv: Curl Concentrado con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie, coge la barra con las manos en supinación (palmas hacia arriba) a la anchura de los hombros.', 'Flexiona ligeramente las piernas e inclina el cuerpo hacia delante, apoyando los codos en los muslos.', 'Flexiona los codos y sube la barra hasta llegar casi a la cabeza.', 'Desciende lentamente sin despegar los codos.']::text[] where nombre = 'Curl Concentrado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado de Dedos con Barra
update public.tipo_ejercicio set instructions = ARRAY['Sentado, con los antebrazos apoyados sobre las rodillas o el banco y las palmas de las manos mirando hacia arriba, sujetar la barra con las manos a la anchura de los hombros y descenderla suavemente sobre las manos estirando los dedos, sin despegar los antebrazos del apoyo.', 'Estirar lo máximo posible y realizar la contracción de los dedos ascendiendo la barra de nuevo hasta cerrar los puños.']::text[] where nombre = 'Curl Concentrado de Dedos con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina, coge los agarres con las palmas de las manos hacia arriba (supinación).', 'Sube las manos flexionando los codos hasta llegar cerca de la cabeza, y desciende de forma controlada.']::text[] where nombre = 'Curl Concentrado en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado en Pronación con Banda
update public.tipo_ejercicio set instructions = ARRAY['Sentado, con el antebrazo apoyado sobre la rodilla o el banco y la palma de la mano mirando hacia abajo, sujetar firmemente la banda y realizar el movimiento de subida y bajada de la muñeca, sin despegar el antebrazo del apoyo.']::text[] where nombre = 'Curl Concentrado en Pronación con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado en Pronación con Barra
update public.tipo_ejercicio set instructions = ARRAY['Sentado, con los antebrazos apoyados sobre las rodillas o el banco y las palmas de las manos mirando hacia abajo, sujetar firmemente la barra con las manos a la anchura de los hombros y realizar el movimiento de subida y bajada de las muñecas, sin despegar los antebrazos del apoyo.']::text[] where nombre = 'Curl Concentrado en Pronación con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
