-- csv: Curl Concentrado en Supinación con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Sentado, con el antebrazo apoyado sobre la rodilla o el banco y la palma de la mano mirando hacia arriba, sujetar firmemente la mancuerna y realizar el movimiento de subida y bajada de la muñeca, sin despegar el antebrazo del apoyo.']::text[] where nombre = 'Curl Concentrado en Supinación con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado en Supinación con Polea
update public.tipo_ejercicio set instructions = ARRAY['Sentado, con los antebrazos apoyados sobre las rodillas o el banco y las palmas de las manos mirando hacia arriba, sujetar firmemente la barra de la polea y realizar el movimiento de subida y bajada de las muñecas, sin despegar los antebrazos del apoyo.']::text[] where nombre = 'Curl Concentrado en Supinación con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado en Supinación en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['Agachado con las piernas abiertas, inclina el cuerpo hacia delante y coge la barra corta de la polea con las manos hacia arriba (supinación).', 'Apoya la parte de atrás de los codos en el interior de los muslos.', 'Flexiona los codos subiendo la barra hasta la cara.', 'Desciende de forma controlada.']::text[] where nombre = 'Curl Concentrado en Supinación en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado Frontal Aislado en Supinación en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['Sentado en el suelo, flexiona una pierna con el pie apoyado en el suelo y estira la otra, abiertas.', 'Coge la polea baja con la palma hacia arriba (supinación) y apoya la parte de atrás del codo en la rodilla.', 'Flexiona el codo acercando la mano a la cabeza y desciende nuevamente de forma controlada, sin estirar del todo para no relajar.']::text[] where nombre = 'Curl Concentrado Frontal Aislado en Supinación en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado Lateral Aislado en Supinación en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, abre las piernas e inclina el cuerpo hacia delante.', 'Coge la polea baja con la palma hacia arriba (supinación) y apoya la parte de atrás del codo en el interior del muslo.', 'Flexiona el codo acercando la mano a la cabeza y desciende nuevamente de forma controlada, sin estirar del todo para no relajar.']::text[] where nombre = 'Curl Concentrado Lateral Aislado en Supinación en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Concentrado Neutral con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Sentado, con el antebrazo apoyado sobre la rodilla o el banco y la palma de la mano mirando hacia la otra mano (agarre en martillo), sujetar firmemente la mancuerna y realizar el movimiento de subida y bajada de la muñeca (en este caso es un movimiento lateral), sin despegar el antebrazo del apoyo.']::text[] where nombre = 'Curl Concentrado Neutral con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Banco Scott en Pronación Aislado con Polea
update public.tipo_ejercicio set instructions = ARRAY['Sentado en el banco con el pecho apoyado, coge la polea con agarre en pronación (palma hacia abajo).', 'Apoya bien la parte trasera superior del brazo en el banco scott y flexiona el codo subiendo la polea.', 'Desciende lentamente sin llegar a estirar del todo.']::text[] where nombre = 'Curl en Banco Scott en Pronación Aislado con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
