-- csv: Curl en caída con Bandas
update public.tipo_ejercicio set instructions = ARRAY['De pie, engancha las bandas en algún lugar alto.', 'Coge un extremo con cada mano, con los codos flexionados y las palmas hacia el cuerpo.', 'Déjate caer suavemente estirando los brazos.', 'Flexiona de nuevo tirando de los bíceps para volver arriba.']::text[] where nombre = 'Curl en caída con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Martillo Alterno con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge una mancuerna con cada mano y con la palma hacia el cuerpo (agarre neutro).', 'Flexiona un codo llevando la mancuerna a la altura del pecho.', 'Mientras desciende, sube la otra mancuerna.']::text[] where nombre = 'Curl en Martillo Alterno con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Martillo con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge la barra con agarre neutro o en martillo (barra con agarres especiales), por delante del cuerpo.', 'Flexiona los codos hasta subir la barra hasta la altura del pecho y baja de forma controlada.']::text[] where nombre = 'Curl en Martillo con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Martillo Cruzado con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge una mancuerna con cada mano y con la palma hacia el cuerpo (agarre neutro).', 'Flexiona un codo llevando la mancuerna al pectoral opuesto.', 'Mientras desciende, sube la otra mancuerna al pectoral contrario.']::text[] where nombre = 'Curl en Martillo Cruzado con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Martillo en Máquina Scott
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina Scott con el pecho apoyado, coge los agarres con las palmas de las manos enfrentadas (agarre neutro o martillo).', 'Sube las manos flexionando los codos hasta llegar cerca de la cabeza, y desciende de forma controlada, con la parte superior de los brazos siempre bien apoyada en el banco.']::text[] where nombre = 'Curl en Martillo en Máquina Scott' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Martillo en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, coge los extremos de la cuerda con las manos a la anchura de los hombros y estira los brazos hacia delante.', 'Flexiona los codos llevando la cuerda a la cabeza.', 'Vuelve a la posición inicial de forma controlada.']::text[] where nombre = 'Curl en Martillo en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Martillo en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge la cuerda con las manos a la anchura de los hombros, flexiona los codos subiendo la cuerda hasta el pecho, con los codos pegados al cuerpo.', 'Desciende de forma controlada.']::text[] where nombre = 'Curl en Martillo en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
