-- csv: Curl en Supinación Aislado con Banda
update public.tipo_ejercicio set instructions = ARRAY['Coloca la banda a la altura del pecho.', 'Estira el brazo lateralmente y agarra el extremo de la banda con la palma de la mano hacia arriba.', 'Flexiona el codo acercando la mano a la cabeza y vuelve a estirar lentamente.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Curl en Supinación Aislado con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
