-- csv: Curl en Supinación Concentrado con Banda
update public.tipo_ejercicio set instructions = ARRAY['Sentado con las piernas bien separadas y el cuerpo ligeramente inclinado hacia delante, pisa la banda cerca del extremo y agárralo con una mano, con la palma hacia la pierna contraria.', 'Apoya el codo en el muslo y flexiona hasta llegar con la mano cerca de la cabeza.', 'Desciende lentamente sin llegar a estirar del todo para no relajar el músculo.']::text[] where nombre = 'Curl en Supinación Concentrado con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
