-- csv: Curl en Supinación en Máquina Scott
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina Scott con el pecho apoyado, coge los agarres con las palmas de las manos hacia arriba (supinación).', 'Sube las manos flexionando los codos hasta llegar cerca de la cabeza, y desciende de forma controlada, con la parte superior de los brazos siempre bien apoyada en el banco.']::text[] where nombre = 'Curl en Supinación en Máquina Scott' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Supinación en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, con la espalda recta, coge la barra con las manos a la anchura de los hombros en supinación (palmas hacia arriba) y estira los brazos hacia arriba.', 'Flexiona los codos llevando la barra tras la cabeza.', 'Desciende ligeramente los codos para realizar bien la contracción.', 'Vuelve a la posición inicial de forma controlada.']::text[] where nombre = 'Curl en Supinación en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Supinación en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge la barra con las manos a la anchura de los hombros y con las palmas hacia arriba, flexiona los codos subiendo la barra hasta el pecho, con los codos pegados al cuerpo.', 'Desciende de forma controlada.']::text[] where nombre = 'Curl en Supinación en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Supinación hacia abajo con Barra
update public.tipo_ejercicio set instructions = ARRAY['Boca abajo con el pecho apoyado en el respaldo del banco y con los brazos sueltos hacia delante, con los pies en el suelo.', 'Agarra la barra con las palmas hacia delante (supinación) a la anchura de los hombros.', 'Flexiona los codos hasta llegar a arriba y desciende lentamente, todo sin mover la parte superior de los brazos.']::text[] where nombre = 'Curl en Supinación hacia abajo con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Supinación hacia abajo con Barra Z
update public.tipo_ejercicio set instructions = ARRAY['Apoyando la parte trasera de los brazos en un banco (por ejemplo Scott, pero al revés, aunque sirve un banco plano tumbado boca abajo) y con los brazos sueltos hacia delante, con los pies en el suelo.', 'Agarra la barra con las palmas hacia delante (supinación) a la anchura máxima de la barra z.', 'Flexiona los codos hasta llegar a arriba y desciende lentamente, todo sin mover la parte superior de los brazos.']::text[] where nombre = 'Curl en Supinación hacia abajo con Barra Z' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl en Supinación Retraído con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge la barra con las manos a la anchura de los hombros, con las palmas hacia arriba (supinación).', 'Sube la barra flexionando los codos y echándoles hacia atrás, luego desciende de forma controlada a la posición inicial.']::text[] where nombre = 'Curl en Supinación Retraído con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
