-- csv: Curl Femoral Aislado en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Con el muslo apoyado, la rodillas libre y la parte trasera del tobillo en el rodillo.', 'Flexiona la rodilla hacia atrás 90°, manteniendo inmóvil la parte alta de la pierna.', 'Vuelve de forma controlada sin relajar el músculo.', 'Al terminar la serie cambia de pierna.']::text[] where nombre = 'Curl Femoral Aislado en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Femoral Horizontal en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia abajo en el banco de la máquina, con las rodillas libres y la parte trasera de los tobillos en el rodillo.', 'Flexiona las rodillas hacia atrás 90°, manteniendo inmóvil la parte alta de la pierna, sin levantar los glúteos.', 'Vuelve de forma controlada sin relajar el músculo.']::text[] where nombre = 'Curl Femoral Horizontal en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Femoral Libre
update public.tipo_ejercicio set instructions = ARRAY['De rodillas en el suelo con los tobillos sujetos por alguna plataforma, banco o step.', 'Trata de estirar las piernas llevando el cuerpo hacia delante hasta tumbarte en el suelo.', 'Vuelve a la posicion inicial flexionando las piernas y dejando el cuerpo en vertical.']::text[] where nombre = 'Curl Femoral Libre' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Femoral Libre Asistido con Polea
update public.tipo_ejercicio set instructions = ARRAY['De rodillas sobre el banco con los tobillos agarrados y de espaldas a la polea, coge la barra por detrás de la cabeza con agarre ancho y las manos hacia delante.', 'Trata de estirar las piernas llevando el cuerpo hacia delante hasta estar en paralelo al suelo.', 'Vuelve a la posición inicial flexionando las piernas y dejando el cuerpo vertical.']::text[] where nombre = 'Curl Femoral Libre Asistido con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Femoral Vertical en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado con el respaldo algo inclinado y la espalda bien apoyada, con las rodillas libres y la parte trasera de los tobillos en el rodillo.', 'Flexiona las rodillas hacia atrás 90°, manteniendo inmóvil la parte alta de la pierna.', 'Vuelve de forma controlada sin relajar el músculo.']::text[] where nombre = 'Curl Femoral Vertical en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Femoral Vertical en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie de cara a la polea baja con las piernas casi juntas, ponte la correa en un tobillo.', 'Flexiona la rodilla hacia atrás 90°, manteniendo inmóvil la parte alta de la pierna.', 'Vuelve de forma controlada sin relajar el músculo.']::text[] where nombre = 'Curl Femoral Vertical en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Horizontal Cerrado en Supinación con Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco plano, coge la barra de la polea con las manos a una anchura inferior a la de los hombros y las palmas hacia arriba (supinación).', 'Flexiona los codos y elévalos, de forma que llegues con la barra hasta la cara.', 'Luego desciende de nuevo lentamente.']::text[] where nombre = 'Curl Horizontal Cerrado en Supinación con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Horizontal con giro con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco plano, coge una mancuerna con cada mano con las palmas hacia el cuerpo (agarre neutro) y extiende los brazos a los lados, a 45º del cuerpo.', 'Flexiona los codos manteniendo los brazos inmovilizados, hasta llegar con las mancuernas frente al pecho, mientras giras las muñecas hacia adentro (palmas hacia arriba).', 'Al llegar a arriba sube un poco los brazos para una mayor contracción.', 'Desciende de forma controlada a la posición inicial.']::text[] where nombre = 'Curl Horizontal con giro con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Horizontal con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco plano, coge una mancuerna con cada mano con las palmas hacia arriba (supinación) y extiende los brazos a los lados, perpendiculares al cuerpo (como si fuese una apertura de pecho).', 'Flexiona los codos manteniendo los brazos inmovilizados, hasta llegar con las mancuernas frente al pecho.', 'Desciende de forma controlada.']::text[] where nombre = 'Curl Horizontal con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Horizontal en Supinación con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco plano, coge una mancuerna con cada mano con las palmas hacia arriba (supinación) y extiende los brazos a los lados, a 45º del cuerpo.', 'Flexiona los codos manteniendo los brazos inmovilizados, hasta llegar con las mancuernas frente al pecho.', 'Al llegar a arriba sube un poco los brazos intentando girar las muñecas hacia afuera para una mayor contracción.', 'Desciende de forma controlada.']::text[] where nombre = 'Curl Horizontal en Supinación con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Horizontal en Supinación con Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco plano, coge la barra de la polea con las manos a la anchura de los hombros y las palmas hacia arriba (supinación).', 'Flexiona los codos llevando la barra frente al pecho y desciende de nuevo lentamente.']::text[] where nombre = 'Curl Horizontal en Supinación con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Horizontal Inclinado con Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco inclinado, coge un agarre con cada mano con las palmas hacia arriba (supinación) y extiende los brazos a los lados, perpendiculares al cuerpo (como si fuese una apertura de pecho).', 'Flexiona los codos manteniendo los brazos inmovilizados, hasta llegar con las manos frente a los hombros.', 'Desciende de forma controlada.']::text[] where nombre = 'Curl Horizontal Inclinado con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Inclinado Alterno en Supinación con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco inclinado, coge una mancuerna con cada mano con las palmas hacia delante (supinación).', 'Deja caer los brazos a ambos lados del cuerpo.', 'Sube una mancuerna flexionando el codo hasta llegar a la altura del pecho.', 'Desciende completamente y al llegar a abajo, sube el otro brazo.']::text[] where nombre = 'Curl Inclinado Alterno en Supinación con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Inclinado con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie, con el pecho apoyado sobre un banco con el respaldo inclinado y los brazos colgando hacia abajo, sujetar firmemente la barra con las manos a la anchura de los hombros y las palmas mirando hacia atrás y realizar el movimiento de subida y bajada de las muñecas en su máximo recorrido.']::text[] where nombre = 'Curl Inclinado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Inclinado con giro Alterno con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco inclinado, coge una mancuerna con cada mano con las palmas hacia el interior (agarre neutro o martillo) y deja caer los brazos a ambos lados del cuerpo.', 'Flexiona un codo subiendo la mancuerna a la altura del pecho mientras giras la muñeca con la palma hacia arriba.', 'Mientras desciendes, sube el otro brazo.']::text[] where nombre = 'Curl Inclinado con giro Alterno con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Inclinado Lateral con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco inclinado, coge una mancuerna con cada mano con las palmas hacia arriba (supinación) y deja caer los brazos a ambos lados del cuerpo, separándolos formando un ángulo de 45º con el mismo.', 'Flexiona los codos subiendo las mancuernas a la altura de los hombros.', 'Desciende de forma controlada.']::text[] where nombre = 'Curl Inclinado Lateral con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Inclinado Neutro Alterno con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco inclinado, coge una mancuerna con cada mano con las palmas hacia el interior (agarre neutro o martillo) y deja caer los brazos a ambos lados del cuerpo.', 'Flexiona un codo subiendo la mancuerna a la altura del pecho.', 'Mientras desciende, sube el otro brazo.']::text[] where nombre = 'Curl Inclinado Neutro Alterno con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Lateral con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge una mancuerna con cada mano y estira los brazos lateralmente a ambos lados del cuerpo, con las palmas de las manos hacia arriba.', 'Flexiona los codos hasta llevar las mancuernas cerca de la cabeza, sin mover la parte superior de los brazos.', 'Estira de nuevo de forma controlada sin estirar del todo.']::text[] where nombre = 'Curl Lateral con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Lateral en Supinación Aislado con Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie ponte en perpendicular a la polea con las piernas ligeramente separadas.', 'Con la polea a la altura del hombro, estira un brazo y agarra con la mano en supinación (palma hacia arriba).', 'Flexiona el codo llevando la mano cerca de la cabeza, sin mover el brazo.', 'Desciende lentamente.']::text[] where nombre = 'Curl Lateral en Supinación Aislado con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Lateral en Supinación con Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie ponte entre dos poleas con las piernas ligeramente separadas.', 'Con las poleas a la altura de los hombros, estira los brazo a los lados y agarra con las manos en supinación (palmas hacia arriba).', 'Flexiona los codos llevando las manos cerca de la cabeza, sin mover los brazos.', 'Desciende lentamente.']::text[] where nombre = 'Curl Lateral en Supinación con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Spider Aislado en Pronación con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Boca abajo con el pecho apoyado en el respaldo del banco inclinado y con los brazos sueltos hacia delante.', 'Puedes poner las rodillas sobre el banco o directamente estirar las piernas con los pies en el suelo.', 'Agarra una mancuerna con una mano, con la palma hacia atrás (pronación).', 'Flexiona el codo hasta llegar a arriba y desciende lentamente, todo sin mover la parte superior del brazo.', 'Con la otra mano puedes agarrarte al banco para tener estabilidad.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Curl Spider Aislado en Pronación con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Spider Aislado en Supinación con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Boca abajo con el pecho apoyado en el respaldo del banco inclinado y con los brazos sueltos hacia delante.', 'Puedes poner las rodillas sobre el banco o directamente estirar las piernas con los pies en el suelo.', 'Agarra una mancuerna con una mano, con la palma hacia delante (supinación).', 'Flexiona el codo hasta llegar a arriba y desciende lentamente, todo sin mover la parte superior del brazo.', 'Con la otra mano puedes agarrarte al banco para tener estabilidad.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Curl Spider Aislado en Supinación con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Spider Aislado Neutro con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Boca abajo con el pecho apoyado en el respaldo del banco inclinado y con los brazos sueltos hacia delante.', 'Puedes poner las rodillas sobre el banco o directamente estirar las piernas con los pies en el suelo.', 'Agarra una mancuerna con una mano, con la palma hacia el cuerpo (agarre neutro).', 'Flexiona el codo hasta llegar a arriba y desciende lentamente, todo sin mover la parte superior del brazo.', 'Con la otra mano puedes agarrarte al banco para tener estabilidad.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Curl Spider Aislado Neutro con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Spider en Pronación con Barra
update public.tipo_ejercicio set instructions = ARRAY['Boca abajo con el pecho apoyado en el respaldo del banco inclinado y con los brazos sueltos hacia delante.', 'Puedes poner las rodillas sobre el banco o directamente estirar las piernas con los pies en el suelo.', 'Agarra la barra con las palmas hacia el cuerpo (pronación) a la anchura de los hombros.', 'Flexiona los codos hasta llegar a arriba y desciende lentamente, todo sin mover la parte superior de los brazos.']::text[] where nombre = 'Curl Spider en Pronación con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Spider en Supinación con Barra
update public.tipo_ejercicio set instructions = ARRAY['Boca abajo con el pecho apoyado en el respaldo del banco inclinado y con los brazos sueltos hacia delante.', 'Puedes poner las rodillas sobre el banco o directamente estirar las piernas con los pies en el suelo.', 'Agarra la barra con las palmas hacia delante (supinación) a la anchura de los hombros.', 'Flexiona los codos hasta llegar a arriba y desciende lentamente, todo sin mover la parte superior de los brazos.']::text[] where nombre = 'Curl Spider en Supinación con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Spider en Supinación con Barra Z
update public.tipo_ejercicio set instructions = ARRAY['Boca abajo con el pecho apoyado en el respaldo del banco inclinado y con los brazos sueltos hacia delante.', 'Puedes poner las rodillas sobre el banco o directamente estirar las piernas con los pies en el suelo.', 'Agarra la barra z con las palmas hacia delante (supinación) a la anchura de los hombros.', 'Flexiona los codos hasta llegar a arriba y desciende lentamente, todo sin mover la parte superior de los brazos.']::text[] where nombre = 'Curl Spider en Supinación con Barra Z' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Spider Neutro con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Boca abajo con el pecho apoyado en el respaldo del banco inclinado y con los brazos sueltos hacia delante.', 'Puedes poner las rodillas sobre el banco o directamente estirar las piernas con los pies en el suelo.', 'Agarra una mancuerna con ambas manos, con los dedos entrelazados.', 'Flexiona los codos hasta llegar a arriba y desciende lentamente, todo sin mover la parte superior de los brazos.']::text[] where nombre = 'Curl Spider Neutro con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Vertical de Dedos con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las palmas de las manos mirando hacia atrás, sujetar la barra por detrás del cuerpo con las manos a la anchura de los hombros y descenderla suavemente sobre las manos estirando los dedos lo máximo posible.', 'Después volver a cerrar los puños.']::text[] where nombre = 'Curl Vertical de Dedos con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Vertical en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie con las palmas de las manos mirando hacia atrás, sujetar firmemente la barra de la polea por detrás del cuerpo con las manos a la anchura de los hombros y realizar el movimiento de subida y bajada de las muñecas en su máximo recorrido.']::text[] where nombre = 'Curl Vertical en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Vertical en Supinación con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las palmas de las manos mirando hacia atrás, sujetar firmemente la barra por detrás del cuerpo con las manos a la anchura de los hombros y realizar el movimiento de subida y bajada de las muñecas en su máximo recorrido.']::text[] where nombre = 'Curl Vertical en Supinación con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Curl Vertical en Supinación con Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco plano, coge la barra de la polea con las manos a la anchura de los hombros y las palmas hacia arriba (supinación).', 'Flexiona los codos llevando la barra tras la cabeza, subiendo los codos un poco al final del movimiento.', 'Desciende de nuevo lentamente.']::text[] where nombre = 'Curl Vertical en Supinación con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Desplazamientos de Boxeo
update public.tipo_ejercicio set instructions = ARRAY['Se trata de mover las piernas hacia delante y hacia atrás, como si corriéramos en el sitio, sin necesitar metros para desplazarnos.', 'También podemos desplazarnos ligeramente hacia los lados.']::text[] where nombre = 'Desplazamientos de Boxeo' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a una anchura algo mayor que la de los hombros y las palmas hacia delante, sube el cuerpo mediante la flexión de los brazos hasta pasar la cabeza sobre la barra.', 'Desciende lentamente.']::text[] where nombre = 'Dominada' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada a una mano
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con una mano en agarre neutro (palma hacia el interior), sube el cuerpo mediante la flexión del brazo hasta llegar con la cabeza a la barra, inclinando hacia el lado contrario del brazo para compensar el peso.', 'Desciende lentamente.', 'Con la otra mano puedes coger peso para añadir dificultad.']::text[] where nombre = 'Dominada a una mano' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada a una mano asistida
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con una mano en agarre supino (palma hacia atrás) y otra mano en una cuerda o toalla más abajo y enganchada al otro lado de la barra, sube el cuerpo mediante la flexión del brazo hasta llegar con la cabeza a la barra.', 'Desciende lentamente.']::text[] where nombre = 'Dominada a una mano asistida' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada Abierta
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a una anchura mayor que la de los hombros y las palmas hacia delante, sube el cuerpo mediante la flexión de los brazos hasta pasar la cabeza sobre la barra.', 'Desciende lentamente.']::text[] where nombre = 'Dominada Abierta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada Cerrada
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a la anchura de los hombros y las palmas hacia delante, sube el cuerpo mediante la flexión de los brazos hasta pasar la cabeza sobre la barra.', 'Desciende lentamente.']::text[] where nombre = 'Dominada Cerrada' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada Cerrada Corta
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a la anchura de los hombros y las palmas hacia delante, sube el cuerpo mediante media flexión de los brazos abriendo los codos hacia los lados.', 'Desciende lentamente.']::text[] where nombre = 'Dominada Cerrada Corta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada Cerrada en Martillo
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos en posición neutra o de martillo, sube el cuerpo mediante la flexión de los brazos hasta pasar la cabeza sobre la barra.', 'Desciende lentamente.']::text[] where nombre = 'Dominada Cerrada en Martillo' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada Circular en Supinación
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a la anchura de los hombros y las palmas hacia atrás, sube lateralmente mediante la flexión de un brazo, luego iguala el otro brazo y relaja el primero, haciendo círculos en el ascenso.', 'Cambia el sentido de los círculos.']::text[] where nombre = 'Dominada Circular en Supinación' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada en Supinación
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a la anchura de los hombros y las palmas hacia atrás, sube el cuerpo mediante la flexión de los brazos hasta pasar la cabeza sobre la barra.', 'Desciende lentamente.']::text[] where nombre = 'Dominada en Supinación' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada Invertida
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a una anchura algo mayor que la de los hombros y las palmas hacia delante, da la vuelta al cuerpo pasando las piernas flexionadas por delante de la barra de dominadas y quedando boca abajo.', 'Sube el cuerpo mediante la flexión de los brazos hasta tocar con las piernas en la barra.', 'Desciende lentamente.']::text[] where nombre = 'Dominada Invertida' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada Lateral
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a una anchura mayor que la de los hombros y las palmas hacia delante, sube lateralmente mediante la flexión de un brazo hasta pasar la cabeza sobre la barra.', 'Desciende lentamente.', 'Cambia de brazo al terminar la serie o alterna a un lado cada vez.']::text[] where nombre = 'Dominada Lateral' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada Mixta
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a una anchura algo mayor que la de los hombros y una palma hacia cada lado, sube el cuerpo mediante la flexión de los brazos hasta pasar la cabeza sobre la barra.', 'Desciende lentamente.']::text[] where nombre = 'Dominada Mixta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Dominada Trasera
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a una anchura algo mayor que la de los hombros y las palmas hacia delante, sube el cuerpo mediante la flexión de los brazos hasta dejar la barra tras la cabeza.', 'Desciende lentamente.']::text[] where nombre = 'Dominada Trasera' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Completa con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge la barra con las manos en pronación (palmas hacia abajo) a la anchura de los hombros.', 'Con los brazos estirados, eleva la barra frontalmente hasta tenerla sobre la cabeza.', 'Desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Completa con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de Cadera con flexión de rodillas v1
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con las piernas rectas y los pies apoyados en el suelo, manteniendo las manos a los lados del cuerpo con las palmas hacia abajo.', 'Levanta lentamente las caderas del suelo, flexionando ligeramente las rodillas y llevando los muslos contra el abdomen.', 'Alcanza la posición más alta posible y luego baja las caderas de manera controlada hasta que vuelvan a tocar ligeramente el suelo, estirando de nuevo las piernas pero sin llegar a apoyar los pies.', 'Este ejercicio trabaja principalmente los músculos de los abdominales inferiores, fortaleciendo el núcleo y mejorando la estabilidad de la cadera.']::text[] where nombre = 'Elevación de Cadera con flexión de rodillas v1' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de Cadera con flexión de rodillas v2
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba sobre un banco con las piernas rectas, manteniendo las manos a los lados de la cabeza agarrando el propio banco.', 'Levanta lentamente las caderas del suelo, flexionando ligeramente las rodillas y llevando los muslos contra el abdomen.', 'Alcanza la posición más alta posible y luego baja las caderas de manera controlada estirando de nuevo las piernas pero sin llegar a descansar.', 'Este ejercicio trabaja principalmente los músculos de los abdominales inferiores, fortaleciendo el núcleo y mejorando la estabilidad de la cadera.']::text[] where nombre = 'Elevación de Cadera con flexión de rodillas v2' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de Cadera con piernas estiradas
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con las piernas rectas y los pies apoyados en el suelo, manteniendo las manos a los lados del cuerpo con las palmas hacia abajo.', 'Levanta lentamente las caderas del suelo, manteniendo las rodillas estiradas.', 'Alcanza la posición más alta posible y luego baja las caderas de manera controlada hasta que vuelvan a tocar ligeramente el suelo, llevando las piernas a la posición inicial sin llegar a descansar.', 'Este ejercicio trabaja principalmente los músculos de los abdominales inferiores, fortaleciendo el núcleo y mejorando la estabilidad de la cadera.']::text[] where nombre = 'Elevación de Cadera con piernas estiradas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de Cadera con piernas estiradas v2
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba sobre un banco con las piernas rectas y las manos agarrando el banco por encima de la cabeza.', 'Levanta las caderas.', 'Luego levanta lentamente las piernas, manteniendo las rodillas estiradas.', 'Alcanza la posición más alta posible y luego baja las caderas de manera controlada a la vez que las piernas, llevando las piernas a la posición inicial sin llegar a descansar.', 'Este ejercicio trabaja principalmente los músculos de los abdominales inferiores, fortaleciendo el núcleo y mejorando la estabilidad de la cadera.']::text[] where nombre = 'Elevación de Cadera con piernas estiradas v2' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de Cadera con piernas flexionadas
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con las rodillas dobladas y los pies apoyados en el suelo, manteniendo las manos a los lados del cuerpo con las palmas hacia abajo.', 'Levanta lentamente las caderas del suelo, manteniendo las rodillas dobladas en un ángulo de aproximadamente 90 grados.', 'Alcanza la posición más alta posible y luego baja las caderas de manera controlada hasta que vuelvan a tocar ligeramente el suelo.', 'Este ejercicio trabaja principalmente los músculos de los abdominales inferiores, fortaleciendo el núcleo y mejorando la estabilidad de la cadera.']::text[] where nombre = 'Elevación de Cadera con piernas flexionadas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de piernas alternas Colgado
update public.tipo_ejercicio set instructions = ARRAY['Cuélgate de una barra de dominadas con las manos hacia delante a una anchura algo superior a la de los hombros.', 'Flexiona las rodillas a 90º y eleva una hacia delante, mediante la contracción del abdomen hasta tener la rodilla a la altura de la cadera.', 'Desciende de forma controlada mientras subes la otra pierna.', 'Evita balanceos.']::text[] where nombre = 'Elevación de piernas alternas Colgado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de piernas colgado con Polea
update public.tipo_ejercicio set instructions = ARRAY['Agarra una correa a los pies y ésta a una polea baja (o dos, una a cada lado).', 'Colgado de una barra de dominadas con los brazos extendidos y las manos a una anchura superior a la de los hombros, levanta las piernas con ellas extendidas hacia el frente, formando un ángulo de 90º con el cuerpo (sin balanceos).']::text[] where nombre = 'Elevación de piernas colgado con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de piernas con Bandas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia arriba en el suelo, con las piernas estiradas y una banda en cada pie, conectadas previamente a algún soporte a la misma altura.', 'Pon las manos tras la cabeza.', 'Levanta las piernas completamente estiradas, tirando de la parte baja del abdomen, hasta ponerlas perpendiculares al suelo.', 'Desciende lentamente y repite.']::text[] where nombre = 'Elevación de piernas con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de Piernas con torsión en soporte
update public.tipo_ejercicio set instructions = ARRAY['Apoya la espalda y los antebrazos en el soporte, con las manos agarradas.', 'Eleva las piernas con ellas totalmente estiradas mediante la contracción del abdomen hasta tener los pies frente a la cadera (piernas a 90º del torso).', 'Desciende de forma controlada hacia un lado.', 'Vuelve a subir y desciende hacia el otro lado.', 'Evita balanceos.']::text[] where nombre = 'Elevación de Piernas con torsión en soporte' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de piernas en Fitball
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo sobre el fitball.', 'Apoya las manos en el suelo y deslízate hacia delante hasta lograr apoyar los pies sobre el fitball y las manos justo debajo de los hombros.', 'Procura apretar el abdomen para que la lumbar no se vaya hacia el suelo y quede protegida.', 'Comienza a realizar los encogimientos llevando las rodillas hacia el pecho manteniendo todo el cuerpo por encima de la pelota y las manos siempre debajo de los hombros.']::text[] where nombre = 'Elevación de piernas en Fitball' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de piernas estiradas Colgado
update public.tipo_ejercicio set instructions = ARRAY['Cuélgate de una barra de dominadas con las manos hacia delante a la anchura de los hombros.', 'Eleva las piernas con ellas totalmente estiradas mediante la contracción del abdomen hasta tener los pies frente a la cadera (piernas a 90º del torso).', 'Desciende de forma controlada y vuelve a subir evitando balanceos.']::text[] where nombre = 'Elevación de piernas estiradas Colgado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de piernas estiradas en soporte
update public.tipo_ejercicio set instructions = ARRAY['Apoya la espalda y los antebrazos en el soporte, con las manos agarradas.', 'Eleva las piernas con ellas totalmente estiradas mediante la contracción del abdomen hasta tener los pies frente a la cadera (piernas a 90º del torso).', 'Desciende de forma controlada y vuelve a subir evitando balanceos.']::text[] where nombre = 'Elevación de piernas estiradas en soporte' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de piernas flexionadas Colgado
update public.tipo_ejercicio set instructions = ARRAY['Cuélgate de una barra de dominadas con las manos hacia delante a una anchura algo superior a la de los hombros.', 'Eleva las piernas con ellas flexionadas mediante la contracción del abdomen hasta tener las rodillas delante del pecho.', 'Desciende de forma controlada y vuelve a subir evitando balanceos.']::text[] where nombre = 'Elevación de piernas flexionadas Colgado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de piernas flexionadas en soporte
update public.tipo_ejercicio set instructions = ARRAY['Apoya la espalda y los antebrazos en el soporte, con las manos agarradas.', 'Eleva las piernas con ellas flexionadas mediante la contracción del abdomen hasta tener las rodillas delante del pecho.', 'Desciende de forma controlada y vuelve a subir evitando balanceos.']::text[] where nombre = 'Elevación de piernas flexionadas en soporte' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de piernas laterales Colgado
update public.tipo_ejercicio set instructions = ARRAY['Cuélgate de una barra de dominadas con las manos hacia delante a una anchura algo superior a la de los hombros.', 'Eleva las piernas con ellas juntas y flexionadas hacia un lado, mediante la contracción del abdomen hasta tener las rodillas a la altura del pecho (hacia un lado).', 'Desciende de forma controlada y vuelve a subir hacia el otro lado evitando balanceos.']::text[] where nombre = 'Elevación de piernas laterales Colgado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de rodillas
update public.tipo_ejercicio set instructions = ARRAY['La forma eficiente de hacer este ejercicio es elevando las rodillas constantemente a la altura de la cadera, manteniendo la espalda recta, el pecho erguido, los abdominales contraídos y las rodillas suaves al impacto.']::text[] where nombre = 'Elevación de rodillas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación de rodillas con apoyo
update public.tipo_ejercicio set instructions = ARRAY['La forma eficiente de hacer este ejercicio es elevando las rodillas constantemente sobre la altura de la cadera, manteniendo el torso recto con los brazos apoyados en una pared.']::text[] where nombre = 'Elevación de rodillas con apoyo' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal Aislada en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie de espaldas a la polea, con la espalda recta y las piernas ligeramente separadas, coge la barra con la mano en pronación (palma hacia abajo).', 'Con el brazo rectos, eleva la barra hasta subir la mano a la altura de los hombros y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal Aislada en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal Cerrada en Pronación con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge la barra con las manos en pronación (palmas hacia abajo) a una anchura muy inferior a la de los hombros.', 'Con los brazos algo flexionados, eleva la barra hasta subir las manos a la altura de los hombros y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal Cerrada en Pronación con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal con giros con Barra Z
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge la barra con las manos en pronación (palmas hacia abajo) a la anchura de los hombros.', 'Con los brazos rectos, eleva la barra hasta subir las manos un poco por encima de la altura de los hombros.', 'Una vez subida, gira hacia un lado y hacia el otro, inclinando la barra 45° a cada lado y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal con giros con Barra Z' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge la mancuerna por delante del cuerpo con las dos manos y los dedos entrelazados.', 'Con los brazos rectos, eleva las mancuernas frontalmente hasta ponerlas a la altura de la cabeza y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal Declinada Abierta con Barra Z
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo en un banco declinado, apoyando el pecho en el respaldo y con los pies en el suelo.', 'Coge la barra con las manos en pronación (palmas hacia abajo) a la anchura máxima posible.', 'Con los codos ligeramente flexionados, eleva la barra hasta tener los brazos perpendiculares al cuerpo y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal Declinada Abierta con Barra Z' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal Declinada con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo en un banco declinado, apoyando el pecho en el respaldo y con los pies en el suelo.', 'Coge una mancuerna con ambas manos y los dedos entrelazados.', 'Con los codos ligeramente flexionados, eleva la mancuerna hasta ponerla a la altura de la cabeza y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal Declinada con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal Declinada en Pronación con Barra
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo en un banco declinado, apoyando el pecho en el respaldo y con los pies en el suelo.', 'Coge la barra con las manos en pronación (palmas hacia abajo) a la anchura de los hombros.', 'Con los codos ligeramente flexionados, eleva la barra hasta poner la barra a la altura de la cabeza y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal Declinada en Pronación con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie de espaldas a la polea, con la espalda recta y las piernas ligeramente separadas, coge la barra con las manos en pronación (palmas hacia abajo) a la anchura de los hombros.', 'Con los brazos rectos, eleva la barra hasta subir las manos un poco por encima de la altura de los hombros y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal en Pronación con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge la barra con las manos en pronación (palmas hacia abajo) a la anchura de los hombros.', 'Con los brazos rectos, eleva la barra hasta subir las manos un poco por encima de la altura de los hombros y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal en Pronación con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal Horizontal en Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el suelo con los pies cerca de la polea, coge la barra en pronación (palmas hacia abajo) a la anchura de los hombros.', 'Con los brazos estirados, sube la barra hasta tenerlos verticales.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevación Frontal Horizontal en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal Inclinada en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge la barra con las manos en pronación (palmas hacia abajo) a la anchura de los hombros.', 'Con los brazos rectos, eleva la barra hasta subir las manos un poco por encima de la altura de los hombros, inclinando hacia un lado 45° de forma que una mano quede por encima de la otra y desciende de nuevo de forma controlada.', 'Cambia de lado en cada repetición o al terminar la serie.']::text[] where nombre = 'Elevación Frontal Inclinada en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Frontal Inclinada en Supinación con Barra Z
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco inclinado, coge la barra con las manos en supinación a la anchura de los hombros.', 'Con los codos ligeramente flexionados, eleva la barra hasta poner los brazos perpendiculares al cuerpo y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevación Frontal Inclinada en Supinación con Barra Z' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Lateral Aislada con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, agarra la banda por delante del cuerpo, con el brazo contrario a donde esté enganchada y la palma hacia el cuerpo.', 'Sin balanceo ni impulso, eleva la mano hacia el lateral en diagonal con la mano mirando hacia abajo.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevación Lateral Aislada con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Lateral Aislada en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie al lado de la polea con las piernas separadas, agarra la polea con el brazo más alejado y la palma hacia el cuerpo.', 'Sin balanceo ni impulso, eleva la mano hacia el lateral con la mano mirando hacia abajo.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevación Lateral Aislada en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Lateral Concentrada en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie al lado de la polea con los pies juntos justo en el mástil, agarra la polea con el brazo más alejado y la palma hacia el cuerpo.', 'Con la otra mano agarra el mástil a la altura del hombro y deja caer el cuerpo al lado contrario formando una V.', 'Sin balanceo ni impulso, eleva la mano hacia el lateral con la mano mirando hacia abajo.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevación Lateral Concentrada en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Lateral en Punta
update public.tipo_ejercicio set instructions = ARRAY['De pie lateralmente en el extremo de la barra, con las piernas separadas y la espalda recta, coge el extremo de la barra con la mano más cercana a ella y llévala a la altura de la cadera a la pierna contraria.', 'Desde ahí realiza la subida en diagonal, con el brazo completamente estirado.', 'Luego desciende de forma controlada.']::text[] where nombre = 'Elevación Lateral en Punta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Lateral Horizontal Aislada con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Tumbado de lado sobre un banco plano, coge una mancuerna con el brazo superior, con el brazo paralelo al suelo y el codo flexionado de forma que la mancuerna esté hacia abajo.', 'Eleva el brazo hasta ponerlo vertical manteniendo la flexión del codo.', 'Con la otra mano puedes agarrar el banco.']::text[] where nombre = 'Elevación Lateral Horizontal Aislada con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Lateral Horizontal en Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado de lado en el suelo con los pies cerca de la polea, coge el agarre con el brazo superior y la palma de la mano hacia el suelo.', 'Con el brazo estirado, eleva la mano hasta tener el brazo vertical.', 'Aguanta un poco y desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevación Lateral Horizontal en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Lateral Inclinada Aislada con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Tumbado de lado sobre un banco inclinado, coge una mancuerna con el brazo superior, con el brazo estirado y paralelo al cuerpo.', 'Eleva el brazo hasta ponerlo en vertical y desciende de forma controlada.', 'Con la otra mano puedes agarrar el banco.']::text[] where nombre = 'Elevación Lateral Inclinada Aislada con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Total Colgado
update public.tipo_ejercicio set instructions = ARRAY['Cuélgate de una barra de dominadas con las manos hacia delante a una anchura algo superior a la de los hombros.', 'Flexiona las piernas hacia delante, con los muslos a 90° del torso y también de los gemelos.', 'Manteniendo esa posición de las piernas, eleva todo el cuerpo mediante la contracción del abdomen hasta tener los pies sobre la altura de la barra.', 'Desciende de forma controlada y vuelve a subir evitando balanceos.']::text[] where nombre = 'Elevación Total Colgado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevación Trasera con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie coge la barra tras el cuerpo con las manos en pronación, con agarre algo más ancho de los hombros.', 'Eleva la barra por detrás flexionando los brazos, aguanta un segundo y vuelve a bajar de forma controlada.', 'La espalda siempre recta y sin ningún tipo de balanceo corporal.']::text[] where nombre = 'Elevación Trasera con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Circulares con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, agarra una mancuerna en cada mano por delante del cuerpo con las palmas hacia el frente (supinación).', 'Sin balanceo ni impulso, eleva las pesas hacia el lateral hasta que los brazos queden paralelos al suelo y las manos mirando hacia delante.', 'A continuación lleva las manos a arriba por encima de la cabeza quedando los brazos extendidos y las palmas también hacia delante.', 'Desciende de forma controlada.']::text[] where nombre = 'Elevaciones Circulares con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Completas con Bandas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge las bandas con las manos en pronación (palmas hacia abajo) por delante del cuerpo.', 'Con los brazos estirados, eleva las mancuernas frontalmente hasta tenerlas sobre la cabeza, a los lados.', 'Desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Completas con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Completas con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge las mancuernas con las manos en pronación (palmas hacia abajo) a la anchura de los hombros.', 'Con los brazos estirados, eleva las mancuernas frontalmente hasta tenerlas sobre la cabeza.', 'Desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Completas con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Frontales con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge los extremos de la banda con las manos en pronación (palmas hacia atrás) y ponlas delante del cuerpo.', 'Con los brazos rectos, eleva las manos frontalmente hasta ponerlas a la altura de la cabeza y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Frontales con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Frontales Declinadas en Pronación con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo en un banco declinado, apoyando el pecho en el respaldo y con los pies en el suelo.', 'Coge las mancuernas con las manos en pronación (palmas hacia atrás) a la anchura de los hombros.', 'Con los codos ligeramente flexionados, eleva las mancuernas hasta ponerlas a la altura de la cabeza y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Frontales Declinadas en Pronación con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Frontales Declinadas Neutras con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo en un banco declinado, apoyando el pecho en el respaldo y con los pies en el suelo.', 'Coge las mancuernas con las manos en martillo o agarre neutro (palmas hacia el interior) a la anchura de los hombros.', 'Con los codos ligeramente flexionados, eleva las mancuernas hasta ponerlas a la altura de la cabeza y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Frontales Declinadas Neutras con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Frontales en Pronación con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge las mancuernas con las manos en pronación (palmas hacia atrás) y ponlas delante del cuerpo.', 'Con los brazos rectos, eleva las mancuernas frontalmente hasta ponerlas a la altura de la cabeza y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Frontales en Pronación con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Frontales en Supinación con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, coge las mancuernas con las manos en supinación (palmas hacia delante) y ponlas delante del cuerpo.', 'Con los brazos rectos, eleva las mancuernas frontalmente hasta ponerlas a la altura de la cabeza y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Frontales en Supinación con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Frontales Inclinadas con giro con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco inclinado, deja caer los brazos a los lados y coge las mancuernas con las manos en agarre neutro (palmas hacia dentro).', 'Con los brazos estirados, eleva las mancuernas frontalmente hasta tenerlas a la altura de los hombros, girando las muñecas de forma que queden en pronación (palmas hacia abajo) y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Frontales Inclinadas con giro con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Frontales Inclinadas en Pronación con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco inclinado, coge las mancuernas con las manos en pronación (palmas hacia abajo) a la anchura de los hombros.', 'Con los codos ligeramente flexionados, eleva las mancuernas hasta poner los brazos perpendiculares al cuerpo y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Frontales Inclinadas en Pronación con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Lateral - Frontal Alto con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Sentado con la espalda recta, agarra una mancuerna en cada mano con las palmas hacia el cuerpo.', 'Sin balanceo ni impulso, eleva las pesas hacia el lateral hasta que los brazos queden paralelos al suelo y las manos mirando hacia abajo.', 'A continuación lleva las manos al frente por encima de la cabeza y con una pequeña rotación de los hombros hacia el interior.', 'Desciende de forma controlada.']::text[] where nombre = 'Elevaciones Lateral - Frontal Alto con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Lateral - Frontal con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, agarra una mancuerna en cada mano con las palmas hacia el cuerpo.', 'Sin balanceo ni impulso, eleva las pesas hacia el lateral hasta que los brazos queden paralelos al suelo y las manos mirando hacia abajo.', 'A continuación lleva las manos al frente del pecho y con una pequeña rotación de los hombros hacia el interior.', 'Desciende de forma controlada.']::text[] where nombre = 'Elevaciones Lateral - Frontal con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, agarra un extremo de la banda con cada mano con las palmas hacia el cuerpo.', 'Sin balanceo ni impulso, eleva las manos hacia el lateral con los brazos estirados, hasta que los brazos queden paralelos al suelo y las manos mirando hacia abajo.', 'Aprieta los hombros y aguanta durante uno o dos segundos.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevaciones Laterales con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales Declinadas con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo en un banco declinado, apoyando el pecho en el respaldo y con los pies en el suelo.', 'Coge las mancuernas con las manos en martillo o agarre neutro (palmas hacia el interior) por delante del cuerpo dejando los brazos hacia abajo.', 'Con los codos ligeramente flexionados, eleva las mancuernas lateralmente hasta ponerlas a la altura de los hombros y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Laterales Declinadas con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales Declinadas en Pronación con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo en un banco declinado, apoyando el pecho en el respaldo y con los pies en el suelo.', 'Coge las mancuernas con las manos en pronación (palmas hacia el suelo) por delante del cuerpo creando un ángulo de 90º entre torso y brazos.', 'Con los codos ligeramente flexionados, eleva las mancuernas lateralmente hasta ponerlas a la altura de los hombros y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Laterales Declinadas en Pronación con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales Declinadas en Supinación con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo en un banco declinado, apoyando el pecho en el respaldo y con los pies en el suelo.', 'Coge las mancuernas con las manos en supinación (palmas hacia delante) a la anchura de los hombros.', 'Con los codos ligeramente flexionados, eleva las mancuernas lateralmente hasta ponerlas a la altura de la cabeza y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Laterales Declinadas en Supinación con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales Declinadas Neutras con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Túmbate hacia abajo en un banco declinado, apoyando el pecho en el respaldo y con los pies en el suelo.', 'Coge las mancuernas con las manos en martillo o agarre neutro (palmas hacia el interior) por delante del cuerpo creando un ángulo de 90º entre torso y brazos.', 'Con los codos ligeramente flexionados, eleva las mancuernas lateralmente hasta ponerlas a la altura de los hombros y desciende de nuevo de forma controlada.']::text[] where nombre = 'Elevaciones Laterales Declinadas Neutras con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales Delanteras con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado de lado con las piernas juntas y flexionadas, pon la mano de abajo sujetando la cabeza (o en alguna postura cómoda) y agarra una mancuerna con la otra, con el brazo estirado hacia delante y la palma hacia el suelo.', 'Sin balanceo ni impulso, eleva la pesa hacia el lateral con el brazo estirado hasta que quede perpendicular al suelo.', 'Aprieta los hombros y aguanta durante uno o dos segundos.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevaciones Laterales Delanteras con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Con la espalda recta coge un agarre con cada mano y sin balanceo ni impulso, eleva los soportes hacia el lateral y flexiona ligeramente los codos, hasta que los brazos queden paralelos al suelo y las manos mirando hacia abajo.', 'Aprieta los hombros y aguanta durante uno o dos segundos.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevaciones Laterales en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales en Supinación con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, agarra una mancuerna en cada mano con las palmas hacia delante.', 'Sin balanceo ni impulso, eleva las pesas hacia el lateral, hasta que los brazos queden paralelos al suelo.', 'Aprieta los hombros y aguanta durante uno o dos segundos.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevaciones Laterales en Supinación con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales Horizontales con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado de lado en un banco o el suelo, pon la mano de abajo sujetando la cabeza (o en alguna postura cómoda) y agarra una mancuerna con la otra, con el brazo estirado sobre la pierna y la palma hacia el suelo.', 'Sin balanceo ni impulso, eleva la pesa hacia arriba con el brazo estirado hasta alcanzar un ángulo aproximado de 90º con el torso.', 'Aprieta los hombros y aguanta durante uno o dos segundos.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevaciones Laterales Horizontales con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Elevaciones Laterales Neutras con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas ligeramente separadas, agarra una mancuerna en cada mano con las palmas hacia el cuerpo.', 'Sin balanceo ni impulso, eleva las pesas hacia el lateral y flexiona ligeramente los codos, hasta que los brazos queden paralelos al suelo y las manos mirando hacia abajo.', 'Aprieta los hombros y aguanta durante uno o dos segundos.', 'Desciende de forma controlada sin descansar abajo.']::text[] where nombre = 'Elevaciones Laterales Neutras con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimiento Aislado con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Sentado con la espalda recta, coge una mancuerna con una mano con agarre neutro o martillo (palma hacia el interior) al lado del cuerpo.', 'Encoge el hombro sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio e inclinando el cuello para mayor congestión.', 'Termina la serie y cambia de brazo.']::text[] where nombre = 'Encogimiento Aislado con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge un extremo de la banda con cada mano a los lados del cuerpo y las palmas hacia dentro.', 'Encoge los hombros sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge una mancuerna con cada mano a los lados del cuerpo y las palmas hacia dentro.', 'Encoge los hombros sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos Concentrados en Máquina
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, pon los hombros bajo los soportes acolchados.', 'Encoge los hombros subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos Concentrados en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos Declinados con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado en un banco inclinado con el pecho apoyado en el respaldo y los pies en el suelo, coge una mancuerna con cada mano a los lados del cuerpo y las palmas hacia dentro.', 'Encoge los hombros sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos Declinados con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos Delanteros con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge una barra por delante del cuerpo con las manos en pronación (palmas hacia atrás) a una anchura algo superior a la de los hombros.', 'Encoge los hombros sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos Delanteros con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos en Máquina
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, agarra los soportes con los brazos extendidos.', 'Encoge los hombros subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos en Paralelas
update public.tipo_ejercicio set instructions = ARRAY['Estira los brazos sobre las barras paralelas y flexiona las piernas.', 'Con los brazos bien estirados, encoge los hombros y deja caer el cuerpo, subiendo y bajando el peso con el trapecio.']::text[] where nombre = 'Encogimientos en Paralelas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge la barra por delante del cuerpo con las manos en pronación (palmas hacia atrás) a una anchura algo inferior a la de los hombros.', 'Encoge los hombros sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos en Press Militar con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge una barra con las manos en pronación (palmas hacia atrás) a una anchura superior a la de los hombros y súbela sobre la cabeza volteando los brazos (palmas que queden hacia delante) y estirando bien.', 'Encoge los hombros sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos en Press Militar con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos Horizontales en Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba con los pies hacia la polea, coge la barra con las manos en pronación a la anchura de los hombros.', 'Encoge los hombros y vuelve a bajar, todo con los brazos estirados moviendo el peso con el trapecio.']::text[] where nombre = 'Encogimientos Horizontales en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos Inclinados con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco inclinado, coge una mancuerna con cada mano a los lados del cuerpo y las palmas hacia dentro.', 'Encoge los hombros sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos Inclinados con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos Laterales con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge una con cada mano a los lados del cuerpo y las palmas hacia dentro.', 'Flexiona los codos hacia fuera subiendo las mancuernas a los costados del pecho, y baja de forma controlada.']::text[] where nombre = 'Encogimientos Laterales con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos Libres en Banco
update public.tipo_ejercicio set instructions = ARRAY['Ponte en el lateral de un banco y apoya las manos en él a la anchura de los hombros, de espaldas (como si fueses a hacer fondos entre bancos).', 'Apoya los pies en el suelo con las rodillas flexionadas a 90°.', 'Con la espalda y los brazos rectos, deja caer el peso cargándolo en el trapecio y encoge los hombros todo lo que puedas.']::text[] where nombre = 'Encogimientos Libres en Banco' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos Sentado con Barra
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, con las piernas juntas y el cuerpo ligeramente inclinado hacia delante, coge una barra por detrás de las piernas con las manos en pronación (palmas hacia atrás) a una anchura algo superior a la de los hombros.', 'Encoge los hombros sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos Sentado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Encogimientos Traseros con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta, coge una barra por detrás del cuerpo con las manos en pronación (palmas hacia atrás) a una anchura algo superior a la de los hombros.', 'Encoge los hombros sin flexionar los brazos, subiendo y bajando el peso exclusivamente con el trapecio.']::text[] where nombre = 'Encogimientos Traseros con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Concentrada en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['Coge la barra de la polea con una mano en supinación (palma hacia arriba).', 'Pon una rodilla en el suelo y la otra hacia delante flexionada 90º.', 'Apoya la parte trasera del codo en el interior del muslo y estira el brazo hacia abajo.', 'Flexiona el codo de nuevo de forma controlada.']::text[] where nombre = 'Extensión Concentrada en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Concentrada en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie y de espaldas a la polea, coge la barra de la polea con una mano en supinación (palma hacia arriba).', 'Estira el brazo hacia arriba y con la otra mano agarra la parte trasera del codo para inmovilizar la parte superior del brazo.', 'Flexiona el codo hacia atrás y vuelve a estirar de forma controlada.']::text[] where nombre = 'Extensión Concentrada en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Cuádriceps Aislada con Banda
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco plano, agarra la banda en alguna parte baja y en tu tobillo.', 'Extiende la pierna hacia delante estirando la rodilla completamente.', 'Desciende sin relajar.']::text[] where nombre = 'Extensión de Cuádriceps Aislada con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Cuádriceps con Barra
update public.tipo_ejercicio set instructions = ARRAY['De rodillas en el suelo, coge una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Echa los glúteos hacia atrás casi apoyando sobre los talones.', 'A continuación ve hacia delante dejando las rodillas flexionadas a 90º y contrayendo los cuádriceps.', 'Aguante y retrocede lentamente sin descansar abajo.']::text[] where nombre = 'Extensión de Cuádriceps con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Cuádriceps en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina con los tobillos tras el rodillo, extiende las piernas hacia delante estirando las rodillas completamente.', 'Desciende sin descansar abajo.']::text[] where nombre = 'Extensión de Cuádriceps en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelo Aislado con Banda
update public.tipo_ejercicio set instructions = ARRAY['Pon la parte delantera de un pie sobre una plataforma como puede ser un step o un disco.', 'Pilla la banda con la plataforma y cogela con la mano del lado del pie apoyado.', 'La otra pierna ponla hacia atrás sin apoyar.', 'Ponte de puntillas estirando bien el gemelo y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelo Aislado con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelo Aislado Delantero con Banda
update public.tipo_ejercicio set instructions = ARRAY['Pon la parte trasera de un pie sobre una plataforma como puede ser un step o un disco.', 'Pilla la banda con la plataforma y coge la con la mano del lado del pie apoyado.', 'La otra pierna ponla hacia atrás sin apoyar.', 'Sube y baja el tobillo todo lo que puedas, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelo Aislado Delantero con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelo Aislado en Polea
update public.tipo_ejercicio set instructions = ARRAY['Agárrate la polea baja a la cintura, con una correa o cinturón.', 'Súbete en una plataforma, step o un disco alto apoyando solo la parte delantera del pie.', 'Desciende todo lo que puedas y sube estirando bien para la pie y el gemelo.', 'Aguanta arriba y desciende de nuevo.']::text[] where nombre = 'Extensión de Gemelo Aislado en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelo Aislado sentado con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, pon la parte delantera de un pie sobre una plataforma como puede ser un step o un disco.', 'La otra pierna ponla hacia atrás y coge una mancuerna sobre el muslo de la pierna a trabajar.', 'Ponte de puntillas estirando bien el gemelo y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelo Aislado sentado con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies juntos, pisa el centro de la banda y coge cada extremo con una mano.', 'Flexiona los brazos hacia arriba poniendo las manos a los lados de los hombros con las palmas hacia delante.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos Concentrada en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Pon la parte delantera de los pies al borde de la plataforma.', 'Inclínate hacia delante poniendo la parte baja de la espalda bajo el soporte acolchado.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos Concentrada en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos de pie
update public.tipo_ejercicio set instructions = ARRAY['Pon la parte delantera de los pies al borde de un step o plataforma.', 'Puedes ponerte de pie con las manos en algún soporte o pared o inclinarte hacia delante con las manos en un banco o similar.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos de pie' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos de pie con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas a la anchura de los hombros coge una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Pon la parte delantera de los pies al borde de un step o plataforma.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos de pie con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos de pie con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies casi juntos, coge una mancuerna con cada mano.', 'Pon la parte delantera de los pies al borde de un step o plataforma.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos de pie con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos Declinada en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Pon la parte delantera de los pies al borde de la plataforma, con los hombros bajo los soportes acolchados y el cuerpo apoyado hacia abajo en el respaldo Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos Declinada en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos en Máquina con carga Inferior
update public.tipo_ejercicio set instructions = ARRAY['Pon la parte delantera de los pies al borde de la plataforma y coge un agarre con cada mano con las palmas hacia atrás.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos en Máquina con carga Inferior' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos en Máquina con carga Superior
update public.tipo_ejercicio set instructions = ARRAY['Pon la parte delantera de los pies al borde de la plataforma, con los hombros bajo los soportes acolchados.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos en Máquina con carga Superior' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos en Polea
update public.tipo_ejercicio set instructions = ARRAY['Pon un banco plano perpendicular a la polea.', 'Agárrate la polea baja a la cintura, con una correa o cinturón.', 'Súbete en el banco apoyando solo la parte delantera de los pies con ellos juntos.', 'Desciende todo lo que puedas y sube estirando bien los pies y los gemelos.', 'Aguanta arriba y desciende de nuevo.']::text[] where nombre = 'Extensión de Gemelos en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos en Prensa
update public.tipo_ejercicio set instructions = ARRAY['Colócate con la espalda bien apoyada en el respaldo de la máquina inclinada a 45 grados y los pies al borde de la plataforma, apoyando solo la parte delantera y con escasa separación.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos en Prensa' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos Inclinada en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Pon la parte delantera de los pies al borde de la plataforma, con los hombros bajo los soportes acolchados y el cuerpo apoyado hacia arriba en el respaldo Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.']::text[] where nombre = 'Extensión de Gemelos Inclinada en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos sentado con Barra
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, con las piernas juntas, ponte una barra sobre las rodillas ayudando a mantenerla con las manos.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.', 'Puedes poner la parte delantera de los pies al borde de un step o plataforma para mayor recorrido.']::text[] where nombre = 'Extensión de Gemelos sentado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos sentado con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en un banco o silla y pon la parte delantera de los pies al borde de un step o plataforma. ​Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.', 'Pon una mancuerna sobre los muslos para incrementar la dificultad.']::text[] where nombre = 'Extensión de Gemelos sentado con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Gemelos sentado en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado, pon la parte delantera de los pies al borde de la plataforma y con los muslos bajo los soportes acolchados.', 'Ponte de puntillas estirando bien los gemelos y desciende, repetidamente hasta terminar la serie.', 'Carga el peso que consideres.']::text[] where nombre = 'Extensión de Gemelos sentado en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión de Glúteos en Polea
update public.tipo_ejercicio set instructions = ARRAY['De rodillas de espaldas a la polea, coge el agarre entre las piernas con las dos manos entrelazadas.', 'Con las piernas lo más flexionadas posibles (prácticamente sentado sobre tus gemelos), inclina el cuerpo hacia delante.', 'A continuación pon las rodillas a 90° poniendo el torso en vertical y apretando bien los glúteos.', 'Vuelve a la posición inicial y repite con movimientos controlados.']::text[] where nombre = 'Extensión de Glúteos en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Declinada con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco declinado, coge las mancuernas con agarre neutro (palmas hacia el interior), frente al pecho y estira los brazos.', 'Flexiona los codos ligeramente mientras desciendes las mancuernas hasta llegar detrás de la cabeza.', 'Vuelve a la posición inicial con el movimiento controlado.']::text[] where nombre = 'Extensión Declinada con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Delante-Detrás con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Sentados en un banco o similar, cogemos una mancuerna con cada mano y estiramos los brazos hacia arriba, con las manos en pronación (palmas hacia delante).', 'Flexionamos los codos 90º por delante de la cabeza, sin bajar los brazos.', 'Volvemos a estirar bien arriba y repetimos la flexión por detrás de la cabeza.', 'Estiramos de nuevo y repetimos los pasos hasta completar la serie.']::text[] where nombre = 'Extensión Delante-Detrás con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Diagonal en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie al lado de una polea con las piernas ligeramente separadas y la espalda recta, coge el agarre con las dos manos entrelazadas y ponlo frente al lado de la cadera más cercano a la polea.', 'Realiza una extensión elevando los brazos semiflexionados en diagonal hacia arriba, haciendo un giro del torso para mayor congestión dorsal.', 'Desciende de nuevo lentamente.']::text[] where nombre = 'Extensión Diagonal en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión en caída con Bandas
update public.tipo_ejercicio set instructions = ARRAY['De pie, engancha las bandas en algún lugar alto.', 'De espaldas, coge un extremo con cada mano, con los codos flexionados y las palmas hacia el cuerpo.', 'Déjate caer suavemente flexionando los brazos.', 'Estira de nuevo tirando de los tríceps para volver arriba.']::text[] where nombre = 'Extensión en caída con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Frontal Aislada con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas juntas, pon la banda en algún lugar bajo y enrollada a tu tobillo.', 'Levanta la pierna hacia delante flexionando la rodilla a 90°.']::text[] where nombre = 'Extensión Frontal Aislada con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Frontal Aislada en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie con una pierna delante de otra y el cuerpo inclinado hacia delante de espaldas a la polea, coge la polea alta con la palma hacia delante y estira el brazo sobre la cabeza.', 'Desciende la polea por detrás de la cabeza flexionando el codo de forma controlada.']::text[] where nombre = 'Extensión Frontal Aislada en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Frontal con Arnés
update public.tipo_ejercicio set instructions = ARRAY['Sentado con el cuerpo inclinado hacia delante, colocar el arnés en la cabeza y engancharlo a un disco.', 'Tirar hacia atrás con el cuello y volver a la posición inicial de nuevo, todo con un movimiento lento y controlado y con el resto del cuerpo inmovilizado.']::text[] where nombre = 'Extensión Frontal con Arnés' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Frontal con Disco
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia abajo en un banco, coger un disco y sostenerlo por detrás de la cabeza con ambas manos.', 'Tirar hacia atrás con el cuello y volver a la posición inicial de nuevo, todo con un movimiento lento y controlado y con el resto del cuerpo inmovilizado.']::text[] where nombre = 'Extensión Frontal con Disco' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Frontal en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Apoyar la parte trasera de la cabeza sobre la almohadilla móvil de la máquina, empujar hacia atrás con el cuello y volver a la posición inicial de nuevo, todo con un movimiento lento y controlado y con el resto del cuerpo inmovilizado.']::text[] where nombre = 'Extensión Frontal en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Frontal en Polea
update public.tipo_ejercicio set instructions = ARRAY['Sentado mirando hacia la polea, colocar el arnés en la cabeza y engancharlo a la polea baja.', 'Tirar hacia atrás con el cuello y volver a la posición inicial de nuevo, todo con un movimiento lento y controlado y con el resto del cuerpo inmovilizado.']::text[] where nombre = 'Extensión Frontal en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión hacia abajo con Bandas
update public.tipo_ejercicio set instructions = ARRAY['Coloca las bandas en un lugar alto sobre la cabeza.', 'De pie con la espalda recta, coge un extremo con cada mano y estira los brazos hacia abajo.', 'Aguanta y flexiona los codos de nuevo, llegando lo más arriba posible sin llegar a relajar el músculo ni descansar.', 'Estira de nuevo con movimientos controlados.']::text[] where nombre = 'Extensión hacia abajo con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Horizontal con Barra
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco, coge la barra a una anchura algo inferior de los hombros con las palmas hacia arriba, frente al pecho y estira los brazos.', 'Flexiona los codos y desciende la barra hasta llegar detrás de la cabeza.', 'Vuelve a la posición inicial con el movimiento controlado.']::text[] where nombre = 'Extensión Horizontal con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Horizontal con Barra Z
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco, coge la barra z por el interior con las palmas hacia arriba, frente al pecho y estira los brazos.', 'Flexiona los codos y desciende la barra hasta llegar detrás de la cabeza.', 'Vuelve a la posición inicial con el movimiento controlado.']::text[] where nombre = 'Extensión Horizontal con Barra Z' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Horizontal Concentrada Interna con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Tumbado en un banco plano, coge la mancuerna con agarre en pronación (palma hacia los pies) y estira el brazo sobre le pecho.', 'Utiliza la otra mano para ejercer de apoyo o tope, colocándola detrás del codo y ejerciendo presión para mantener el otro brazo completamente recto.', 'Desciende la mancuerna hacia el interior del pecho, flexionando el codo 90º, de forma controlada.', 'Estira volviendo a la posición inicial.']::text[] where nombre = 'Extensión Horizontal Concentrada Interna con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Horizontal Concentrada Superior con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Tumbado en un banco plano, coge la mancuerna con agarre neutro (palma hacia el interior) y estira el brazo sobre le pecho.', 'Utiliza la otra mano para ejercer de apoyo o tope, colocándola detrás del codo y ejerciendo presión para mantener el otro brazo completamente recto.', 'Desciende la mancuerna flexionando el codo 90º, de forma controlada.', 'Estira volviendo a la posición inicial.']::text[] where nombre = 'Extensión Horizontal Concentrada Superior con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Horizontal en Martillo en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie y de espaldas a la polea con el cuerpo inclinado y una pierna delante de otra, coge la cuerda de la polea alta con las dos manos y estira los brazos hacia delante.', 'Desciende la polea por detrás de la cabeza flexionando los codos de forma controlada.']::text[] where nombre = 'Extensión Horizontal en Martillo en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Inclinada con Barra Z
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco inclinado, coge la barra z por el interior con las palmas hacia arriba, frente al pecho y estira los brazos.', 'Flexiona los codos y desciende la barra hasta llegar con ella sobre la cabeza, sin mover los brazos.', 'Vuelve a subir la barra estirando bien los codos.']::text[] where nombre = 'Extensión Inclinada con Barra Z' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Lateral Aislada con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie, pon la banda en algún soporte a la altura de tu cabeza y coge un extremo con una mano por detrás de la cabeza.', 'Estira el brazo con la palma de la mano hacia arriba.', 'Flexiona el codo de forma que la mano quede detrás de la cabeza.', 'Vuelve a estirar el brazo.']::text[] where nombre = 'Extensión Lateral Aislada con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Lateral Aislada en Supinación en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta de lado a la polea, coge la polea alta con la palma hacia arriba y estira el brazo hacia abajo.', 'Sube flexionando el codo de forma controlada sin llegar a relajar y vuelve a estirar.']::text[] where nombre = 'Extensión Lateral Aislada en Supinación en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Lateral con Arnés
update public.tipo_ejercicio set instructions = ARRAY['Tumbado de lado en el banco, colocar el arnés en la cabeza y engancharlo a un disco.', 'Tirar de lado con el cuello y volver a la posición inicial de nuevo, todo con un movimiento lento y controlado y con el resto del cuerpo inmovilizado.']::text[] where nombre = 'Extensión Lateral con Arnés' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Lateral en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Apoyar una parte lateral de la cabeza sobre la almohadilla móvil de la máquina, empujar hacia ella con el cuello y volver a la posición inicial de nuevo, todo con un movimiento lento y controlado y con el resto del cuerpo inmovilizado.', 'Luego realizar el ejercicio desde el otro lado.']::text[] where nombre = 'Extensión Lateral en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Trasera Aislada en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta de lado a la polea, coge la polea alta con la palma hacia abajo delante del pecho y estira el brazo hacia fuera lateralmente.', 'Retrocede de forma controlada flexionando de nuevo el codo.']::text[] where nombre = 'Extensión Trasera Aislada en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Trasera Aislada en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies casi juntos y la espalda recta, ponte la correa en un tobillo enganchada a la polea baja, de cara a ella.', 'Apóyate con las manos en el mástil de la polea para mantener el equilibrio y lleva la pierna hacia atrás todo lo que puedas con ella estirada, contrayendo el glúteo al final.']::text[] where nombre = 'Extensión Trasera Aislada en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Trasera con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas, inclina el cuerpo hacia delante y coge una barra por detrás con las manos en pronación (palmas hacia atrás) a una anchura algo mayor a la de los hombros.', 'Levanta la barra hacia atrás con los brazos rectos todo lo que puedas y desciende controlando el movimiento.']::text[] where nombre = 'Extensión Trasera con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Trasera en Máquina
update public.tipo_ejercicio set instructions = ARRAY['De pie en la máquina con la espalda recta, ponte el rodillo en la parte baja del muslo, por detrás.', 'Lleva la pierna hacia delante ligeramente flexionada.', 'Comienza el movimiento llevando la pierna hacia atrás todo lo que puedas.', 'Después regresa lentamente a la posición inicial, sin dejar caer el peso bruscamente.']::text[] where nombre = 'Extensión Trasera en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical Aislada con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Sentado con la espalda recta, coge la mancuerna con agarre neutro (palma hacia el interior) y estira el brazo sobre la cabeza.', 'Desciende la mancuerna por detrás de la cabeza flexionando el codo 90º, de forma controlada.', 'Estira volviendo a la posición inicial.', 'Puedes utilizar la otra mano para ejercer de apoyo o tope, colocándola detrás del codo y ejerciendo presión para mantener el otro brazo completamente recto.']::text[] where nombre = 'Extensión Vertical Aislada con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical Aislada en Pronación en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta de cara a la polea, coge la polea alta con la palma hacia abajo y estira el brazo hacia abajo.', 'Sube flexionando el codo de forma controlada sin llegar a relajar y vuelve a estirar.']::text[] where nombre = 'Extensión Vertical Aislada en Pronación en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical Aislada en Pronación en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie con una pierna delante de otra y el cuerpo inclinado hacia delante de espaldas a la polea, coge la polea baja con la palma hacia abajo y estira el brazo sobre la cabeza.', 'Desciende la polea por detrás de la cabeza flexionando el codo de forma controlada.']::text[] where nombre = 'Extensión Vertical Aislada en Pronación en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical Aislada en Supinación en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta de cara a la polea, coge la polea alta con una mano y la palma hacia arriba y estira el brazo hacia abajo.', 'Sube flexionando el codo de forma controlada sin llegar a relajar y vuelve a estirar.']::text[] where nombre = 'Extensión Vertical Aislada en Supinación en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical con Bandas
update public.tipo_ejercicio set instructions = ARRAY['De pie, coloca las bandas a una altura baja y de espaldas, coge un extremo con cada mano.', 'Estira los brazos hacia arriba, con las palmas de las manos hacia delante.', 'Desciende las manos por detrás de la cabeza flexionando los codos de forma controlada.', 'Estira volviendo a la posición inicial.']::text[] where nombre = 'Extensión Vertical con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical con Barra Z
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, coge la barra z con las manos a la anchura de los hombros y las palmas hacia arriba, y estira los brazos.', 'Flexiona los codos y desciende la barra hasta llegar con ella por detrás del cuello, sin mover los brazos ni separarlos.', 'Vuelve a subir la barra estirando bien los codos.']::text[] where nombre = 'Extensión Vertical con Barra Z' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Sentados en un banco o similar, cogemos una mancuerna con ambas manos y estiramos los brazos hacia arriba.', 'Flexionamos los codos hacia atrás de forma que la mancuerna quede por detrás de la cabeza, sin dejar caer el peso.', 'Estiramos de nuevo con un movimiento controlado.', 'Debemos intentar mantener los codos cerrados, como si quisiéramos que se tocasen entre ellos.']::text[] where nombre = 'Extensión Vertical con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical en Pronación en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta de cara a la polea, coge la barra en pronación (palmas hacia abajo) y estira los brazos hacia abajo.', 'Sube flexionando los codos de forma controlada sin llegar a relajar y vuelve a estirar.']::text[] where nombre = 'Extensión Vertical en Pronación en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical en Pronación en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De rodillas y de espaldas a la polea, coge la polea baja con las palmas hacia arriba y estira los brazos sobre la cabeza.', 'Desciende la polea por detrás de la cabeza flexionando los codos de forma controlada.']::text[] where nombre = 'Extensión Vertical en Pronación en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical en Supinación en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta de cara a la polea, coge la polea alta con las palmas hacia arriba y estira los brazos hacia abajo.', 'Sube flexionando los codos de forma controlada sin llegar a relajar y vuelve a estirar.']::text[] where nombre = 'Extensión Vertical en Supinación en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical Neutra en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas y la espalda recta de cara a la polea, coge la cuerda de la polea alta y estira los brazos hacia abajo.', 'Sube flexionando los codos de forma controlada sin llegar a relajar y vuelve a estirar.']::text[] where nombre = 'Extensión Vertical Neutra en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensión Vertical Neutra en Polea Baja
update public.tipo_ejercicio set instructions = ARRAY['De pie y de espaldas a la polea, coge la cuerda de la polea baja y estira los brazos sobre la cabeza.', 'Desciende la polea por detrás de la cabeza flexionando los codos de forma controlada.']::text[] where nombre = 'Extensión Vertical Neutra en Polea Baja' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones Concentradas en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De rodillas y de espaldas a la polea alta, coge la barra con ambas manos hacia delante (pronación) a la anchura de los hombros.', 'Inclina el cuerpo hacia delante y apoya la parte trasera de los codos en un banco, con ellos flexionados 90º.', 'Estira hacia delante y retrocede de forma controlada.']::text[] where nombre = 'Extensiones Concentradas en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones Cruzadas en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie entre dos poleas altas, con la espalda recta y las piernas ligeramente separadas.', 'Coge cada extremo con la mano inversa y flexiona los codos, dejando las manos frente al pecho con las poleas ya cruzadas.', 'Estira los codos hacia abajo tensando bien los tríceps y retrocede de forma controlada.']::text[] where nombre = 'Extensiones Cruzadas en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones Cruzadas en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['De pie entre dos poleas altas, con la espalda recta y las piernas ligeramente separadas, coge el agarre del lado opuesto con cada mano, con las palmas hacia delante, estirando los brazos hacia arriba de forma que queden cruzadas delante de la cabeza.', 'Tira de ambas manos hacia abajo en diagonal, abriendo los brazos a los costados y manteniendo la contracción dorsal.']::text[] where nombre = 'Extensiones Cruzadas en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones en caída libre
update public.tipo_ejercicio set instructions = ARRAY['Colocamos una barra a una altura algo inferior a la de la cadera.', 'Vamos hacia atrás con los pies, los juntamos y nos colgamos de la barra con los brazos hacia arriba, flexionados y con las manos a la anchura de los hombros.', 'Estiramos los brazos subiendo el torso por encima de la barra.', 'Bajamos de forma controlada.']::text[] where nombre = 'Extensiones en caída libre' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentados en la máquina, cogemos los agarres con las manos en posición neutra (palmas hacia nuestro cuerpo) y estiramos los brazos hacia abajo, sin mover el cuerpo ni abrir los codos.', 'Estiramos bien y volvemos a la posición inicial sin llegar a reposar el peso.']::text[] where nombre = 'Extensiones en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones en Pronación en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentados en la máquina, cogemos los agarres con las manos en pronación (palmas hacia abajo) y estiramos los brazos hacia abajo, sin mover el cuerpo ni abrir los codos.', 'Estiramos bien y volvemos a la posición inicial sin llegar a reposar el peso.']::text[] where nombre = 'Extensiones en Pronación en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones Horizontales Internas con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado en un banco plano, coge las mancuernas con agarre en pronación (palmas hacia los pies) y estira los brazos sobre le pecho.', 'Desciende las mancuernas hacia el interior del pecho, flexionando los codos mientras los abres para permitir el movimiento haciendo espacio para las mancuernas.', 'Estira volviendo a la posición inicial, todo de forma controlada.']::text[] where nombre = 'Extensiones Horizontales Internas con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones Inclinadas con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado en un banco inclinado, cogemos una mancuerna con cada mano con agarre neutro y estiramos los brazos hacia arriba.', 'Flexionamos los codos hacia atrás de forma que la mancuerna quede por detrás de la cabeza, sin dejar caer el peso.', 'Estiramos de nuevo con un movimiento controlado.', 'Debemos intentar mantener los codos cerrados, como si quisiéramos que se tocasen entre ellos.']::text[] where nombre = 'Extensiones Inclinadas con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones Laterales Amplias con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas a la anchura de los hombros, coge una banda con las dos manos delante del pecho, con los brazos extendidos paralelos al suelo y las palmas enfrentadas.', 'Estira los brazos hacia los lados lados todo lo que puedas y retrocede a la posición inicial.']::text[] where nombre = 'Extensiones Laterales Amplias con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Extensiones Laterales con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas a la anchura de los hombros, coge una banda con las dos manos delante de cada hombro, con los brazos extendidos paralelos al suelo y las palmas enfrentadas.', 'Estira los brazos hacia los lados lados todo lo que puedas y retrocede a la posición inicial.']::text[] where nombre = 'Extensiones Laterales con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexión Frontal con Disco
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba, coger un disco y sostenerlo por delante de la cabeza con ambas manos.', 'Tirar hacia delante con el cuello y volver a la posición inicial de nuevo, todo con un movimiento lento y controlado y con el resto del cuerpo inmovilizado.']::text[] where nombre = 'Flexión Frontal con Disco' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexión Frontal en Polea
update public.tipo_ejercicio set instructions = ARRAY['Sentado de espaldas a la polea, colocar el arnés en la cabeza y engancharlo a la polea alta.', 'Tirar hacia delante con el cuello y volver a la posición inicial de nuevo, todo con un movimiento lento y controlado y con el resto del cuerpo inmovilizado.']::text[] where nombre = 'Flexión Frontal en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv (alias): Flexiones (Push-ups)
update public.tipo_ejercicio set instructions = ARRAY['Empezamos con el pecho y abdomen pegado al suelo y las manos apoyadas a la altura del pecho.', 'Los codos deben apuntar siempre hacia atrás, y no hacia los lados ya que puede llevarnos a una lesión de hombros y también a aguantar menos en tensión.', 'Además lograremos una mayor estabilidad arriba.', 'Al subir el cuerpo debes mantener apretadas las caderas, los hombros y los talones, y lo mismo al volver hacia el suelo.', 'Debes tener el mismo control que cuando haces las planchas solo que añadiendo el movimiento.', 'Los brazos deben estar completamente rectos al subir y al bajar tenemos que volver a tocar el suelo, sin descansar abajo.', 'Los brazos volverán a estar en ángulo como al comienzo.']::text[] where nombre = 'Flexiones (Push-ups)' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones a una mano
update public.tipo_ejercicio set instructions = ARRAY['La posición será como en una flexión normal, pero colocaremos solamente una mano en el suelo.', 'Seguidamente, será importante intentar lograr una posición que nos permita mantenernos en equilibrio usando las piernas y el brazo de apoyo extendidos.', 'El brazo que va a realizar la flexión estará a la altura del hombro, completamente extendido, y el otro brazo lo mantendremos doblado, colocándolo en nuestra zona lumbar.', 'Las piernas estarán más separadas como cuando realizamos una flexión normal, ya que si no perderíamos el equilibrio.', 'Deberemos descender poco a poco, hasta tocar el suelo con la barbilla, para volver a subir de nuevo.']::text[] where nombre = 'Flexiones a una mano' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones a una mano asistidas
update public.tipo_ejercicio set instructions = ARRAY['La posición será como en una flexión normal, pero colocaremos solamente una mano en el suelo.', 'La otra la pondremos sobre un banco, silla o caja, apoyando toda la parte del codo y antebrazo, a modo de sujeción.', 'Deberemos descender poco a poco, cargando el peso en la mano del suelo, para volver a subir de nuevo.', 'Al terminar la serie cambiar de mano.']::text[] where nombre = 'Flexiones a una mano asistidas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Abiertas
update public.tipo_ejercicio set instructions = ARRAY['Empezamos con el pecho y abdomen pegado al suelo y las manos apoyadas a la altura del pecho, a una anchura algo superior a la de los codos si estiramos los brazos a los lados.', 'Subimos estirando los brazos con los codos en ángulo, estirando bien arriba.', 'Al bajar tenemos que volver a tocar el suelo, sin descansar abajo.', 'Los brazos volverán a estar en ángulo como al comienzo.']::text[] where nombre = 'Flexiones Abiertas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Archer
update public.tipo_ejercicio set instructions = ARRAY['Las manos deben estar colocadas en una posición más amplia en relación a los hombros.', 'Al momento de bajar, no lo harás hacia abajo de forma recta, si no que deberás colocar todo su peso en uno de los brazos.', 'Una vez hayas bajado y colocado el peso de tu cuerpo en el brazo derecho, subirás y bajarás, pero esta vez colocando el peso del cuerpo en el brazo izquierdo.']::text[] where nombre = 'Flexiones Archer' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Básicas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia abajo en el suelo, apoya las punteras de los pies y estira los brazos levantando solo la parte superior del cuerpo, manteniendo las caderas abajo.', 'Coloca las manos a la anchura de los hombros.', 'Baja el cuerpo hacia el suelo con los codos cerca del cuerpo, y luego empuja nuevamente hacia arriba.', 'Mantén la espalda recta y tensa los abdominales y el pecho.']::text[] where nombre = 'Flexiones Básicas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Cerradas
update public.tipo_ejercicio set instructions = ARRAY['Empezamos en posición de plancha con las manos apoyadas a la altura del pecho, a una anchura inferior a la de los hombros (delante del pecho).', 'Subimos estirando los brazos con los codos en ángulo, estirando bien arriba.', 'Bajamos a la posición inicial sin descansar abajo.', 'Los brazos volverán a estar en ángulo como al comienzo.']::text[] where nombre = 'Flexiones Cerradas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones con codos
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia abajo en el suelo, apoya las punteras de los pies y los antebrazos completamente (posición de plancha).', 'Sube el cuerpo estirando los brazos de forma que apoyes solo las manos.', 'Estira bien arriba y baja lentamente de nuevo, apoyando los codos.', 'Mantén la espalda recta y tensa los abdominales y el pecho.']::text[] where nombre = 'Flexiones con codos' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones con Soportes
update public.tipo_ejercicio set instructions = ARRAY['Con los soportes colocados en el suelo a la altura del pecho y a una anchura un poco superior a la de los hombros, nos colocamos en posición de plancha con una mano sobre cada soporte, brazos estirados.', 'Los codos deben apuntar siempre hacia atrás, y no hacia los lados ya que puede llevarnos a una lesión de hombros y también a aguantar menos en tensión.', 'Además lograremos una mayor estabilidad arriba.', 'Al subir el cuerpo debes mantener apretadas las caderas, los hombros y los talones, y lo mismo al volver hacia el suelo.', 'Debes tener el mismo control que cuando haces las planchas solo que añadiendo el movimiento.', 'Los brazos deben estar completamente rectos al subir y bajaremos todo lo posible, sin descansar abajo.']::text[] where nombre = 'Flexiones con Soportes' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Cruzadas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia abajo en el suelo, apoya las punteras de los pies y estira los brazos levantando el cuerpo.', 'Coloca una mano delante de otra, mirando ambas hacia el interior, frente al pecho.', 'Baja el cuerpo hacia el suelo flexionando los codos, con estos perpendiculares al torso, y luego empuja nuevamente hacia arriba.', 'Mantén la espalda recta y tensa los abdominales y el pecho.']::text[] where nombre = 'Flexiones Cruzadas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Declinadas
update public.tipo_ejercicio set instructions = ARRAY['Empezamos en posición de plancha con las manos apoyadas a la altura del pecho, a la anchura de los hombros.', 'Ponemos los pies en alto, sobre un banco, silla o cualquier otro elemento.', 'Subimos estirando los brazos con los codos en ángulo, estirando bien arriba.', 'Bajamos a la posición inicial sin descansar abajo.', 'Los brazos volverán a estar en ángulo como al comienzo.']::text[] where nombre = 'Flexiones Declinadas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Diamante
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia abajo en el suelo, apoya las punteras de los pies y estira los brazos levantando el cuerpo del suelo (posición de plancha).', 'Coloca las manos debajo del pecho y en forma de diamante.', 'Haz que tus dedos índices y tus pulgares se toquen entre sí.', 'De este modo formarás un diamante, o lo que se conoce también como pirámide.', 'Baja el cuerpo hacia el suelo, y luego empuja nuevamente hacia arriba.', 'Mantén la espalda recta y tensa los abdominales y el pecho.', 'Asegúrate de mantener los dedos correctamente en la posición de diamante.']::text[] where nombre = 'Flexiones Diamante' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones en supinación
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia abajo en el suelo, apoya las punteras de los pies y estira los brazos levantando el cuerpo.', 'Coloca las manos a la anchura de los hombros frente al pecho, con los dedos apuntando hacia atrás.', 'Baja el cuerpo hacia el suelo flexionando los codos, con estos cerca del cuerpo, y luego empuja nuevamente hacia arriba.', 'Mantén la espalda recta y tensa los abdominales y el pecho.']::text[] where nombre = 'Flexiones en supinación' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Pliométricas
update public.tipo_ejercicio set instructions = ARRAY['Comienza en una plancha alta o en la parte superior de la posición de flexión.', 'El torso debe estar en línea recta, con el núcleo apretado y las palmas directamente debajo de los hombros.', 'Empieza a bajar el cuerpo como si fueras a hacer una lagartija hasta que tu pecho casi toque el suelo.', 'A medida que empujas hacia arriba, hazlo con suficiente fuerza para que tus manos se levanten del suelo (como un pequeño salto).', 'Aterriza suavemente en el suelo y pasa a tu siguiente repetición de inmediato.']::text[] where nombre = 'Flexiones Pliométricas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Pliométricas con Palmada
update public.tipo_ejercicio set instructions = ARRAY['Comienza en una plancha alta o en la parte superior de la posición de flexión.', 'El torso debe estar en línea recta, con el núcleo apretado y las palmas directamente debajo de los hombros.', 'Empieza a bajar el cuerpo como si fueras a hacer una lagartija hasta que tu pecho casi toque el suelo.', 'A medida que empujas hacia arriba, hazlo con suficiente fuerza para que tus manos se levanten del suelo y te permita dar una palmada en el aire.', 'Aterriza suavemente en el suelo y pasa a tu siguiente repetición de inmediato.']::text[] where nombre = 'Flexiones Pliométricas con Palmada' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Verticales con Banco
update public.tipo_ejercicio set instructions = ARRAY['Pon las manos en el suelo a una anchura algo mayor a la de los hombros, en posición de flexión de pecho.', 'Sube los pies en un banco plano.', 'Inclina el torso hacia delante y realiza flexiones de los brazos de forma que los hombros carguen con el peso.']::text[] where nombre = 'Flexiones Verticales con Banco' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Flexiones Verticales entre Bancos
update public.tipo_ejercicio set instructions = ARRAY['Coloca dos bancos planos paralelos, separados a una anchura algo mayor a la de los hombros.', 'Ponte entre ellos y pon una mano y un pie en cada uno, en posición de flexión de pecho.', 'Sube los glúteos e Inclina el torso hacia delante.', 'Realiza flexiones con los brazos de forma que los hombros carguen con el peso.']::text[] where nombre = 'Flexiones Verticales entre Bancos' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Fondos Cerrados en Paralelas
update public.tipo_ejercicio set instructions = ARRAY['Ponemos las manos en las barras paralelas y estiramos los brazos, con la espalda recta y las piernas un poco recogidas.', 'Bajamos de forma controlada sin inclinar el cuerpo hasta tener los codos flexionados a 90°.', 'Volvemos a subir estirando bien arriba.', 'Podemos utilizar un cinturón de lastre para añadir peso y dificultad al ejercicio.']::text[] where nombre = 'Fondos Cerrados en Paralelas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Fondos Coreanos en Barra
update public.tipo_ejercicio set instructions = ARRAY['Ponemos las manos en la barra, con el cuerpo delante y estiramos los brazos, con la espalda recta y las piernas un poco recogidas.', 'Bajamos de forma controlada inclinando el cuerpo un poco hacia delante y las piernas hacia atrás, hasta tener los codos flexionados a 90°.', 'Volvemos a subir estirando bien arriba.', 'Hay que aprender a jugar con el balanceo, para evitar tocar con el culo en la barra así como dañar las muñecas o los hombros.']::text[] where nombre = 'Fondos Coreanos en Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Fondos en banco
update public.tipo_ejercicio set instructions = ARRAY['Coloca las manos encima del banco, plataforma o silla a la anchura de los hombros.', 'Los pies hacia adelante en el suelo y separados a la anchura de la cadera.', 'Empieza el movimiento inspirando y flexionando los codos para descender la parte superior del cuerpo hacia el suelo, intentando llegar con los brazos a un ángulo recto de 90º.', 'La espalda tiene que estar siempre cerca del banco.', 'Mantén los codos lo más cerca posible del cuerpo y flexionados hacia atrás.', 'De esta manera evitarás que se desplacen y trabajarás solo el tríceps.', 'De lo contrario, también estarías involucrando los hombros en el ejercicio.', 'Para regresar a la posición inicial exhala y mientras asciendes coloca los brazos rectos.']::text[] where nombre = 'Fondos en banco' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Fondos en Barra
update public.tipo_ejercicio set instructions = ARRAY['Ponemos las manos en las barra y estiramos los brazos, con la espalda recta y las piernas un poco recogidas.', 'Bajamos de forma controlada inclinando el cuerpo un poco hacia delante hasta tener los codos flexionados a 90°.', 'Volvemos a subir estirando bien arriba.', 'Podemos utilizar un cinturón de lastre para añadir peso y dificultad al ejercicio.']::text[] where nombre = 'Fondos en Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Fondos en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentados en la máquina con la espalda recta, ponemos las manos en pronación (palmas hacia atrás) a una anchura un poco superior a la de los hombros.', 'Estiramos los brazos hacia abajo sin levantar el cuerpo, y volvemos a la posición inicial con un movimiento controlado.']::text[] where nombre = 'Fondos en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv (alias): Fondos en Paralelas (Dips)
update public.tipo_ejercicio set instructions = ARRAY['Ponemos las manos en las barras paralelas y estiramos los brazos, con la espalda recta y las piernas un poco recogidas.', 'Bajamos de forma controlada inclinando el cuerpo un poco hacia delante hasta tener los codos flexionados a 90°.', 'Volvemos a subir estirando bien arriba.', 'Podemos utilizar un cinturón de lastre para añadir peso y dificultad al ejercicio.']::text[] where nombre = 'Fondos en Paralelas (Dips)' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Fondos en Pronación en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentados con las piernas sujetas, cogemos los agarres con las manos en pronación (palmas hacia atrás) y estiramos los brazos hacia abajo, sin mover el cuerpo ni abrir los codos.', 'Estiramos bien y volvemos a la posición inicial sin llegar a reposar el peso.']::text[] where nombre = 'Fondos en Pronación en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv (alias): Fondos entre Bancos
update public.tipo_ejercicio set instructions = ARRAY['Coloca las manos encima del banco, plataforma o silla a la anchura de los hombros.', 'Los pies hacia adelante encima de otro banco o plataforma y separados a la anchura de la cadera.', 'Empieza el movimiento inspirando y flexionando los codos para descender la parte superior del cuerpo hacia el suelo, intentando llegar con los brazos a un ángulo recto de 90º.', 'La espalda tiene que estar siempre cerca del banco.', 'Mantén los codos lo más cerca posible del cuerpo y flexionados hacia atrás.', 'De esta manera evitarás que se desplacen y trabajarás solo el tríceps.', 'De lo contrario, también estarías involucrando los hombros en el ejercicio.', 'Para regresar a la posición inicial exhala y mientras asciendes coloca los brazos rectos.']::text[] where nombre = 'Fondos entre Bancos' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Fondos Imposibles
update public.tipo_ejercicio set instructions = ARRAY['Se trata de colocarse en las barras paralelas apoyando los antebrazos en las mismas, y subir hasta bloquear los codos, sin utilizar balanceos ni impulsos, sólo por pura fuerza de tríceps.', 'Para coger fuerza y técnica, podemos empezar desde arriba descendiendo muy lentamente, y subir de un salto si es necesario.']::text[] where nombre = 'Fondos Imposibles' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Giros de cintura de pie con Banda
update public.tipo_ejercicio set instructions = ARRAY['Pon una banda en algún soporte a la altura del pecho.', 'Colócate lateralmente a él y coge el extremo con las dos manos, con los brazos extendidos y el torso girado hacia ese lado.', 'Gira tu torso al lado contrario con el brazo bloqueado sin mover las piernas, apretando el abdomen.']::text[] where nombre = 'Giros de cintura de pie con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Giros de cintura doblado con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas y la espalda recta, ponte una barra sobre el trapecio y sujeta con las dos manos para fijarla.', 'Inclina el cuerpo hacia delante formando un ángulo de 90º con las piernas.', 'Gira tu torso de lado a lado sin mover las piernas, apretando el abdomen.']::text[] where nombre = 'Giros de cintura doblado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Giros de cintura sentado con Barra
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en un banco y con las piernas flexionadas y la espalda recta.', 'Ponte una barra sobre el trapecio.', 'Gira tu torso de lado a lado sin mover las piernas, apretando el abdomen.']::text[] where nombre = 'Giros de cintura sentado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Giros de cintura sentado con Polea
update public.tipo_ejercicio set instructions = ARRAY['Sentado de espaldas a la polea, coge el agarre pasando una mano por delante del cuerpo, con el codo flexionado, girando la cintura.', 'Gira tu torso al lado contrario con el brazo bloqueado sin mover las piernas, apretando el abdomen.']::text[] where nombre = 'Giros de cintura sentado con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Giros Inferiores de Oblicuos en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Sentado en la máquina con la espalda recta, coge las manillas con ambas manos con las piernas ligeramente separadas y flexionadas.', 'Manteniendo el equilibrio gira la cadera de lado a lado, apretando el abdomen y moviendo solo la parte inferior del cuerpo.']::text[] where nombre = 'Giros Inferiores de Oblicuos en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Giros sentado en Fitball
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un fitball con la espalda recta, las piernas flexionadas y los pies en el suelo, gira el torso hacia los lados sin mover la parte inferior del cuerpo.', 'Puedes sostener una pesa para añadirle dificultad al ejercicio.']::text[] where nombre = 'Giros sentado en Fitball' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Giros Superiores de Oblicuos en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Coge las manillas con ambas manos con las piernas ligeramente separadas y la espalda recta.', 'Manteniendo el equilibrio gira la cadera de lado a lado, apretando el abdomen y evitando mover los hombros o la cabeza.']::text[] where nombre = 'Giros Superiores de Oblicuos en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Giros Superiores Sentado
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en el suelo con las piernas rectas y los pies talones en el suelo.', 'Cruza los brazos sobre tu pecho, apoyando las manos en los hombros y con los codos paralelos a las piernas.', 'Contrae los músculos abdominales y gira el torso hacia un lado, manteniendo la contracción y la postura.', 'Luego vuelve lentamente a la posición inicial.', 'Repite el movimiento hacia el otro lado.', 'Este ejercicio ayuda a mejorar la flexibilidad de la columna vertebral y a fortalecer los músculos abdominales y oblicuos.']::text[] where nombre = 'Giros Superiores Sentado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Giros Superiores Sentado con peso
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en el suelo con las rodillas flexionadas y los pies asegurados.', 'Sostén un peso con ambas manos frente al pecho, con los brazos estirados.', 'Inclínate ligeramente hacia atrás para activar los músculos abdominales.', 'Desde esta posición, gira el torso hacia un lado, llevando el peso hacia el suelo junto a la cadera.', 'Mantén el núcleo comprometido y controla el movimiento.', 'Regresa al centro y luego gira hacia el otro lado, repitiendo el movimiento.', 'Alterna los giros de manera controlada durante el número deseado de repeticiones.', 'Este ejercicio fortalece los oblicuos y mejora la estabilidad del core.']::text[] where nombre = 'Giros Superiores Sentado con peso' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Golpes alternos
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas firmes sin movernos del sitio, procedemos a lanzar puñetazos al frente alternando ambos brazos.', 'Se trata de un calentamiento típico del boxeo.']::text[] where nombre = 'Golpes alternos' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Half Wipers con piernas estiradas
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con los brazos extendidos hacia los lados y las palmas hacia abajo.', 'Levanta las piernas rectas hacia arriba.', 'Lentamente, gira las piernas hacia un lado, manteniéndolas rectas.', 'Detén el movimiento cuando las piernas estén cerca del suelo, pero sin tocarlo, y luego vuelve a la posición inicial.', 'Repite el movimiento hacia el otro lado.', 'Este ejercicio trabaja los oblicuos y abdominales, mejorando la estabilidad del core y la flexibilidad de la cadera.']::text[] where nombre = 'Half Wipers con piernas estiradas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Half Wipers con piernas flexionadas
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con los brazos extendidos hacia los lados y las palmas hacia abajo.', 'Levanta las piernas, doblando las rodillas a 90 grados.', 'Gira las piernas lentamente hacia un lado, manteniendo las rodillas dobladas.', 'Detén el movimiento cuando las rodillas estén cerca del suelo, pero sin tocarlo, y luego vuelve a la posición inicial.', 'Repite el movimiento hacia el otro lado.', 'Este ejercicio trabaja los oblicuos y abdominales, mejorando la estabilidad del core y la flexibilidad de la cadera.']::text[] where nombre = 'Half Wipers con piernas flexionadas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hand Grip
update public.tipo_ejercicio set instructions = ARRAY['Colocar los cuatro dedos a lo largo de un mango, sujetando el otro mango con la palma.', 'El pulgar debe quedar libre, apenas apoyando el movimiento.', 'El objetivo es cerrar la mano lentamente por completo y luego abrirla lentamente.']::text[] where nombre = 'Hand Grip' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hip Thrust Aislado con Barra
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el suelo con las piernas flexionadas, ponte una barra sobre la cadera.', 'Apoya la parte alta de la espalda sobre un banco.', 'Eleva la pelvis con una sola pierna tensando bien el glúteo arriba, con la espalda sobre el banco.']::text[] where nombre = 'Hip Thrust Aislado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hip Thrust con Banda
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el suelo con las piernas flexionadas, abre los brazos hacia los lados formando un ángulo de 45° con el cuerpo.', 'Con las manos hacia abajo, ponlas sobre una banda que pase por tu cadera tensando lo que consideres oportuno.', 'Eleva la pelvis tensando bien los glúteos arriba.', 'Puedes poner las manos sobre discos o alguna plataforma para alcanzar más elevación.']::text[] where nombre = 'Hip Thrust con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hip Thrust con Barra
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el suelo con las piernas flexionadas, ponte una barra sobre la cadera.', 'Eleva la pelvis tensando bien los glúteos arriba.']::text[] where nombre = 'Hip Thrust con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hip Thrust con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el suelo con las piernas flexionadas, ponte una mancuerna sobre la cadera.', 'Eleva la pelvis tensando bien los glúteos arriba.']::text[] where nombre = 'Hip Thrust con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hip Thrust Declinado con Barra
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el suelo con las piernas flexionadas, ponte una barra sobre la cadera.', 'Apoya los pies sobre un banco plano.', 'Eleva la pelvis tensando bien los glúteos arriba, con los pies sobre el banco.']::text[] where nombre = 'Hip Thrust Declinado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hip Thrust Inclinado con Barra
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en el suelo con las piernas flexionadas, ponte una barra sobre la cadera.', 'Apoya la parte alta de la espalda sobre un banco.', 'Eleva la pelvis tensando bien los glúteos arriba, con la espalda sobre el banco.']::text[] where nombre = 'Hip Thrust Inclinado con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv (alias): Hiperextensiones (Lumbares)
update public.tipo_ejercicio set instructions = ARRAY['Colócate hacia abajo en el banco plano con sujeción de los tobillos y la cadera apoyada.', 'Pon las manos en el pecho o tras la cabeza.', 'Flexiona el torso hasta que el cuerpo forme un ángulo de 90 grados.', 'Desde esta posición de flexión debes efectuar una extensión mientras levantas el torso hasta que el cuerpo queda en línea recta nuevamente y en la zona lumbar se forma una curva levemente acentuada.', 'Vuelve a descender mientras tomas aire y cuando extiendes el torso exhala el aire.', 'Puedes sujetar un disco en el pecho para incrementar la dificultad.']::text[] where nombre = 'Hiperextensiones (Lumbares)' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hiperextensiones en Fitball
update public.tipo_ejercicio set instructions = ARRAY['Coloca una Pelota Suiza delante de ti y arrodíllate.', 'Inclínate hacia adelante, colocando la parte superior de las caderas y el estómago sobre la Pelota Suiza.', 'Estira las piernas hacia atrás.', 'Empieza con la cabeza levantada, la espalda estirada, el pecho separado de la pelota y las manos detrás de la cabeza.', 'Baja el pecho y la cabeza hasta notar un buen estiramiento en los isquiotibiales y luego contrae la parte inferior de la espalda para volver a la posición inicial.']::text[] where nombre = 'Hiperextensiones en Fitball' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hiperextensiones en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Colócate en la máquina con sujeción de los tobillos y la espalda apoyada.', 'Pon las manos en el pecho o tras la cabeza.', 'Flexiona la cadera hacia atrás y retrocede lentamente.']::text[] where nombre = 'Hiperextensiones en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hiperextensiones Inclinadas
update public.tipo_ejercicio set instructions = ARRAY['Colócate hacia abajo en el banco inclinado con sujeción de los tobillos y la cadera apoyada.', 'Pon las manos en el pecho o tras la cabeza.', 'Flexiona el torso hasta que el cuerpo forme un ángulo de 90 grados.', 'Desde esta posición de flexión debes efectuar una extensión mientras levantas el torso hasta que el cuerpo queda en línea recta nuevamente y en la zona lumbar se forma una curva levemente acentuada.', 'Vuelve a descender mientras tomas aire y cuando extiendes el torso exhala el aire.']::text[] where nombre = 'Hiperextensiones Inclinadas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Hollow Hold
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba con los brazos extendidos sobre la cabeza y las piernas rectas.', 'Levanta los hombros y las piernas del suelo, manteniendo la parte baja de la espalda en contacto con el suelo.', 'Contrae los músculos abdominales para mantener la posición y forma un arco en el cuerpo, manteniendo el abdomen y las piernas activados.', 'Mantén la posición durante el tiempo deseado, respirando de manera controlada.', 'Este ejercicio fortalece los músculos abdominales, especialmente los profundos, y ayuda a mejorar la estabilidad del core.']::text[] where nombre = 'Hollow Hold' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Inclinación diagonal en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta y las piernas a la anchura aproximada de la cadera, ponte a un lado de la polea alta.', 'Coge el soporte con las dos manos y los dedos entrelazados a un lado del cuerpo, con los brazos extendidos.', 'Flexiona el tronco lateralmente hacia abajo del lado contrario, girando el torso y bajando los brazos completamente en diagonal.']::text[] where nombre = 'Inclinación diagonal en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Jackknife Sit-Up
update public.tipo_ejercicio set instructions = ARRAY['Acuéstate boca arriba sobre una estera con los brazos extendidos por encima de la cabeza y las piernas rectas.', 'A medida que inhalas, contrae los abdominales y levanta simultáneamente los brazos y las piernas del suelo, manteniéndolos rectos.', 'Dirige tus manos hacia tus pies, intentando tocarlos mientras elevas el torso y las piernas.', 'Mantén la posición por un momento y luego baja lentamente el torso y las piernas de vuelta al suelo.', 'Este ejercicio trabaja los músculos abdominales superiores e inferiores, así como los flexores de la cadera.']::text[] where nombre = 'Jackknife Sit-Up' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Jalón Abierto Doble Neutro en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['Sentado o de rodillas entre dos poleas altas y con la espalda recta, estira los brazos hacia arriba y coge los soportes con las manos hacia el interior.', 'Flexiona los brazos bajando las manos a la altura aproximada de los hombros.', 'Estira de nuevo de forma controlada.']::text[] where nombre = 'Jalón Abierto Doble Neutro en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Jalón Abierto en Pronación en Polea Alta
update public.tipo_ejercicio set instructions = ARRAY['Sentado de cara a la polea con la espalda recta, estira los brazos hacia arriba y coge la barra con las manos a una anchura muy superior a la de los hombros y las manos hacia delante.', 'Flexiona los brazos bajando la barra al mentón.', 'Estira de nuevo de forma controlada.']::text[] where nombre = 'Jalón Abierto en Pronación en Polea Alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Jalón Abierto en Supinación en Polea Alta
