-- csv: Remo en Supinación en Máquina Smith
update public.tipo_ejercicio set instructions = ARRAY['Agarra la barra con las manos en supinación a la anchura de los hombros, flexiona ligeramente las rodillas con las piernas separadas e inclina el torso hacia delante.', 'Ahora, mientras mantienes el torso inmóvil, coge aire mientras levantas la barra hasta llegar con la barra a la altura del abdomen, aguantando un segundo arriba.', 'Después desciende de forma controlada.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Remo en Supinación en Máquina Smith' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
