update public.tipo_ejercicio set instructions = ARRAY['Sentado con las piernas estiradas y los pies juntos, pon la banda a la altura del pecho y coge un extremo con la mano hacia el interior.', 'Flexiona el codo llevando la mano al torso, sacando pecho.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Remo Horizontal Aislado con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
