update public.tipo_ejercicio set instructions = ARRAY['Sentado y con el pecho apoyado, estira los brazos y coge los agarres con las manos en pronación (palmas hacia abajo).', 'Realiza la flexión de los codos llevando las manos hacia atrás con retracción escapular al final del movimiento.', 'Desciende lentamente sin llegar a apoyar el peso al final y vuelve a subir.']::text[] where nombre = 'Remo Horizontal en Pronación en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
