-- csv: Remo Inclinado Alterno con Bandas
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas y la espalda recta, pon las bandas en un lugar alto y agarra un extremo con cada mano estirando los brazos hacia arriba.', 'Flexiona un brazo llevando la mano hacia el costado.', 'Estíralo de nuevo mientras recoges el otro brazo.']::text[] where nombre = 'Remo Inclinado Alterno con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
