update public.tipo_ejercicio set instructions = ARRAY['Apoyando el pecho en el respaldo de un banco inclinado, sostén una barra con agarre en pronación (palmas hacia abajo) a una anchura algo mayor a la de los hombros.', 'Coge aire mientras levantas la barra hasta llegar tocar el respaldo por la parte inferior, con contracción escapular y aguantando un segundo arriba.', 'Después desciende de forma controlada.', 'Separa bien los codos del cuerpo en la subida.']::text[] where nombre = 'Remo Inclinado en Pronación con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
