update public.tipo_ejercicio set instructions = ARRAY['Pon la cuerda en un lugar alto.', 'Agarra un extremo con cada mano y déjate caer hacia atrás formando un ángulo aproximado de 45° con el suelo.', 'Con los brazos estirados, ábrelos hacia los lados elevando el cuerpo hacia las bandas.']::text[] where nombre = 'Remo Libre Inclinado Abierto con Cuerda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Libre Inclinado Cerrado con Cuerda
update public.tipo_ejercicio set instructions = ARRAY['Pon la cuerda en un lugar alto.', 'Agarra un extremo con cada mano y déjate caer hacia atrás formando un ángulo aproximado de 45° con el suelo.', 'Con los brazos estirados, realiza la flexión de los codos elevando el cuerpo hacia las bandas, manteniendo los codos pegados.']::text[] where nombre = 'Remo Libre Inclinado Cerrado con Cuerda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Neutro con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Sosteniendo dos mancuernas en agarre neutro (palmas hacia el interior) a la anchura de los hombros, flexiona ligeramente las rodillas con las piernas separadas e inclina el torso hacia delante.', 'Ahora, mientras mantienes el torso inmóvil, coge aire mientras levantas las mancuernas hasta llegar bajo el pecho, con contracción escapular y aguantando un segundo arriba.', 'Después desciende de forma controlada.', 'Mantén los codos cerca del cuerpo.']::text[] where nombre = 'Remo Neutro con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Superior Aislado con Banda
update public.tipo_ejercicio set instructions = ARRAY['De rodillas en el suelo con el cuerpo inclinado hacia delante, pon la banda arriba y coge un extremo con la mano hacia el suelo.', 'Flexiona el codo llevando la mano hacia el hombro.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Remo Superior Aislado con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Superior Aislado con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Inclinado hacia delante en un banco plano, apoyando la rodilla y la mano de un lado del cuerpo, coge una mancuerna con la otra mano con agarre en pronación (palma hacia atrás).', 'Realiza el ascenso con el codos hacia arriba flexionándolo 90º, hasta que quede sobre la altura del hombro y perpendicular al cuerpo.', 'Desciende de forma controlada.']::text[] where nombre = 'Remo Superior Aislado con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Superior Aislado en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie frente a la polea con una pierna delante y otra detrás, con la espalda recta, estira un brazo y coge la polea alta con agarre en pronación (palma hacia el suelo).', 'Realiza la flexión del codo llevándolo hacia el costado y con un giro del torso a favor, para lograr mayor carga del dorsal.', 'Vuelve a estirar suavemente.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Remo Superior Aislado en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Superior con Bandas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, pon las bandas en un lugar alto y coge un extremo con cada mano, delante de la cabeza con los codos a la altura de los hombros y las palmas de las manos hacia el suelo.', 'Lleva los codos hacia atrás como haciendo un Remo, en línea con los hombros.', 'Estira de nuevo lentamente y vuelve a flexionar.']::text[] where nombre = 'Remo Superior con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Superior con Cuerda en Polea
update public.tipo_ejercicio set instructions = ARRAY['De rodillas o sentado delante de la polea, con la espalda recta, estira los brazos hacia arriba y coge la cuerda con las manos hacia dentro.', 'Realiza la flexión de los codos llevándolos hacia los lados de los hombros hacia afuera, haciendo que las manos queden delante de los mismos.', 'Vuelve a estirar suavemente.']::text[] where nombre = 'Remo Superior con Cuerda en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Superior en Polea
update public.tipo_ejercicio set instructions = ARRAY['De rodillas delante de la polea con la espalda recta, coge la cuerda de la polea alta con las dos manos y los brazos estirados Lleva los codos hacia atrás como haciendo un Remo, en línea con los hombros.', 'Estira de nuevo lentamente y vuelve a flexionar.']::text[] where nombre = 'Remo Superior en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Superior en Pronación en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie delante de la polea, con la espalda recta, estira los brazos hacia delante y coge la barra con las manos hacia abajo a una anchura inferior a la de los hombros.', 'Realiza la flexión de los codos llevándolos hacia los lados de los hombros hacia afuera, haciendo que las manos queden delante del pecho.', 'Vuelve a estirar suavemente.']::text[] where nombre = 'Remo Superior en Pronación en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Remo Superior Trasero con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['Sentado con las piernas juntas y el torso inclinado hacia delante, coge una mancuerna con cada mano con agarre en pronación (palmas hacia atrás).', 'Realiza el ascenso con los codos hacia arriba flexionándolos 90º, hasta que queden sobre la altura de los hombros y perpendiculares al cuerpo.', 'Desciende de forma controlada.']::text[] where nombre = 'Remo Superior Trasero con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Retracción Escapular Colgado
update public.tipo_ejercicio set instructions = ARRAY['Colgado en una barra de dominadas con las manos a una anchura algo mayor que la de los hombros y las palmas hacia delante, realiza la retracción escapular (juntando omóplatos) y sacando pecho.', 'Relaja y procede de nuevo.']::text[] where nombre = 'Retracción Escapular Colgado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Retracción Escapular entre Bancos
update public.tipo_ejercicio set instructions = ARRAY['Colocate entre dos bancos planos, túmbate hacia arriba con los pies en el suelo y un codo sobre cada banco, con los brazos perpendiculares al cuerpo.', 'Realiza es ascenso del torso mediante retracción escapular (juntando omóplatos) y sacando pecho.', 'Desciende lentamente y vuelve a subir.']::text[] where nombre = 'Retracción Escapular entre Bancos' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rodilla al codo
update public.tipo_ejercicio set instructions = ARRAY['Nos colocaremos de pie, con el torso recto.', 'Es importante, que lo mantengamos apretado durante la realización del ejercicio.', 'Mejorará nuestra estabilidad y estimulación muscular en el abdomen.', 'Colocaremos los brazos a los lados del cuerpo con los codos ligeramente flexionados.', 'A continuación, elevaremos la pierna izquierda hacia el centro y acompañaremos el movimiento con el codo derecho, llegando a tocar.', 'Tras esto, realizaremos el mismo movimiento con la pierna derecha y el codo izquierdo.']::text[] where nombre = 'Rodilla al codo' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rodilla al codo con giro
update public.tipo_ejercicio set instructions = ARRAY['Nos colocaremos de pie, con el torso recto.', 'Es importante, que lo mantengamos apretado durante la realización del ejercicio.', 'Mejorará nuestra estabilidad y estimulación muscular en el abdomen.', 'Deberemos tratar de colocar los codos alineados con la cabeza.', 'A continuación, elevaremos la pierna izquierda y giraremos el torso para acompañar con el codo opuesto (no tendrá que llegar a hacerlo).', 'Tras esto, realizaremos el mismo movimiento con la pierna derecha y el codo izquierdo.']::text[] where nombre = 'Rodilla al codo con giro' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rodilla al codo con sentadilla
update public.tipo_ejercicio set instructions = ARRAY['Nos colocaremos en posición de sentadilla con las manos por detrás de la cabeza.', 'A continuación, elevaremos la rodilla izquierda y acompañaremos el movimiento girando el torso para tratar de aproximar la rodilla al codo contrario, estirando por completo la pierna de apoyo.', 'Tras esto, realizaremos el mismo movimiento con la pierna derecha y el codo izquierdo.']::text[] where nombre = 'Rodilla al codo con sentadilla' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Roll Reverse Crunch
update public.tipo_ejercicio set instructions = ARRAY['Sentado en el suelo, pon el rodillo bajo los gemelos Apoya las manos a los lados por detrás del cuerpo.', 'Contrae los abdominales y levanta las caderas del suelo mientras estiras la pelvis hacia adelante.', 'Haz una pausa en la posición y luego recoge las caderas lentamente hacia la posición inicial.', 'Este ejercicio trabaja los músculos abdominales inferiores y puede ayudar a fortalecer el core.']::text[] where nombre = 'Roll Reverse Crunch' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación Concentrada con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Sentado, con el codo apoyado sobre la rodilla o el banco, el brazo hacia abajo y la palma de la mano mirando hacia la otra mano (agarre en martillo), sujetar firmemente la mancuerna y realizar el movimiento de rotación de la muñeca sin despegar el antebrazo del apoyo.']::text[] where nombre = 'Rotación Concentrada con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación de Aductor Externa con Banda
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia abajo en el suelo, con el extremo de una banda en un tobillo y el otro extremo en algún suporte a media altura.', 'Flexiona la pierna 90° hasta atrás.', 'Realiza la rotación hacia fuera, teniendo en cuenta que la banda debe tensar hacia el interior de la pierna.']::text[] where nombre = 'Rotación de Aductor Externa con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación de Aductor Interna con Banda
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia abajo en el suelo, con el extremo de una banda en un tobillo y el otro extremo en algún suporte a media altura.', 'Flexiona la pierna 90° hasta atrás.', 'Realiza la rotación hacia dentro, teniendo en cuenta que la banda debe tensar hacia el exterior de la pierna.']::text[] where nombre = 'Rotación de Aductor Interna con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación de Cadera Externa con Banda
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, con el extremo de una banda en un tobillo y el otro extremo en algún suporte.', 'Flexiona la pierna 90°.', 'Realiza la rotación hacia fuera, teniendo en cuenta que la banda debe tensar hacia el interior de la pierna.']::text[] where nombre = 'Rotación de Cadera Externa con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación de Cadera Interna con Banda
update public.tipo_ejercicio set instructions = ARRAY['Sentado en un banco o similar, con el extremo de una banda en un tobillo y el otro extremo en algún suporte.', 'Flexiona la pierna 90°.', 'Realiza la rotación hacia dentro, teniendo en cuenta que la banda debe tensar hacia el exterior de la pierna.']::text[] where nombre = 'Rotación de Cadera Interna con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación Externa Aislada con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Tumbado lateralmente, coge una mancuerna en pronación (palma hacia el suelo) con el codo flexionado sobre el costado del cuerpo.', 'Realiza la rotación del hombro poniendo el antebrazo en vertical manteniendo la flexión.']::text[] where nombre = 'Rotación Externa Aislada con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación Externa Aislada en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie al lado de la polea, coge el agarre con la mano más lejana, el brazo flexionado 90° y la palma hacia el interior.', 'Realiza la rotación del hombro hacia el exterior del cuerpo manteniendo la flexión del codo.']::text[] where nombre = 'Rotación Externa Aislada en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación Externa Concentrada con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie tras un banco inclinado, apoya el codo flexionado sobre el borde del respaldo y coge una mancuerna en pronación (palma hacia el suelo) con la mano delante del pectoral opuesto.', 'Realiza la rotación del hombro poniendo el antebrazo en vertical manteniendo la flexión.']::text[] where nombre = 'Rotación Externa Concentrada con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación Interna Aislada en Polea
update public.tipo_ejercicio set instructions = ARRAY['Sentado al lado de la polea, coge el agarre con la mano más cercana, el brazo flexionado 90° y la palma hacia el interior.', 'Realiza la rotación del hombro hacia el interior del pecho manteniendo la flexión del codo.']::text[] where nombre = 'Rotación Interna Aislada en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación Vertical Aislada con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas ligeramente separadas, coge una mancuerna en pronación (palma hacia el suelo) con el codo flexionado a 90º hacia abajo y con el brazo en línea con el hombro lateralmente.', 'Realiza la rotación del hombro poniendo el antebrazo en vertical hacia arriba manteniendo la flexión.']::text[] where nombre = 'Rotación Vertical Aislada con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Rotación Vertical Aislada en Polea
update public.tipo_ejercicio set instructions = ARRAY['De rodillas frente a la polea, coge el soporte con la mano en pronación (palma hacia el suelo) con el codo flexionado a 90º hacia delante y con el brazo en línea con el hombro lateralmente.', 'Realiza la rotación del hombro poniendo el antebrazo en vertical hacia arriba manteniendo la flexión.']::text[] where nombre = 'Rotación Vertical Aislada en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Russian Twist
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en el suelo con las rodillas dobladas y los pies apoyados.', 'Inclina ligeramente el torso hacia atrás.', 'Junta las manos frente al pecho.', 'Gira el torso hacia un lado y luego hacia el otro, acercando el codo de ese lado hacia el suelo.', 'Mantén el equilibrio y repite alternando los lados.', 'Este ejercicio trabaja los oblicuos y mejora la estabilidad del core.']::text[] where nombre = 'Russian Twist' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Russian Twist con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['Siéntate en el suelo y con las piernas flexionadas, sujeta los pies bajo algún soporte.', 'Inclínate ligeramente hacia atrás para que tu torso y piernas formen una V, apretando tu pared abdominal para activar el core.', 'Balanceándote, gira tu torso de lado a lado sin mover las piernas.', 'Sostén una mancuerna entre los brazos para mayor dificultad.']::text[] where nombre = 'Russian Twist con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Russian Twist en Fitball con Polea
update public.tipo_ejercicio set instructions = ARRAY['Túmbate con la espalda sobre un fitball con las piernas flexionadas y los pies en el suelo.', 'Agarra el soporte de la polea alta con las dos manos, quedando este a un lado.', 'Balanceándote, gira tu torso al lado contrario al de la polea, tirando del cable.', 'Al terminar la serie, date la vuelta para trabajar el otro lado.']::text[] where nombre = 'Russian Twist en Fitball con Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Salto alterno en el sitio
update public.tipo_ejercicio set instructions = ARRAY['Con las rodillas ligeramente flexionadas, adelantar una pierna y retrasar la otra.', 'Realizar un pequeño salto e invertir la posición de ambas piernas, acompañando siempre con los brazos opuestos.']::text[] where nombre = 'Salto alterno en el sitio' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Salto con Cuerda Alterno Alto
update public.tipo_ejercicio set instructions = ARRAY['De pie con un solo pie sobre el suelo y la rodilla ligeramente flexionada, sostén la cuerda con ambas manos y hazla girar alrededor de tu cuerpo mientras saltas cuando pase por tus pies, manteniendo la posición, subiendo la rodilla lo máximo posible y cambiando de pie de apoyo en cada salto.', 'Puedes aumentar el ritmo progresivamente.']::text[] where nombre = 'Salto con Cuerda Alterno Alto' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Salto con Cuerda Alterno Normal
update public.tipo_ejercicio set instructions = ARRAY['De pie con un solo pie sobre el suelo y la rodilla ligeramente flexionada, sostén la cuerda con ambas manos y hazla girar alrededor de tu cuerpo mientras saltas cuando pase por tus pies, manteniendo la posición y cambiando de pie de apoyo en cada salto.', 'Puedes aumentar el ritmo progresivamente.']::text[] where nombre = 'Salto con Cuerda Alterno Normal' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Salto con Cuerda Alto
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies juntos y las rodillas ligeramente flexionadas, sostén la cuerda con ambas manos y hazla girar alrededor de tu cuerpo mientras saltas cuando pase por tus pies, manteniendo la posición y subiendo las rodillas lo máximo posible.', 'Puedes aumentar el ritmo progresivamente.']::text[] where nombre = 'Salto con Cuerda Alto' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Salto con Cuerda Lateral
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies juntos y las rodillas ligeramente flexionadas, sostén la cuerda con ambas manos y hazla girar alrededor de tu cuerpo mientras saltas cuando pase por tus pies, de un lado al otro manteniendo el equilibrio.', 'Puedes aumentar el ritmo progresivamente.']::text[] where nombre = 'Salto con Cuerda Lateral' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Salto con Cuerda Normal
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies juntos y las rodillas ligeramente flexionadas, sostén la cuerda con ambas manos y hazla girar alrededor de tu cuerpo mientras saltas cuando pase por tus pies, manteniendo la posición.', 'Puedes aumentar el ritmo progresivamente.']::text[] where nombre = 'Salto con Cuerda Normal' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Salto con desplazamiento lateral
update public.tipo_ejercicio set instructions = ARRAY['De pie, erguido con los pies separados a la anchura ancho de los hombros y los brazos extendidos a los lados.', 'Realiza una sentadilla y toca con una mano la parte exterior del pie.', 'Salta lateralmente desplazándote hacia el lado opuesto.', 'Al bajar, toca con la otra mano la parte exterior del pie.']::text[] where nombre = 'Salto con desplazamiento lateral' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Salto con desplazamiento lateral cruzado
update public.tipo_ejercicio set instructions = ARRAY['Con el cuerpo inclinado hacia delante, un pie adelantado y el otro atrás, toca el pie delantero con la mano opuesta y retrasa el otro brazo.', 'Salta lateralmente desplazándote hacia el lado opuesto y realiza la posición inversa.']::text[] where nombre = 'Salto con desplazamiento lateral cruzado' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Salto de esquí
update public.tipo_ejercicio set instructions = ARRAY['De pie, con las manos sobre la cintura, adelanta un poco un pie y retrasa el otro.', 'Con las rodillas ligeramente flexionadas, alterna entre ambos pies con un pequeño salto.']::text[] where nombre = 'Salto de esquí' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Saltos rodillas en cuclillas con Barra
update public.tipo_ejercicio set instructions = ARRAY['De rodillas en el suelo, coge una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Con la punta de los pies apoyada en el suelo (dedos flexionados), de un impulso salta hasta ponerte en cuclillas.', 'Déjate caer suavemente hacia delante y vuelve a repetir.']::text[] where nombre = 'Saltos rodillas en cuclillas con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla a una pierna con Banda Debajo
update public.tipo_ejercicio set instructions = ARRAY['De pie delante de una plataforma como puede ser un banco o silla, de espaldas a este, da un paso hacia delante y lleva una pierna hacia atrás flexionada, apoyando el empeine en el borde de la plataforma.', 'Pisa la banda con el pie de apoyo y coge los extremos con las manos.', 'Desciende flexionando la pierna de apoyo manteniendo la espalda recta.', 'Sube de nuevo estirando la pierna sin ayudarte de la que está en la plataforma, ya que es para ayudar con el equilibrio.']::text[] where nombre = 'Sentadilla a una pierna con Banda Debajo' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla a una pierna con Banda Delante
update public.tipo_ejercicio set instructions = ARRAY['De pie delante de una plataforma como puede ser un banco o silla, de espaldas a este, da un paso hacia delante y lleva una pierna hacia atrás flexionada, apoyando el empeine en el borde de la plataforma.', 'Coge el extremo de la banda con la mano inversa a la pierna de apoyo, estando el otro extremo en algún soporte delante de ti.', 'Desciende flexionando la pierna de apoyo manteniendo la espalda recta.', 'Sube de nuevo estirando la pierna sin ayudarte de la que está en la plataforma, ya que es para ayudar con el equilibrio.']::text[] where nombre = 'Sentadilla a una pierna con Banda Delante' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla a una pierna con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con una barra tras la nuca, con las manos en ella a los lados de los hombros mirando hacia delante, ponte delante de un banco o silla.', 'Lleva una pierna hacia atrás y apoya el empeine del pie en el borde del banco para mantener el equilibrio.', 'Esta pierna no debe ejercer ningún tipo de fuerza.', 'Desciende la pierna de apoyo flexionando la rodilla 90º, sin descansar abajo, subiendo de nuevo y estirando bien arriba.']::text[] where nombre = 'Sentadilla a una pierna con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla a una pierna con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con una mancuerna en cada mano, ponte delante de un banco o silla.', 'Lleva una pierna hacia atrás y apoya el empeine del pie en el borde del banco para mantener el equilibrio.', 'Esta pierna no debe ejercer ningún tipo de fuerza.', 'Desciende la pierna de apoyo flexionando la rodilla 90º, sin descansar abajo, subiendo de nuevo y estirando bien arriba.']::text[] where nombre = 'Sentadilla a una pierna con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla Abierta con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas a una anchura algo superior a la de los hombros, coge una mancuerna con las dos manos y ponla delante del pecho, con los brazos flexionados.', 'Desciende flexionando las rodillas y bajando los glúteos por debajo de estas, sin descansar abajo, subiendo de nuevo y estirando bien arriba.']::text[] where nombre = 'Sentadilla Abierta con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla Aislada Asistida con Cuerda
update public.tipo_ejercicio set instructions = ARRAY['De pie, pon una cuerda en un lugar alto y agarra cada extremo con una mano.', 'Apóyate solo con un pie en el suelo y la otra pierna ponla hacia delante.', 'Déjate caer hacia atrás flexionando la pierna de apoyo 90° y estirando los brazos para no caerte.', 'Vuelve a estirar la pierna ayudándote de los brazos si es necesario.']::text[] where nombre = 'Sentadilla Aislada Asistida con Cuerda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla Asistida con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con los tobillos sujetos en un soporte, coge una mancuerna con ambas manos delante del pecho, col los brazos flexionados.', 'Flexiona las piernas 90º dejando caer el cuerpo suavemente hacia atrás, manteniendo la espalda erguida.', 'Sube de nuevo estirando bien arriba.']::text[] where nombre = 'Sentadilla Asistida con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla Cerrada Inclinada en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Apoya la espalda en el respaldo inclinado, con los hombros bajo los soportes acolchados.', 'Pon los pies en la parte alta de la plataforma, a una anchura inferior a la de los hombros.', 'Sube estirando las piernas apretando glúteos arriba y desciende bajando los glúteos tras las rodillas.']::text[] where nombre = 'Sentadilla Cerrada Inclinada en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla con Banda
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas a la anchura de los hombros y con la espalda recta agáchate flexionando las rodillas.', 'Pisa la banda y coge los extremos con las manos, tensando lo que consideres, y ponlas sobre los hombros con los brazos flexionados, sirviendo estos solo de agarre sin que carguen el peso.', 'Sube estirando las piernas y apretando glúteos arriba.', 'Desciende lentamente sin descansar abajo.']::text[] where nombre = 'Sentadilla con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas a la anchura de los hombros y una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Desciende flexionando las rodillas 90º, sin descansar abajo, subiendo de nuevo y estirando bien arriba.']::text[] where nombre = 'Sentadilla con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, coge una mancuerna con cada mano.', 'Desciende flexionando las rodillas a 90º y vuelve a subir de forma controlada.']::text[] where nombre = 'Sentadilla con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla con Poleas
update public.tipo_ejercicio set instructions = ARRAY['De pie entre dos poleas bajas, pon los pies a una anchura mayor que la de los hombros y con la espalda recta agáchate flexionando las rodillas.', 'Coge un agarre con cada mano y ponlas sobre los hombros con los brazos flexionados, sirviendo estos solo de agarre sin que carguen el peso.', 'Sube estirando las piernas y apretando glúteos arriba.', 'Desciende lentamente sin descansar abajo.']::text[] where nombre = 'Sentadilla con Poleas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla con salto con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas a una anchura muy superior a la de los hombros coge una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Desciende flexionando las rodillas 90º, sin descansar abajo, subiendo de nuevo de un impulso dando un salto al final.']::text[] where nombre = 'Sentadilla con salto con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla con salto con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De cuclillas con la espalda recta, coge una mancuerna con cada mano.', 'Impúlsate saltando hacia arriba con las piernas rectas y vuelve a caer en cuclillas para inmediatamente saltar otra vez.']::text[] where nombre = 'Sentadilla con salto con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla en Máquina
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies a la anchura de los hombros y con la espalda recta agáchate flexionando las rodillas.', 'Coge un agarre con cada mano con las palmas hacia el interior.', 'Sube estirando las piernas y apretando glúteos arriba.', 'Desciende lentamente sin descansar abajo.']::text[] where nombre = 'Sentadilla en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla en Pared con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, coge una mancuerna con cada mano.', 'Apoya la espalda en una pared con los pies un poco hacia delante.', 'Desciende flexionando las rodillas a 90º sin despegar la espalda de la pared.']::text[] where nombre = 'Sentadilla en Pared con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla en Punta
update public.tipo_ejercicio set instructions = ARRAY['De pie de cara a la barra con las piernas a la anchura de los hombros y la espalda recta, coge el extremo de la barra con las dos manos entrelazadas delante del pecho.', 'Desciende bajando los glúteos tras las rodillas y sube estirando las piernas apretando glúteos arriba.']::text[] where nombre = 'Sentadilla en Punta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla en zancada con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie coge una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Da un paso adelantando una pierna y flexionando ambas ligeramente.', 'Inclínate hacia delante flexionando la pierna adelantada a 90º.', 'Vuelve a estirar la pierna sin despegar el pie.']::text[] where nombre = 'Sentadilla en zancada con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla en zancada inclinada con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie coge una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Con un banco declinado delante, da un paso adelantando una pierna y pon el pie en el respaldo.', 'Inclínate hacia delante flexionando la pierna del banco a 90º.', 'Vuelve a estirar la pierna sin despegar el pie.']::text[] where nombre = 'Sentadilla en zancada inclinada con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla en zancada inclinada con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie coge una mancuerna con cada mano, a los lados del cuerpo.', 'Con un banco declinado delante, da un paso adelantando una pierna y pon el pie en el respaldo.', 'Inclínate hacia delante flexionando la pierna del banco a 90º.', 'Vuelve a estirar la pierna sin despegar el pie.']::text[] where nombre = 'Sentadilla en zancada inclinada con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla Profunda con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas a la anchura de los hombros y una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Desciende flexionando las rodillas y bajando los glúteos hasta su altura, sin descansar abajo, subiendo de nuevo y estirando bien arriba.']::text[] where nombre = 'Sentadilla Profunda con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla Sumo con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas a una anchura muy superior a la de los hombros coge una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Desciende flexionando las rodillas 90º, sin descansar abajo, subiendo de nuevo y estirando bien arriba.']::text[] where nombre = 'Sentadilla Sumo con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla Sumo con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas a una anchura muy superior a la de los hombros, coge una mancuerna con las dos manos y ponla delante de la cadera, con los brazos estirados.', 'Desciende flexionando las rodillas y bajando los glúteos a la altura de estas, sin descansar abajo, subiendo de nuevo y estirando bien arriba.']::text[] where nombre = 'Sentadilla Sumo con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sentadilla Sumo Inclinada en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Apoya la espalda en el respaldo inclinado, con los hombros bajo los soportes acolchados.', 'Pon los pies en la parte alta de la plataforma, a una anchura superior a la de los hombros.', 'Sube estirando las piernas apretando glúteos arriba y desciende bajando los glúteos tras las rodillas.']::text[] where nombre = 'Sentadilla Sumo Inclinada en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Serratos Aislados en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie, con los pies separados a la anchura de los hombros y las piernas ligeramente flexionadas.', 'Extiende un brazo cogiendo el agarre con la palma hacia dentro y da un paso atrás.', 'Manteniendo la postura, lleva la mano hacia el muslo (con el brazo extendido pero desbloqueado), aguantando unos instantes la contracción de la espalda.', 'Después, vuelve a subir el peso de forma controlada hasta el punto de partida (sin apoyar el peso para no descansar) provocando un estiramiento dorsal.', 'Al terminar la serie cambia de brazo.']::text[] where nombre = 'Serratos Aislados en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Serratos con Cuerda en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie, con los pies separados a la anchura de los hombros y las piernas ligeramente flexionadas.', 'Extiende los brazos cogiendo la cuerda con las palmas hacia dentro y da un paso atrás, manteniendo la espalda recta con una leve inclinación hacia delante, con el pecho y glúteos hacia fuera, ejerciendo tensión sobre la musculatura dorsal.', 'Manteniendo la postura, lleva la cuerda hacia los muslos (con los brazos extendidos pero desbloqueados), aguantando unos instantes la contracción de la espalda.', 'Después, vuelve a separar el peso de forma controlada hasta el punto de partida (sin apoyar el peso para no descansar) provocando un estiramiento dorsal.']::text[] where nombre = 'Serratos con Cuerda en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Serratos con giro en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie, con los pies separados a la anchura de los hombros y las piernas ligeramente estiradas.', 'Extiende los brazos cogiendo la barra con las palmas hacia abajo y da un paso atrás.', 'Manteniendo la postura, lleva la barra a un lado de la cadera con un pequeño giro del torso.', 'Después, vuelve a subir el peso de forma controlada hasta el punto de partida (sin apoyar el peso para no descansar) provocando un estiramiento dorsal.', 'Puedes alternar una vez a cada lado o terminar la serie y cambiar.']::text[] where nombre = 'Serratos con giro en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Serratos Inclinados Cerrados con Barra en Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco inclinado de espaldas a la polea alta, extiende los brazos cogiendo la barra con las palmas hacia delante a una anchura inferior a la de los hombros.', 'Con los brazos rectos, baja la barra hasta la altura del esternón, apretando los dorsales y aguantando un poco, para volver a subir de forma controlada.']::text[] where nombre = 'Serratos Inclinados Cerrados con Barra en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Serratos Inclinados con Barra en Polea
update public.tipo_ejercicio set instructions = ARRAY['Tumbado hacia arriba en un banco ligeramente inclinado inclinado de espaldas a la polea alta, extiende los brazos cogiendo la barra con las palmas hacia delante a la anchura de los hombros.', 'Con los brazos rectos, baja la barra hasta la altura de la cadera, apretando los dorsales y aguantando un poco, para volver a subir de forma controlada.']::text[] where nombre = 'Serratos Inclinados con Barra en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Serratos Inferiores con Barra en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie, con los pies separados a la anchura de los hombros y las piernas ligeramente flexionadas.', 'Extiende los brazos cogiendo la barra de la polea alta con las palmas hacia abajo, manteniendo la espalda recta.', 'Lleva la barra a la altura del abdomen (posición inicial).', 'Desde ahí, bájala hasta los muslos y vuelve a la posición inicial de forma controlada.']::text[] where nombre = 'Serratos Inferiores con Barra en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sit Up con Bandas
update public.tipo_ejercicio set instructions = ARRAY['Tumbado en el suelo hacia arriba con la espalda recta y las piernas estiradas y algo separadas, levanta los brazos en vertical y agarra dos bandas conectadas a algún soporte a esa altura, por detrás de la cabeza.', 'Desde atrás, inspira y mientras exhalas el aire inicia el encogimiento abdominal para elevar el torso mediante la contracción de los músculos de la zona media del cuerpo, formando un ángulo de 90º con las piernas.', 'Regresa lentamente a la posición inicial y repite tantas veces como necesites para completar la serie de ejercicios.']::text[] where nombre = 'Sit Up con Bandas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sit Up en Fitball
update public.tipo_ejercicio set instructions = ARRAY['Apoya la espalda sobre el fitball, con los pies apoyados en el suelo, las rodillas flexionadas a 90° y las manos detrás de la cabeza.', 'Desde atrás, con la espalda casi en su totalidad apoyada sobre el fitball excepto la cabeza y columna dorsal que deben estar levemente despegadas del objeto, inspira y mientras exhalas el aire inicia el encogimiento abdominal para elevar el torso mediante la contracción de los músculos de la zona media del cuerpo.', 'Regresa lentamente a la posición inicial y repite tantas veces como necesites para completar la serie de ejercicios.']::text[] where nombre = 'Sit Up en Fitball' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sit Up en Máquina
update public.tipo_ejercicio set instructions = ARRAY['Tumbado en el banco de la máquina hacia arriba con la espalda recta y las piernas flexionadas y los pies en los soportes fijos, agarra el soporte móvil con las manos delante del pecho.', 'Desde atrás, inspira y mientras exhalas el aire inicia el encogimiento abdominal para elevar el torso mediante la contracción de los músculos de la zona media del cuerpo, formando un ángulo de 90º con las piernas.', 'Regresa lentamente a la posición inicial y repite tantas veces como necesites para completar la serie de ejercicios.']::text[] where nombre = 'Sit Up en Máquina' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Skips
update public.tipo_ejercicio set instructions = ARRAY['El skipping es uno de los ejercicios más efectivos para incluir en el entrenamiento de un corredor con el objetivo de mejorar o aprender la técnica de carrera.', 'Gracias a este trabajo seremos capaces de fortalecer el tren inferior, prevenir lesiones o incluso economizar mayor energía durante la carrera.']::text[] where nombre = 'Skips' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Split Jacks
update public.tipo_ejercicio set instructions = ARRAY['Comienza dando un paso hacia atrás hasta quedar en estocada mientras relajas los brazos.', 'Una vez estés en esta posición, salta y, mientras lo haces, cambia la posición de tus piernas para aterrizar en una estocada del lado contrario.', 'A medida que saltas, mueve los brazos hacia abajo y hacia arriba de forma alterna.']::text[] where nombre = 'Split Jacks' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Sprints con rodilla alta
update public.tipo_ejercicio set instructions = ARRAY['La forma eficiente de hacer este ejercicio es elevando las rodillas constantemente sobre la altura de la cadera, manteniendo la espalda recta, el pecho erguido, los abdominales contraídos y las rodillas suaves al impacto.', 'La parte superior del cuerpo debe participar en la actividad moviendo los brazos de forma alterna adelantando el opuesto a las rodillas.', 'Y es así como la carrera ponderada de rodilla alta elevará el ritmo cardíaco al entrenamiento máximo del 90%, aumentando la activación muscular.']::text[] where nombre = 'Sprints con rodilla alta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Squat Tuck Jumps
update public.tipo_ejercicio set instructions = ARRAY['Consiste en realizar sentadillas con salto impulsándonos para elevar los pies del suelo elevando ambas rodillas al pecho y después caer de pie.', 'Con este ejercicio trabajaremos piernas y glúteos sobre todo.']::text[] where nombre = 'Squat Tuck Jumps' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Step Up
update public.tipo_ejercicio set instructions = ARRAY['Mantener el tronco erguido, tratando de evitar inclinarlo hacia adelante.', 'Mantener el pie de la pierna de atrás en la posición inicial, pero cargando el peso corporal sobre la pierna adelantada.', 'Extender la cadera y la rodilla adelantadas para ponerse de pie encima del cajón.', 'Se puede hacer sobre un banco o cualquier superficie elevada.']::text[] where nombre = 'Step Up' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Step Up con Banda
update public.tipo_ejercicio set instructions = ARRAY['Delante de alguna plataforma como puede ser un banco o una silla, sube una pierna flexionando la rodilla 90°.', 'Pisa el centro de una banda y agarra cada extremo con una mano, tensando lo que necesites.', 'Sube a la plataforma estirando la pierna que está encima, sin impulsarte con la de abajo.', 'Desciende lentamente y vuelve a subir.']::text[] where nombre = 'Step Up con Banda' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Step Up con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, sostén una barra sobre el pecho con las manos hacia arriba y los codos hacia delante.', 'Da un paso hacia delante subiendo en el step o plataforma completamente, estirando bien la pierna de apoyo y vuelve a bajar en el orden de subida.']::text[] where nombre = 'Step Up con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Step Up con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con la espalda recta, sostén una mancuerna con cada mano a los lados del cuerpo.', 'Da un paso hacia delante subiendo en el step, banco o plataforma completamente, estirando bien la pierna de apoyo y vuelve a bajar en el orden de subida.']::text[] where nombre = 'Step Up con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Step Up Lateral
update public.tipo_ejercicio set instructions = ARRAY['Ponte sobre un step o plataforma con un pie, con el otro en el aire.', 'Baja de la plataforma lateralmente flexionando la pierna que está encima, cargando el peso sobre ella.', 'Apoya ligeramente el otro pie y vuelve a subir utilizando la pierna de la plataforma.']::text[] where nombre = 'Step Up Lateral' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Tuck Jumps
update public.tipo_ejercicio set instructions = ARRAY['Consiste en saltar elevando ambas rodillas al pecho, lo más alto posible, para ello, lo ideal es comenzar y culminar el salto con las rodillas flexionadas, de manera de amortiguar el impacto cuando volvemos a caer con ambos pies en el suelo.', 'Con este se trabaja principalmente piernas y abdomen, además de quemar calorías.']::text[] where nombre = 'Tuck Jumps' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Wheel Rollout de pie
update public.tipo_ejercicio set instructions = ARRAY['Ponte de pie con los pies separados a la anchura de los hombros y sostén un rodillo de rueda con ambas manos frente a ti.', 'Mantén la espalda recta y comienza a rodar el rodillo hacia adelante, doblando lentamente la cintura y bajando el torso hacia el suelo.', 'Continúa rodando hacia adelante hasta que sientas un estiramiento en los abdominales, pero evita arquear la espalda baja.', 'Detén el movimiento y, utilizando la fuerza de los abdominales, comienza a rodar el rodillo hacia atrás para volver a la posición inicial.', 'Mantén el control del movimiento en todo momento y evita extender demasiado la espalda.', 'Repite el movimiento durante el número deseado de repeticiones.', 'Este ejercicio trabaja principalmente los músculos abdominales, especialmente los rectos abdominales y los oblicuos, así como los músculos estabilizadores del core.']::text[] where nombre = 'Wheel Rollout de pie' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Wheel Rollout de rodillas
update public.tipo_ejercicio set instructions = ARRAY['Desde una posición de rodillas en el suelo, sostén un rodillo de rueda con ambas manos frente a ti, con los brazos extendidos y los abdominales contraídos.', 'Mantén la espalda recta y comienza a rodar el rodillo hacia adelante, doblando lentamente la cintura y bajando el torso hacia el suelo.', 'Continúa rodando hacia adelante hasta que sientas un estiramiento en los abdominales, pero evita arquear la espalda baja.', 'Detén el movimiento y, utilizando la fuerza de los abdominales, comienza a rodar el rodillo hacia atrás para volver a la posición inicial.', 'Mantén el control del movimiento en todo momento y evita extender demasiado la espalda.', 'Repite el movimiento durante el número deseado de repeticiones.', 'Este ejercicio trabaja principalmente los músculos abdominales, especialmente los rectos abdominales y los oblicuos, así como los músculos estabilizadores del core.']::text[] where nombre = 'Wheel Rollout de rodillas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Wrist Roller
update public.tipo_ejercicio set instructions = ARRAY['De pie, con los brazos estirados hacia delante, realizar la recogida de la cuerda con giro de las muñecas de una en una.', 'Repetir cambiando el sentido.', 'Podemos apoyar los antebrazos sobre una barra, por ejemplo en un rack.']::text[] where nombre = 'Wrist Roller' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada con salto
update public.tipo_ejercicio set instructions = ARRAY['La técnica es sencilla: damos un paso largo con nuestra pierna derecha hacia adelante y flexionamos ambas rodillas hasta que queden en un ángulo de 90 grados (la referencia suele ser que la rodilla izquierda, la de la pierna que queda atrás, esté a punto de rozar el suelo).', 'Una vez abajo (con la zancada dada), cogemos impulso dando un pequeño salto para proceder con la pierna contraria.']::text[] where nombre = 'Zancada con salto' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Delantera con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas a la anchura de los hombros y la espalda recta, coge una mancuerna con cada mano a los lados del cuerpo.', 'Da una zancada hacia delante, flexionando la pierna de apoyo 90° y la otra de forma que quede la rodilla cerca del suelo.', 'Vuelve a la posición inicial.', 'Puedes alternar una vez cada pierna o cambiar al terminar la serie.']::text[] where nombre = 'Zancada Delantera con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Delantera en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie de espaldas a la polea con las piernas a la anchura de los hombros y la espalda recta, coge la cuerda de la polea alta con una mano a cada lado del cuello.', 'Da una zancada hacia delante, flexionando la pierna de apoyo 90° y la otra de forma que quede la rodilla cerca del suelo.', 'Vuelve a la posición inicial.', 'Puedes alternar una vez cada pierna o cambiar al terminar la serie.']::text[] where nombre = 'Zancada Delantera en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Lateral con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies a la anchura de los hombros, coge una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Ahora haz un desplazamiento lateral con una pierna hacia fuera, flexionando al apoyar.', 'Vuelve a la posición inicial manteniendo el equilibrio.', 'Al terminal la serie cambia de pierna.']::text[] where nombre = 'Zancada Lateral con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Lateral con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies a la anchura de los hombros, coge una mancuerna delante del pecho con los brazos flexionados.', 'Ahora haz un desplazamiento lateral con una pierna hacia fuera, flexionando al apoyar.', 'Vuelve a la posición inicial manteniendo el equilibrio.', 'Al terminal la serie cambia de pierna.']::text[] where nombre = 'Zancada Lateral con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Lateral Cruzada con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies a la anchura de los hombros, coge una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Ahora haz un desplazamiento lateral hacia un lado pero moviendo la contraria por detrás de la pierna de apoyo, flexionando esta 90º.', 'Vuelve a la posición inicial manteniendo el equilibrio.', 'Al terminal la serie cambia de pierna.']::text[] where nombre = 'Zancada Lateral Cruzada con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Lateral Cruzada con Mancuerna
update public.tipo_ejercicio set instructions = ARRAY['De pie con los pies a la anchura de los hombros, coge una mancuerna delante del pecho con los brazos flexionados.', 'Ahora haz un desplazamiento lateral hacia un lado pero moviendo la contraria por detrás de la pierna de apoyo, flexionando esta 90º.', 'Vuelve a la posición inicial manteniendo el equilibrio.', 'Al terminal la serie cambia de pierna.']::text[] where nombre = 'Zancada Lateral Cruzada con Mancuerna' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Lateral en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie al lado a la polea baja, con las piernas a la anchura de los hombros y la espalda recta, coge el soporte con la mano más cercana a la polea y póntelo junto al cuello con el codo flexionado.', 'Esto es solo para sostener el peso de la polea con el cuerpo.', 'Ahora haz un desplazamiento lateral con la pierna de fuera, flexionando al apoyar.', 'Vuelve a la posición inicial manteniendo el equilibrio.', 'Al terminal la serie cambia de pierna.']::text[] where nombre = 'Zancada Lateral en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Trasera con Barra
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas separadas a una anchura inferior a la de los hombros y una barra sobre el trapecio, ayudando a mantenerla con las manos a los lados de los hombros.', 'Da un paso hacia atrás con una pierna, flexionando la de apoyo 90º quedando el muslo paralelo al suelo, y sin descansar abajo sube de nuevo a la posición inicial.', 'Cambia de pierna en cada repetición o al final de la serie.', 'Para mayor dificultad, inicia el ejercicio sobre un step o plataforma con cierta altura.']::text[] where nombre = 'Zancada Trasera con Barra' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Trasera con Mancuernas
update public.tipo_ejercicio set instructions = ARRAY['De pie con las piernas a la anchura de los hombros y la espalda recta, coge una mancuerna con cada mano a los lados del cuerpo.', 'Da una zancada hacia atrás, flexionando la pierna de apoyo 90° y la otra de forma que quede la rodilla cerca del suelo.', 'Vuelve a la posición inicial.', 'Puedes alternar una vez cada pierna o cambiar al terminar la serie.']::text[] where nombre = 'Zancada Trasera con Mancuernas' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Trasera en Polea
update public.tipo_ejercicio set instructions = ARRAY['De pie de cara a la polea baja con las piernas a la anchura de los hombros y la espalda recta, coge el agarre de la polea baja con las dos manos entrelazadas delante del abdomen.', 'Da una zancada hacia atrás, flexionando la pierna de apoyo 90° y la otra de forma que quede la rodilla cerca del suelo.', 'Vuelve a la posición inicial.', 'Puedes alternar una vez cada pierna o cambiar al terminar la serie.']::text[] where nombre = 'Zancada Trasera en Polea' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancada Trasera en Punta
update public.tipo_ejercicio set instructions = ARRAY['De pie de cara a la barra con las piernas a la anchura de los hombros y la espalda recta, coge el extremo de la barra con las dos manos entrelazadas delante del pecho.', 'Da una zancada hacia atrás, flexionando la pierna de apoyo 90° y la otra de forma que quede la rodilla cerca del suelo.', 'Vuelve a la posición inicial.', 'Puedes alternar una vez cada pierna o cambiar al terminar la serie.']::text[] where nombre = 'Zancada Trasera en Punta' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
-- csv: Zancadas con salto
update public.tipo_ejercicio set instructions = ARRAY['De pie coge una mancuerna con cada mano, a los lados del cuerpo.', 'Da un paso adelantando una pierna y flexiona ligeramente las dos, con el cuerpo entre medias y la espalda recta.', 'A continuación da un salto de un impulso y cambia el sentido de las piernas, es decir, la de atrás ponla delante y viceversa.']::text[] where nombre = 'Zancadas con salto' and (instructions is null or coalesce(cardinality(instructions), 0) = 0);
commit;
